import React, { useState } from 'react';
import { ShieldCheck, AlertCircle, CheckCircle2, XCircle, Info, Lock } from 'lucide-react';
import { ConferenceBatch, User, UserRole } from '../types';

interface SupervisorCheckProps {
  batch: ConferenceBatch;
  users: User[];
  onApprove: (supervisor: User, justification: string) => void;
  onReject: () => void;
}

const SupervisorCheck: React.FC<SupervisorCheckProps> = ({ batch, users, onApprove, onReject }) => {
  const [supervisorPass, setSupervisorPass] = useState('');
  const [justification, setJustification] = useState('');
  const [error, setError] = useState('');
  const [isValidated, setIsValidated] = useState(false);

  const discrepancies = batch.products.filter(p => p.quantityExpected !== p.quantityChecked);

  const handleValidate = () => {
    // Verifica se existe algum usuário Supervisor ou Admin com a senha digitada
    const validatedUser = users.find(u => 
      (u.role === UserRole.SUPERVISOR || u.role === UserRole.ADMIN) && 
      u.password === supervisorPass
    );

    if (validatedUser) {
      setIsValidated(true);
      setError('');
    } else {
      setError('Senha do supervisor incorreta ou usuário não autorizado.');
    }
  };

  const submitApproval = () => {
    if (!justification.trim()) {
      setError('A justificativa é obrigatória para aprovação com divergência.');
      return;
    }
    // Identifica quem validou para atribuir ao relatório (usando a senha atual para re-identificar se necessário ou pegando o primeiro supervisor)
    const supervisor = users.find(u => 
      (u.role === UserRole.SUPERVISOR || u.role === UserRole.ADMIN) && 
      u.password === supervisorPass
    ) || users[0];

    onApprove(supervisor, justification);
  };

  if (!isValidated) {
    return (
      <div className="max-w-md mx-auto mt-20 bg-white p-8 rounded-2xl shadow-xl border border-slate-100">
        <div className="text-center mb-8">
          <div className="bg-orange-100 w-16 h-16 rounded-full flex items-center justify-center mx-auto mb-4">
            <ShieldCheck className="text-orange-600" size={32} />
          </div>
          <h2 className="text-2xl font-bold text-slate-800">Divergência Encontrada</h2>
          <p className="text-slate-500 mt-2">É necessária a validação de um supervisor para prosseguir.</p>
        </div>

        <div className="space-y-4">
          <div className="bg-orange-50 p-4 rounded-xl border border-orange-100 flex gap-3 text-orange-800 text-sm">
            <AlertCircle size={20} className="shrink-0" />
            <p>O lote atual contém diferenças entre o faturado no XML e o conferido fisicamente.</p>
          </div>

          <div className="relative">
            <Lock className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
            <input
              type="password"
              value={supervisorPass}
              onChange={(e) => setSupervisorPass(e.target.value)}
              placeholder="Senha do Supervisor"
              className="w-full bg-slate-50 border border-slate-200 rounded-xl py-4 pl-12 pr-4 focus:ring-2 focus:ring-orange-500 focus:outline-none"
            />
          </div>

          {error && <p className="text-red-500 text-sm font-medium text-center">{error}</p>}

          <button
            onClick={handleValidate}
            className="w-full bg-slate-900 hover:bg-black text-white py-4 rounded-xl font-bold transition-all shadow-lg"
          >
            Validar Supervisor
          </button>

          <button
            onClick={onReject}
            className="w-full bg-white border border-slate-200 hover:bg-slate-50 text-slate-600 py-4 rounded-xl font-bold transition-all"
          >
            Cancelar Lote
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-5xl mx-auto space-y-6">
      <div className="bg-white p-8 rounded-2xl shadow-sm border border-slate-100">
        <div className="flex justify-between items-start mb-8">
          <div>
            <h2 className="text-2xl font-bold text-slate-800">Relatório Detalhado de Divergências</h2>
            <p className="text-slate-500">Conferente: {batch.conferenteName}</p>
          </div>
          <span className="bg-orange-100 text-orange-700 px-4 py-2 rounded-full text-sm font-bold flex items-center gap-2">
            <Info size={18} />
            Ação Requerida
          </span>
        </div>

        <div className="overflow-hidden border border-slate-100 rounded-xl mb-8">
          <table className="w-full text-left">
            <thead className="bg-slate-50 text-slate-500 text-xs uppercase font-bold">
              <tr>
                <th className="px-6 py-4">Produto</th>
                <th className="px-6 py-4 text-center">XML (Fat)</th>
                <th className="px-6 py-4 text-center">Físico (Conf)</th>
                <th className="px-6 py-4 text-center">Diferença</th>
                <th className="px-6 py-4 text-center">Status</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {discrepancies.map((p) => {
                const diff = p.quantityChecked - p.quantityExpected;
                const isSobra = diff > 0;
                return (
                  <tr key={p.id}>
                    <td className="px-6 py-4">
                      <p className="font-bold text-slate-800 text-sm">{p.description}</p>
                      <p className="text-xs text-slate-400">EAN: {p.ean}</p>
                    </td>
                    <td className="px-6 py-4 text-center font-bold">{p.quantityExpected}</td>
                    <td className="px-6 py-4 text-center font-bold">{p.quantityChecked}</td>
                    <td className={`px-6 py-4 text-center font-bold ${isSobra ? 'text-blue-600' : 'text-red-600'}`}>
                      {diff > 0 ? `+${diff}` : diff}
                    </td>
                    <td className="px-6 py-4 text-center">
                      <span className={`px-3 py-1 rounded-full text-[10px] font-black uppercase ${isSobra ? 'bg-blue-100 text-blue-700' : 'bg-red-100 text-red-700'}`}>
                        {isSobra ? 'SOBRA' : 'FALTA'}
                      </span>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>

        <div className="space-y-4">
          <label className="block text-sm font-bold text-slate-700">Justificativa da Liberação</label>
          <textarea
            value={justification}
            onChange={(e) => setJustification(e.target.value)}
            className="w-full bg-slate-50 border border-slate-200 rounded-xl p-4 min-h-[120px] focus:ring-2 focus:ring-blue-500 focus:outline-none"
            placeholder="Descreva o motivo da aprovação mesmo com divergências..."
          ></textarea>

          {error && <p className="text-red-500 text-sm font-medium">{error}</p>}

          <div className="flex gap-4 pt-4">
            <button
              onClick={onReject}
              className="flex-1 bg-white border border-slate-200 hover:bg-red-50 text-red-600 py-4 rounded-xl font-bold transition-all flex items-center justify-center gap-2"
            >
              <XCircle size={20} />
              Cancelar e Re-conferir
            </button>
            <button
              onClick={submitApproval}
              className="flex-1 bg-green-600 hover:bg-green-700 text-white py-4 rounded-xl font-bold transition-all shadow-lg flex items-center justify-center gap-2"
            >
              <CheckCircle2 size={20} />
              Autorizar Conclusão
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default SupervisorCheck;

