      pdf.save(`conferencia_lote_${batch.id}.pdf`);
    } catch (error) {
      console.error('Erro ao baixar PDF:', error);
      alert('Ocorreu um erro ao gerar o arquivo PDF.');
    } finally {
      setIsExporting(false);
    }
  };

  const hasDivergences = batch.products.some(p => p.quantityExpected !== p.quantityChecked);

  return (
    <div id="print-modal-container" className="fixed inset-0 z-50 flex items-center justify-center p-0 md:p-4 bg-slate-900/60 backdrop-blur-sm no-print">
      <div className="bg-white w-full max-w-5xl h-full md:h-auto md:max-h-[90vh] rounded-none md:rounded-2xl shadow-2xl flex flex-col overflow-hidden animate-in fade-in zoom-in duration-200">

        {/* Modal Header */}
        <div className="p-4 border-b border-slate-100 flex justify-between items-center bg-slate-50 no-print">
          <div className="flex items-center gap-2 text-slate-700">
            <FileText size={20} />
            <span className="font-bold text-sm md:text-base tracking-tight">Relatório de Conferência #{batch.id}</span>
          </div>
          <div className="flex items-center gap-2 md:gap-3">
            <button 
              onClick={handleDownloadPDF}
              disabled={isExporting || isPrinting}
              className="flex items-center gap-2 bg-emerald-600 hover:bg-emerald-700 text-white px-3 md:px-4 py-2 rounded-lg font-bold transition-all text-sm shadow-md disabled:opacity-50"
            >
              {isExporting ? <Loader2 size={16} className="animate-spin" /> : <Download size={16} />}
              <span className="hidden sm:inline">Baixar PDF</span>
            </button>
            <button 
              onClick={handleOpenPDF}
              disabled={isExporting || isPrinting}
              className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-3 md:px-4 py-2 rounded-lg font-bold transition-all text-sm shadow-md disabled:opacity-50"
            >
              {isPrinting ? <Loader2 size={16} className="animate-spin" /> : <ExternalLink size={16} />}
              <span className="hidden sm:inline">Visualizar Online / Imprimir</span>
              <span className="sm:hidden">Visualizar</span>
            </button>
            <button 
              onClick={onClose}
              className="p-2 hover:bg-slate-200 rounded-full transition-colors text-slate-400"
            >
              <X size={20} />
            </button>
          </div>
        </div>

        {/* Modal Content / Área do Relatório */}
        <div id="printable-report" className="flex-1 overflow-y-auto p-8 md:p-12 bg-white printable-content">

          {/* Cabeçalho do Relatório */}
          <div className="flex justify-between items-start mb-10 border-b-2 border-slate-100 pb-8">
            <div className="flex items-center gap-3">
              <div className="bg-blue-600 p-3 rounded-xl">
                <Package className="text-white" size={32} />
              </div>
              <div>
                <h1 className="text-2xl font-black text-slate-800 tracking-tight uppercase">CheckMaster XML</h1>
                <p className="text-slate-500 font-medium text-sm">Sistema de Conferência de Mercadorias</p>
              </div>
            </div>
            <div className="text-right">
              <div className={`inline-flex items-center gap-2 px-4 py-1 rounded-full text-[10px] md:text-xs font-black uppercase mb-2 ${
                !hasDivergences ? 'bg-green-100 text-green-700' : 'bg-orange-100 text-orange-700'
              }`}>
                {!hasDivergences ? <CheckCircle2 size={14} /> : <AlertTriangle size={14} />}
                {!hasDivergences ? 'Conferência Conforme' : 'Conferência com Divergência'}
              </div>
              <p className="text-slate-400 text-[10px]">ID do Lote: <span className="text-slate-800 font-mono">#{batch.id}</span></p>
              <p className="text-slate-400 text-[10px]">Data Finalização: <span className="text-slate-800 font-medium">{new Date(batch.endTime || batch.startTime).toLocaleString('pt-BR')}</span></p>
            </div>
          </div>

          {/* Grid de Detalhes */}
          <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 md:gap-6 mb-10">
            <div className="bg-slate-50 p-4 rounded-xl border border-slate-100">
              <p className="text-[10px] text-slate-400 font-bold uppercase mb-1">Conferente Responsável</p>
              <p className="text-sm font-bold text-slate-800">{batch.conferenteName}</p>
            </div>
            <div className="bg-slate-50 p-4 rounded-xl border border-slate-100">
              <p className="text-[10px] text-slate-400 font-bold uppercase mb-1">Supervisor de Liberação</p>
              <p className="text-sm font-bold text-slate-800">{batch.supervisorName || 'N/A'}</p>
            </div>
            <div className="bg-slate-50 p-4 rounded-xl border border-slate-100">
              <p className="text-[10px] text-slate-400 font-bold uppercase mb-1">Total de SKU's</p>
              <p className="text-sm font-bold text-slate-800">{batch.products.length} Itens</p>
            </div>
            <div className="bg-slate-50 p-4 rounded-xl border border-slate-100">
              <p className="text-[10px] text-slate-400 font-bold uppercase mb-1">Notas Fiscais (NFe)</p>
              <p className="text-[11px] font-bold text-blue-600">
                {batch.notes.map(n => n.number).join(', ')}
              </p>
            </div>
          </div>

          {/* Tabela de Produtos */}
          <div className="mb-10">
            <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest mb-4 border-l-4 border-blue-600 pl-3">Detalhamento dos Itens</h3>
            <div className="border border-slate-200 rounded-xl overflow-hidden">
              <table className="w-full text-left text-xs md:text-sm">
                <thead className="bg-slate-100 border-b border-slate-200">
                  <tr className="text-slate-500 font-bold text-[10px] uppercase">
                    <th className="px-4 py-3">Produto (Cód / EAN)</th>
                    <th className="px-4 py-3">Descrição Comercial</th>
                    <th className="px-4 py-3 text-center">Faturado (XML)</th>
                    <th className="px-4 py-3 text-center">Conferido (Físico)</th>
                    <th className="px-4 py-3 text-center">Diferença</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {batch.products.map(p => {
                    const diff = p.quantityChecked - p.quantityExpected;
                    return (
                      <tr key={p.id} className={diff !== 0 ? 'bg-orange-50/50' : ''}>
                        <td className="px-4 py-3 font-mono text-[10px]">
                          <div className="font-bold text-slate-700">{p.code}</div>
                          <div className="text-slate-400">{p.ean}</div>
                        </td>
                        <td className="px-4 py-3 font-medium text-slate-800 leading-tight">{p.description}</td>
                        <td className="px-4 py-3 text-center font-bold">{p.quantityExpected}</td>
                        <td className="px-4 py-3 text-center font-bold text-blue-600">{p.quantityChecked}</td>
                        <td className={`px-4 py-3 text-center font-bold ${diff === 0 ? 'text-slate-300' : diff > 0 ? 'text-blue-500' : 'text-red-500'}`}>
                          {diff > 0 ? `+${diff}` : diff === 0 ? '0' : diff}
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          </div>

          {/* Área de Justificativa */}
          {batch.justification && (
            <div className="mb-10 p-6 bg-orange-50 border-2 border-dashed border-orange-200 rounded-2xl">
              <h3 className="text-xs font-black text-orange-700 uppercase tracking-widest mb-2 flex items-center gap-2">
                <AlertTriangle size={16} />
                Justificativa Operacional do Supervisor
              </h3>
              <p className="text-slate-700 italic text-sm leading-relaxed">"{batch.justification}"</p>
            </div>
          )}

          {/* Assinaturas */}
          <div className="mt-20 grid grid-cols-2 gap-10 md:gap-20">
            <div className="border-t-2 border-slate-200 pt-4 text-center">
              <p className="text-sm font-bold text-slate-800 mb-1">{batch.conferenteName}</p>
              <p className="text-[10px] text-slate-400 font-bold uppercase tracking-wider">Assinatura do Conferente</p>
            </div>
            <div className="border-t-2 border-slate-200 pt-4 text-center">
              <p className="text-sm font-bold text-slate-800 mb-1">{batch.supervisorName || '________________________'}</p>
              <p className="text-[10px] text-slate-400 font-bold uppercase tracking-wider">Assinatura do Supervisor</p>
            </div>
          </div>

          {/* Rodapé do Relatório */}
          <div className="mt-16 pt-8 border-t border-slate-100 text-center">
            <p className="text-[9px] text-slate-400 font-medium tracking-widest uppercase">
              Relatório Gerado via CheckMaster Logistics Cloud em {new Date().toLocaleString('pt-BR')}
            </p>
            <p className="text-[8px] text-slate-300 mt-1 italic">Processo de Conferência Cega - Integridade Garantida.</p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default ReportModal;

