import React, { useState, useEffect } from 'react';
import { User, UserRole, ConferenceBatch } from './types';
import { INITIAL_USERS, STORAGE_KEYS } from './constants';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import XMLUpload from './components/XMLUpload';
import BlindCheck from './components/BlindCheck';
import SupervisorCheck from './components/SupervisorCheck';
import AdminPanel from './components/AdminPanel';
import ReportModal from './components/ReportModal';
import { LogIn, PackageCheck, Eye } from 'lucide-react';

const App: React.FC = () => {
  // Auth State
  const [user, setUser] = useState<User | null>(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.CURRENT_USER);
    return saved ? JSON.parse(saved) : null;
  });
  const [loginForm, setLoginForm] = useState({ username: '', password: '' });
  const [loginError, setLoginError] = useState('');

  // App State
  const [activeTab, setActiveTab] = useState('dashboard');
  const [users, setUsers] = useState<User[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.USERS);
    return saved ? JSON.parse(saved) : INITIAL_USERS;
  });
  const [batches, setBatches] = useState<ConferenceBatch[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.BATCHES);
    return saved ? JSON.parse(saved) : [];
  });
  const [currentBatch, setCurrentBatch] = useState<ConferenceBatch | null>(null);
  const [isSupervisorView, setIsSupervisorView] = useState(false);
  const [viewingReport, setViewingReport] = useState<ConferenceBatch | null>(null);

  // Sync with LocalStorage
  useEffect(() => localStorage.setItem(STORAGE_KEYS.USERS, JSON.stringify(users)), [users]);
  useEffect(() => localStorage.setItem(STORAGE_KEYS.BATCHES, JSON.stringify(batches)), [batches]);
  useEffect(() => {
    if (user) localStorage.setItem(STORAGE_KEYS.CURRENT_USER, JSON.stringify(user));
    else localStorage.removeItem(STORAGE_KEYS.CURRENT_USER);
  }, [user]);

  // Auth Handlers
  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const found = users.find(u => u.username === loginForm.username && u.password === loginForm.password);
    if (found) {
      setUser(found);
      // Redirecionamento inteligente baseado no perfil
      if (found.role === UserRole.CONFERENTE) {
        setActiveTab('upload');
      } else {
        setActiveTab('dashboard');
      }
    } else {
      setLoginError('Credenciais inválidas. Verifique usuário e senha.');
    }
  };

  const handleLogout = () => {
    setUser(null);
    setCurrentBatch(null);
    setIsSupervisorView(false);
  };

  // Conference Handlers
  const startConference = (batch: ConferenceBatch) => {
    setCurrentBatch(batch);
    setActiveTab('checking');
  };

  const finalizeConference = () => {
    if (!currentBatch) return;

    const hasDivergence = currentBatch.products.some(p => p.quantityExpected !== p.quantityChecked);

    if (hasDivergence) {
      setIsSupervisorView(true);
    } else {
      const finalBatch = { ...currentBatch, status: 'APPROVED' as const, endTime: new Date().toISOString() };
      setBatches([finalBatch, ...batches]);
      setCurrentBatch(null);
      setActiveTab('history');
      setViewingReport(finalBatch);
    }
  };

  const handleSupervisorApprove = (supervisor: User, justification: string) => {
    if (!currentBatch) return;
    const finalBatch = { 
      ...currentBatch, 
      status: 'APPROVED' as const, 
      endTime: new Date().toISOString(),
      supervisorId: supervisor.id,
      supervisorName: supervisor.name,
      justification
    };
    setBatches([finalBatch, ...batches]);
    setCurrentBatch(null);
    setIsSupervisorView(false);
    setActiveTab('history');
    setViewingReport(finalBatch);
  };

  // Login Screen
  if (!user) {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center p-4">
        <div className="max-w-md w-full bg-white rounded-3xl shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-300">
          <div className="p-10 text-center bg-slate-50 border-b border-slate-100">
            <div className="bg-blue-600 w-16 h-16 rounded-2xl flex items-center justify-center mx-auto mb-6 shadow-lg shadow-blue-500/30">
              <PackageCheck className="text-white" size={40} />
            </div>
            <h1 className="text-3xl font-black text-slate-800 tracking-tight">CheckMaster</h1>
            <p className="text-slate-500 mt-2 font-medium">Logística & Conferência Cega</p>
          </div>

          <div className="p-10">
            <form onSubmit={handleLogin} className="space-y-6">
              <div>
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1.5 ml-1">Usuário / Login</label>
                <input 
                  type="text" 
                  className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-5 py-4 focus:outline-none focus:ring-2 focus:ring-blue-500 transition-all font-medium"
                  value={loginForm.username}
                  onChange={e => setLoginForm({...loginForm, username: e.target.value})}
                  placeholder="Seu login"
                  required
                />
              </div>
              <div>
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1.5 ml-1">Senha</label>
                <input 
                  type="password" 
                  className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-5 py-4 focus:outline-none focus:ring-2 focus:ring-blue-500 transition-all"
                  value={loginForm.password}
                  onChange={e => setLoginForm({...loginForm, password: e.target.value})}
                  placeholder="••••••••"
                  required
                />
              </div>

              {loginError && <p className="text-red-500 text-xs font-bold text-center bg-red-50 py-3 rounded-xl animate-shake">{loginError}</p>}

              <button 
                type="submit"
                className="w-full bg-blue-600 hover:bg-blue-700 text-white font-black py-5 rounded-2xl shadow-xl shadow-blue-500/30 transition-all flex items-center justify-center gap-2 group text-sm uppercase tracking-widest"
              >
                Acessar Sistema
                <LogIn size={20} className="group-hover:translate-x-1 transition-transform" />
              </button>
            </form>
            <div className="mt-8 text-center">
              <p className="text-slate-300 text-[9px] font-black uppercase tracking-widest">Enterprise Logistics Solution v1.0.5</p>
            </div>
          </div>
        </div>
      </div>
    );
  }

  // Active UI logic with security protection
  let content;
  if (isSupervisorView && currentBatch) {
    content = (
      <SupervisorCheck 
        batch={currentBatch} 
        users={users}
        onApprove={handleSupervisorApprove}
        onReject={() => {
          setIsSupervisorView(false);
          setCurrentBatch(null);
          setActiveTab('upload');
        }}
      />
    );
  } else if (currentBatch && activeTab === 'checking') {
    content = (
      <BlindCheck 
        batch={currentBatch} 
        onUpdateBatch={setCurrentBatch} 
        onFinish={finalizeConference}
      />
    );
  } else {
    switch (activeTab) {
      case 'dashboard': 
        // Proteção contra acesso manual via estado
        if (user.role === UserRole.CONFERENTE) {
          content = <XMLUpload currentUser={user} onStartConference={startConference} />;
          break;
        }
        content = <Dashboard batches={batches} />; 
        break;
      case 'upload': 
        content = <XMLUpload currentUser={user} onStartConference={startConference} />; 
        break;
      case 'history': 
        content = (
          <div className="space-y-6 animate-in fade-in duration-500">
            <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
              <table className="w-full text-left">
                <thead className="bg-slate-50 text-slate-400 text-[10px] font-black uppercase tracking-widest">
                  <tr>
                    <th className="px-6 py-4">Data/Hora</th>
                    <th className="px-6 py-4">Lote ID</th>
                    <th className="px-6 py-4">Conferente</th>
                    <th className="px-6 py-4">Status</th>
                    <th className="px-6 py-4 text-right">Ações</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50">
                  {batches.map(b => (
                    <tr key={b.id} className="hover:bg-slate-50/50 group transition-colors">
                      <td className="px-6 py-4 text-xs font-bold text-slate-500">
                        {new Date(b.endTime || b.startTime).toLocaleString('pt-BR')}
                      </td>
                      <td className="px-6 py-4 text-sm font-mono font-black text-blue-600 uppercase tracking-tighter">#{b.id}</td>
                      <td className="px-6 py-4 text-sm font-bold text-slate-800">{b.conferenteName}</td>
                      <td className="px-6 py-4">
                        <span className={`px-3 py-1 rounded-lg text-[10px] font-black tracking-widest uppercase ${
                          b.status === 'APPROVED' ? 'bg-green-100 text-green-700' : 'bg-orange-100 text-orange-700'
                        }`}>
                          {b.status}
                        </span>
                      </td>
                      <td className="px-6 py-4 text-right">
                        <div className="flex justify-end gap-2">
                           <button 
                            onClick={() => setViewingReport(b)}
                            className="bg-slate-100 text-slate-600 hover:bg-blue-600 hover:text-white px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all flex items-center gap-2"
                          >
                            <Eye size={14} />
                            Relatório
                          </button>
                        </div>
                      </td>
                    </tr>
                  ))}
                  {batches.length === 0 && (
                    <tr>
                      <td colSpan={5} className="px-6 py-20 text-center text-slate-300 font-bold uppercase text-[10px] tracking-widest">Nenhum histórico disponível.</td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          </div>
        );
        break;
      case 'admin': 
        // Proteção total para o módulo de usuários
        if (user.role === UserRole.CONFERENTE) {
          content = <XMLUpload currentUser={user} onStartConference={startConference} />;
          break;
        }
        content = (
          <AdminPanel 
            users={users} 
            onAddUser={(u) => setUsers([...users, u])} 
            onDeleteUser={(id) => setUsers(users.filter(u => u.id !== id))}
          />
        ); break;
      default: 
        content = user.role === UserRole.CONFERENTE ? 
          <XMLUpload currentUser={user} onStartConference={startConference} /> : 
          <Dashboard batches={batches} />;
    }
  }

  return (
    <Layout user={user} onLogout={handleLogout} activeTab={activeTab} setActiveTab={setActiveTab}>
      {content}
      {viewingReport && (
        <ReportModal 
          batch={viewingReport} 
          onClose={() => setViewingReport(null)} 
        />
      )}
    </Layout>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { User, UserRole, ConferenceBatch } from './types';
import { INITIAL_USERS, STORAGE_KEYS } from './constants';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import XMLUpload from './components/XMLUpload';
import BlindCheck from './components/BlindCheck';
import SupervisorCheck from './components/SupervisorCheck';
import AdminPanel from './components/AdminPanel';
import ReportModal from './components/ReportModal';
import { LogIn, PackageCheck, Eye } from 'lucide-react';

const App: React.FC = () => {
  // Auth State
  const [user, setUser] = useState<User | null>(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.CURRENT_USER);
    return saved ? JSON.parse(saved) : null;
  });
  const [loginForm, setLoginForm] = useState({ username: '', password: '' });
  const [loginError, setLoginError] = useState('');

  // App State
  const [activeTab, setActiveTab] = useState('dashboard');
  const [users, setUsers] = useState<User[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.USERS);
    return saved ? JSON.parse(saved) : INITIAL_USERS;
  });
  const [batches, setBatches] = useState<ConferenceBatch[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.BATCHES);
    return saved ? JSON.parse(saved) : [];
  });
  const [currentBatch, setCurrentBatch] = useState<ConferenceBatch | null>(null);
  const [isSupervisorView, setIsSupervisorView] = useState(false);
  const [viewingReport, setViewingReport] = useState<ConferenceBatch | null>(null);

  // Sync with LocalStorage
  useEffect(() => localStorage.setItem(STORAGE_KEYS.USERS, JSON.stringify(users)), [users]);
  useEffect(() => localStorage.setItem(STORAGE_KEYS.BATCHES, JSON.stringify(batches)), [batches]);
  useEffect(() => {
    if (user) localStorage.setItem(STORAGE_KEYS.CURRENT_USER, JSON.stringify(user));
    else localStorage.removeItem(STORAGE_KEYS.CURRENT_USER);
  }, [user]);

  // Auth Handlers
  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const found = users.find(u => u.username === loginForm.username && u.password === loginForm.password);
    if (found) {
      setUser(found);
      // Redirecionamento inteligente baseado no perfil
      if (found.role === UserRole.CONFERENTE) {
        setActiveTab('upload');
      } else {
        setActiveTab('dashboard');
      }
    } else {
      setLoginError('Credenciais inválidas. Verifique usuário e senha.');
    }
  };

  const handleLogout = () => {
    setUser(null);
    setCurrentBatch(null);
    setIsSupervisorView(false);
    // Limpa os campos de login ao sair
    setLoginForm({ username: '', password: '' });
    setLoginError('');
  };

  // Conference Handlers
  const startConference = (batch: ConferenceBatch) => {
    setCurrentBatch(batch);
    setActiveTab('checking');
  };

  const finalizeConference = () => {
    if (!currentBatch) return;

    const hasDivergence = currentBatch.products.some(p => p.quantityExpected !== p.quantityChecked);

    if (hasDivergence) {
      setIsSupervisorView(true);
    } else {
      const finalBatch = { ...currentBatch, status: 'APPROVED' as const, endTime: new Date().toISOString() };
      setBatches([finalBatch, ...batches]);
      setCurrentBatch(null);
      setActiveTab('history');
      setViewingReport(finalBatch);
    }
  };

  const handleSupervisorApprove = (supervisor: User, justification: string) => {
    if (!currentBatch) return;
    const finalBatch = { 
      ...currentBatch, 
      status: 'APPROVED' as const, 
      endTime: new Date().toISOString(),
      supervisorId: supervisor.id,
      supervisorName: supervisor.name,
      justification
    };
    setBatches([finalBatch, ...batches]);
    setCurrentBatch(null);
    setIsSupervisorView(false);
    setActiveTab('history');
    setViewingReport(finalBatch);
  };

  // Login Screen
  if (!user) {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center p-4">
        <div className="max-w-md w-full bg-white rounded-3xl shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-300">
          <div className="p-10 text-center bg-slate-50 border-b border-slate-100">
            <div className="bg-blue-600 w-16 h-16 rounded-2xl flex items-center justify-center mx-auto mb-6 shadow-lg shadow-blue-500/30">
              <PackageCheck className="text-white" size={40} />
            </div>
            <h1 className="text-3xl font-black text-slate-800 tracking-tight">CheckMaster</h1>
            <p className="text-slate-500 mt-2 font-medium">Logística & Conferência Cega</p>
          </div>

          <div className="p-10">
            <form onSubmit={handleLogin} className="space-y-6">
              <div>
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1.5 ml-1">Usuário / Login</label>
                <input 
                  type="text" 
                  className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-5 py-4 focus:outline-none focus:ring-2 focus:ring-blue-500 transition-all font-medium"
                  value={loginForm.username}
                  onChange={e => setLoginForm({...loginForm, username: e.target.value})}
                  placeholder="Seu login"
                  required
                />
              </div>
              <div>
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1.5 ml-1">Senha</label>
                <input 
                  type="password" 
                  className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-5 py-4 focus:outline-none focus:ring-2 focus:ring-blue-500 transition-all"
                  value={loginForm.password}
                  onChange={e => setLoginForm({...loginForm, password: e.target.value})}
                  placeholder="••••••••"
                  required
                />
              </div>

              {loginError && <p className="text-red-500 text-xs font-bold text-center bg-red-50 py-3 rounded-xl animate-shake">{loginError}</p>}

              <button 
                type="submit"
                className="w-full bg-blue-600 hover:bg-blue-700 text-white font-black py-5 rounded-2xl shadow-xl shadow-blue-500/30 transition-all flex items-center justify-center gap-2 group text-sm uppercase tracking-widest"
              >
                Acessar Sistema
                <LogIn size={20} className="group-hover:translate-x-1 transition-transform" />
              </button>
            </form>
            <div className="mt-8 text-center">
              <p className="text-slate-300 text-[9px] font-black uppercase tracking-widest">Enterprise Logistics Solution v1.0.5</p>
            </div>
          </div>
        </div>
      </div>
    );
  }

  // Active UI logic with security protection
  let content;
  if (isSupervisorView && currentBatch) {
    content = (
      <SupervisorCheck 
        batch={currentBatch} 
        users={users}
        onApprove={handleSupervisorApprove}
        onReject={() => {
          setIsSupervisorView(false);
          setCurrentBatch(null);
          setActiveTab('upload');
        }}
      />
    );
  } else if (currentBatch && activeTab === 'checking') {
    content = (
      <BlindCheck 
        batch={currentBatch} 
        onUpdateBatch={setCurrentBatch} 
        onFinish={finalizeConference}
      />
    );
  } else {
    switch (activeTab) {
      case 'dashboard': 
        if (user.role === UserRole.CONFERENTE) {
          content = <XMLUpload currentUser={user} onStartConference={startConference} />;
          break;
        }
        content = <Dashboard batches={batches} />; 
        break;
      case 'upload': 
        content = <XMLUpload currentUser={user} onStartConference={startConference} />; 
        break;
      case 'history': 
        content = (
          <div className="space-y-6 animate-in fade-in duration-500">
            <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
              <table className="w-full text-left">
                <thead className="bg-slate-50 text-slate-400 text-[10px] font-black uppercase tracking-widest">
                  <tr>
                    <th className="px-6 py-4">Data/Hora</th>
                    <th className="px-6 py-4">Lote ID</th>
                    <th className="px-6 py-4">Conferente</th>
                    <th className="px-6 py-4">Status</th>
                    <th className="px-6 py-4 text-right">Ações</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50">
                  {batches.map(b => (
                    <tr key={b.id} className="hover:bg-slate-50/50 group transition-colors">
                      <td className="px-6 py-4 text-xs font-bold text-slate-500">
                        {new Date(b.endTime || b.startTime).toLocaleString('pt-BR')}
                      </td>
                      <td className="px-6 py-4 text-sm font-mono font-black text-blue-600 uppercase tracking-tighter">#{b.id}</td>
                      <td className="px-6 py-4 text-sm font-bold text-slate-800">{b.conferenteName}</td>
                      <td className="px-6 py-4">
                        <span className={`px-3 py-1 rounded-lg text-[10px] font-black tracking-widest uppercase ${
                          b.status === 'APPROVED' ? 'bg-green-100 text-green-700' : 'bg-orange-100 text-orange-700'
                        }`}>
                          {b.status}
                        </span>
                      </td>
                      <td className="px-6 py-4 text-right">
                        <div className="flex justify-end gap-2">
                           <button 
                            onClick={() => setViewingReport(b)}
                            className="bg-slate-100 text-slate-600 hover:bg-blue-600 hover:text-white px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all flex items-center gap-2"
                          >
                            <Eye size={14} />
                            Relatório
                          </button>
                        </div>
                      </td>
                    </tr>
                  ))}
                  {batches.length === 0 && (
                    <tr>
                      <td colSpan={5} className="px-6 py-20 text-center text-slate-300 font-bold uppercase text-[10px] tracking-widest">Nenhum histórico disponível.</td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          </div>
        );
        break;
      case 'admin': 
        if (user.role === UserRole.CONFERENTE) {
          content = <XMLUpload currentUser={user} onStartConference={startConference} />;
          break;
        }
        content = (
          <AdminPanel 
            users={users} 
            onAddUser={(u) => setUsers([...users, u])} 
            onDeleteUser={(id) => setUsers(users.filter(u => u.id !== id))}
          />
        ); break;
      default: 
        content = user.role === UserRole.CONFERENTE ? 
          <XMLUpload currentUser={user} onStartConference={startConference} /> : 
          <Dashboard batches={batches} />;
    }
  }

  return (
    <Layout user={user} onLogout={handleLogout} activeTab={activeTab} setActiveTab={setActiveTab}>
      {content}
      {viewingReport && (
        <ReportModal 
          batch={viewingReport} 
          onClose={() => setViewingReport(null)} 
        />
      )}
    </Layout>
  );
};

export default App;

