import React, { useState, useEffect } from 'react';
import { User, UserRole, ConferenceBatch } from './types';
import { INITIAL_USERS, STORAGE_KEYS } from './constants';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import XMLUpload from './components/XMLUpload';
import BlindCheck from './components/BlindCheck';
import SupervisorCheck from './components/SupervisorCheck';
import AdminPanel from './components/AdminPanel';
import ReportModal from './components/ReportModal';
import { LogIn, PackageCheck, Eye } from 'lucide-react';

const App: React.FC = () => {
  // Auth State
  const [user, setUser] = useState<User | null>(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.CURRENT_USER);
    return saved ? JSON.parse(saved) : null;
  });
  const [loginForm, setLoginForm] = useState({ username: '', password: '' });
  const [loginError, setLoginError] = useState('');

  // App State
  const [activeTab, setActiveTab] = useState('dashboard');
  const [users, setUsers] = useState<User[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.USERS);
    return saved ? JSON.parse(saved) : INITIAL_USERS;
  });
  const [batches, setBatches] = useState<ConferenceBatch[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.BATCHES);
    return saved ? JSON.parse(saved) : [];
  });
  const [currentBatch, setCurrentBatch] = useState<ConferenceBatch | null>(null);
  const [isSupervisorView, setIsSupervisorView] = useState(false);
  const [viewingReport, setViewingReport] = useState<ConferenceBatch | null>(null);

  // Sync with LocalStorage
  useEffect(() => localStorage.setItem(STORAGE_KEYS.USERS, JSON.stringify(users)), [users]);
  useEffect(() => localStorage.setItem(STORAGE_KEYS.BATCHES, JSON.stringify(batches)), [batches]);
  useEffect(() => {
    if (user) localStorage.setItem(STORAGE_KEYS.CURRENT_USER, JSON.stringify(user));
    else localStorage.removeItem(STORAGE_KEYS.CURRENT_USER);
  }, [user]);

  // Auth Handlers
  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const found = users.find(u => u.username === loginForm.username && u.password === loginForm.password);
    if (found) {
      setUser(found);
      // Redirecionamento inteligente baseado no perfil
      if (found.role === UserRole.CONFERENTE) {
        setActiveTab('upload');
      } else {
        setActiveTab('dashboard');
      }
    } else {
      setLoginError('Credenciais inválidas. Verifique usuário e senha.');
    }
  };

  const handleLogout = () => {
    setUser(null);
    setCurrentBatch(null);
    setIsSupervisorView(false);
    // Limpa os campos de login ao sair
    setLoginForm({ username: '', password: '' });
    setLoginError('');
  };

  const handleUpdateUser = (updatedUser: User) => {
    setUsers(users.map(u => u.id === updatedUser.id ? updatedUser : u));
    // Se o usuário atual for o mesmo que foi atualizado, atualiza a sessão também
    if (user && user.id === updatedUser.id) {
      setUser(updatedUser);
    }
  };

  // Conference Handlers
  const startConference = (batch: ConferenceBatch) => {
    setCurrentBatch(batch);
    setActiveTab('checking');
  };

  const finalizeConference = () => {
    if (!currentBatch) return;

    const hasDivergence = currentBatch.products.some(p => p.quantityExpected !== p.quantityChecked);

    if (hasDivergence) {
      setIsSupervisorView(true);
    } else {
      const finalBatch = { ...currentBatch, status: 'APPROVED' as const, endTime: new Date().toISOString() };
      setBatches([finalBatch, ...batches]);
      setCurrentBatch(null);
      setActiveTab('history');
      setViewingReport(finalBatch);
    }
  };

  const handleSupervisorApprove = (supervisor: User, justification: string) => {
    if (!currentBatch) return;
    const finalBatch = { 
      ...currentBatch, 
      status: 'APPROVED' as const, 
      endTime: new Date().toISOString(),
      supervisorId: supervisor.id,
      supervisorName: supervisor.name,
      justification
    };
    setBatches([finalBatch, ...batches]);
    setCurrentBatch(null);
    setIsSupervisorView(false);
    setActiveTab('history');
    setViewingReport(finalBatch);
  };

  // Login Screen
  if (!user) {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center p-4">
        <div className="max-w-md w-full bg-white rounded-3xl shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-300">
          <div className="p-10 text-center bg-slate-50 border-b border-slate-100">
            <div className="bg-blue-600 w-16 h-16 rounded-2xl flex items-center justify-center mx-auto mb-6 shadow-lg shadow-blue-500/30">
              <PackageCheck className="text-white" size={40} />
            </div>
            <h1 className="text-3xl font-black text-slate-800 tracking-tight">CheckMaster</h1>
            <p className="text-slate-500 mt-2 font-medium">Logística & Conferência Cega</p>
          </div>

          <div className="p-10">
            <form onSubmit={handleLogin} className="space-y-6">
              <div>
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1.5 ml-1">Usuário / Login</label>
                <input 
                  type="text" 
                  className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-5 py-4 focus:outline-none focus:ring-2 focus:ring-blue-500 transition-all font-medium"
                  value={loginForm.username}
                  onChange={e => setLoginForm({...loginForm, username: e.target.value})}
                  placeholder="Seu login"
                  required
                />
              </div>
              <div>
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1.5 ml-1">Senha</label>
                <input 
                  type="password" 
                  className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-5 py-4 focus:outline-none focus:ring-2 focus:ring-blue-500 transition-all"
                  value={loginForm.password}
                  onChange={e => setLoginForm({...loginForm, password: e.target.value})}
                  placeholder="••••••••"
                  required
                />
              </div>

              {loginError && <p className="text-red-500 text-xs font-bold text-center bg-red-50 py-3 rounded-xl animate-shake">{loginError}</p>}

              <button 
                type="submit"
                className="w-full bg-blue-600 hover:bg-blue-700 text-white font-black py-5 rounded-2xl shadow-xl shadow-blue-500/30 transition-all flex items-center justify-center gap-2 group text-sm uppercase tracking-widest"
              >
                Acessar Sistema
                <LogIn size={20} className="group-hover:translate-x-1 transition-transform" />
              </button>
            </form>
            <div className="mt-8 text-center">
              <p className="text-slate-300 text-[9px] font-black uppercase tracking-widest">Enterprise Logistics Solution v1.0.5</p>
            </div>
          </div>
        </div>
      </div>
    );
  }

  // Active UI logic with security protection
  let content;
  if (isSupervisorView && currentBatch) {
    content = (
      <SupervisorCheck 
        batch={currentBatch} 
        users={users}
        onApprove={handleSupervisorApprove}
        onReject={() => {
          setIsSupervisorView(false);
          setCurrentBatch(null);
          setActiveTab('upload');
        }}
      />
    );
  } else if (currentBatch && activeTab === 'checking') {
    content = (
      <BlindCheck 
        batch={currentBatch} 
        onUpdateBatch={setCurrentBatch} 
        onFinish={finalizeConference}
      />
    );
  } else {
    switch (activeTab) {
      case 'dashboard': 
        if (user.role === UserRole.CONFERENTE) {
          content = <XMLUpload currentUser={user} onStartConference={startConference} />;
          break;
        }
        content = <Dashboard batches={batches} />; 
        break;
      case 'upload': 
        content = <XMLUpload currentUser={user} onStartConference={startConference} />; 
        break;
      case 'history': 
        content = (
          <div className="space-y-6 animate-in fade-in duration-500">
            <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
              <table className="w-full text-left">
                <thead className="bg-slate-50 text-slate-400 text-[10px] font-black uppercase tracking-widest">
                  <tr>
                    <th className="px-6 py-4">Data/Hora</th>
                    <th className="px-6 py-4">Lote ID</th>
                    <th className="px-6 py-4">Conferente</th>
                    <th className="px-6 py-4">Status</th>
                    <th className="px-6 py-4 text-right">Ações</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50">
                  {batches.map(b => (
                    <tr key={b.id} className="hover:bg-slate-50/50 group transition-colors">
                      <td className="px-6 py-4 text-xs font-bold text-slate-500">
                        {new Date(b.endTime || b.startTime).toLocaleString('pt-BR')}
                      </td>
                      <td className="px-6 py-4 text-sm font-mono font-black text-blue-600 uppercase tracking-tighter">#{b.id}</td>
                      <td className="px-6 py-4 text-sm font-bold text-slate-800">{b.conferenteName}</td>
                      <td className="px-6 py-4">
                        <span className={`px-3 py-1 rounded-lg text-[10px] font-black tracking-widest uppercase ${
                          b.status === 'APPROVED' ? 'bg-green-100 text-green-700' : 'bg-orange-100 text-orange-700'
                        }`}>
                          {b.status}
                        </span>
                      </td>
                      <td className="px-6 py-4 text-right">
                        <div className="flex justify-end gap-2">
                           <button 
                            onClick={() => setViewingReport(b)}
                            className="bg-slate-100 text-slate-600 hover:bg-blue-600 hover:text-white px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all flex items-center gap-2"
                          >
                            <Eye size={14} />
                            Relatório
                          </button>
                        </div>
                      </td>
                    </tr>
                  ))}
                  {batches.length === 0 && (
                    <tr>
                      <td colSpan={5} className="px-6 py-20 text-center text-slate-300 font-bold uppercase text-[10px] tracking-widest">Nenhum histórico disponível.</td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          </div>
        );
        break;
      case 'admin': 
        if (user.role === UserRole.CONFERENTE) {
          content = <XMLUpload currentUser={user} onStartConference={startConference} />;
          break;
        }
        content = (
          <AdminPanel 
            users={users} 
            currentUser={user}
            onAddUser={(u) => setUsers([...users, u])} 
            onDeleteUser={(id) => setUsers(users.filter(u => u.id !== id))}
            onUpdateUser={handleUpdateUser}
          />
        ); break;
      default: 
        content = user.role === UserRole.CONFERENTE ? 
          <XMLUpload currentUser={user} onStartConference={startConference} /> : 
          <Dashboard batches={batches} />;
    }
  }

  return (
    <Layout user={user} onLogout={handleLogout} activeTab={activeTab} setActiveTab={setActiveTab}>
      {content}
      {viewingReport && (
        <ReportModal 
          batch={viewingReport} 
          onClose={() => setViewingReport(null)} 
        />
      )}
    </Layout>
  );
};

export default App;

import React, { useState } from 'react';
import { ShieldCheck, AlertCircle, CheckCircle2, XCircle, Info, Lock, User as UserIcon } from 'lucide-react';
import { ConferenceBatch, User, UserRole } from '../types';

interface SupervisorCheckProps {
  batch: ConferenceBatch;
  users: User[];
  onApprove: (supervisor: User, justification: string) => void;
  onReject: () => void;
}

const SupervisorCheck: React.FC<SupervisorCheckProps> = ({ batch, users, onApprove, onReject }) => {
  const [supervisorUser, setSupervisorUser] = useState('');
  const [supervisorPass, setSupervisorPass] = useState('');
  const [justification, setJustification] = useState('');
  const [error, setError] = useState('');
  const [validatedUser, setValidatedUser] = useState<User | null>(null);

  const discrepancies = batch.products.filter(p => p.quantityExpected !== p.quantityChecked);

  const handleValidate = () => {
    // Agora validamos LOGIN e SENHA para garantir que a pessoa física seja um supervisor/admin
    const found = users.find(u => 
      (u.role === UserRole.SUPERVISOR || u.role === UserRole.ADMIN) && 
      u.username.toLowerCase() === supervisorUser.toLowerCase() &&
      u.password === supervisorPass
    );

    if (found) {
      setValidatedUser(found);
      setError('');
    } else {
      setError('Acesso negado. Usuário/senha inválidos ou perfil sem permissão de supervisor.');
    }
  };

  const submitApproval = () => {
    if (!justification.trim()) {
      setError('A justificativa é obrigatória para aprovação com divergência.');
      return;
    }
    if (validatedUser) {
      onApprove(validatedUser, justification);
    }
  };

  if (!validatedUser) {
    return (
      <div className="max-w-md mx-auto mt-20 bg-white p-8 rounded-2xl shadow-xl border border-slate-100 animate-in fade-in zoom-in duration-300">
        <div className="text-center mb-8">
          <div className="bg-orange-100 w-16 h-16 rounded-full flex items-center justify-center mx-auto mb-4">
            <ShieldCheck className="text-orange-600" size={32} />
          </div>
          <h2 className="text-2xl font-black text-slate-800 uppercase tracking-tight">Validação Requerida</h2>
          <p className="text-slate-500 mt-2 text-sm font-medium">Apenas supervisores podem autorizar divergências.</p>
        </div>

        <div className="space-y-4">
          <div className="bg-orange-50 p-4 rounded-xl border border-orange-100 flex gap-3 text-orange-800 text-sm">
            <AlertCircle size={20} className="shrink-0" />
            <p>O lote contém diferenças entre o XML e o físico. Insira credenciais de supervisor.</p>
          </div>

          <div className="space-y-3">
            <div className="relative">
              <UserIcon className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
              <input
                type="text"
                value={supervisorUser}
                onChange={(e) => setSupervisorUser(e.target.value)}
                placeholder="Login do Supervisor"
                className="w-full bg-slate-50 border border-slate-200 rounded-xl py-4 pl-12 pr-4 focus:ring-2 focus:ring-orange-500 focus:outline-none font-medium"
              />
            </div>

            <div className="relative">
              <Lock className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
              <input
                type="password"
                value={supervisorPass}
                onChange={(e) => setSupervisorPass(e.target.value)}
                placeholder="Senha"
                className="w-full bg-slate-50 border border-slate-200 rounded-xl py-4 pl-12 pr-4 focus:ring-2 focus:ring-orange-500 focus:outline-none"
              />
            </div>
          </div>

          {error && <p className="text-red-500 text-xs font-bold text-center bg-red-50 py-3 rounded-xl">{error}</p>}

          <button
            onClick={handleValidate}
            className="w-full bg-slate-900 hover:bg-black text-white py-4 rounded-xl font-bold transition-all shadow-lg flex items-center justify-center gap-2"
          >
            <ShieldCheck size={18} />
            Autorizar como Supervisor
          </button>

          <button
            onClick={onReject}
            className="w-full bg-white border border-slate-200 hover:bg-slate-50 text-slate-600 py-4 rounded-xl font-bold transition-all"
          >
            Cancelar e Re-conferir
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-5xl mx-auto space-y-6 animate-in slide-in-from-bottom-4 duration-500">
      <div className="bg-white p-8 rounded-2xl shadow-sm border border-slate-100">
        <div className="flex justify-between items-start mb-8">
          <div>
            <h2 className="text-2xl font-black text-slate-800 tracking-tight uppercase">Análise de Divergências</h2>
            <p className="text-slate-500 font-medium">Validado por: <span className="text-orange-600 font-bold">{validatedUser.name}</span></p>
          </div>
          <span className="bg-orange-100 text-orange-700 px-4 py-2 rounded-full text-[10px] font-black uppercase tracking-widest flex items-center gap-2">
            <Info size={16} />
            Divergência Crítica
          </span>
        </div>

        <div className="overflow-hidden border border-slate-100 rounded-2xl mb-8 shadow-sm">
          <table className="w-full text-left">
            <thead className="bg-slate-50 text-slate-400 text-[10px] font-black uppercase tracking-widest">
              <tr>
                <th className="px-6 py-4">Produto</th>
                <th className="px-6 py-4 text-center">XML (Faturado)</th>
                <th className="px-6 py-4 text-center">Físico (Lido)</th>
                <th className="px-6 py-4 text-center">Diferença</th>
                <th className="px-6 py-4 text-center">Status</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {discrepancies.map((p) => {
                const diff = p.quantityChecked - p.quantityExpected;
                const isSobra = diff > 0;
                return (
                  <tr key={p.id} className="hover:bg-slate-50/50 transition-colors">
                    <td className="px-6 py-4">
                      <p className="font-bold text-slate-800 text-sm">{p.description}</p>
                      <p className="text-xs text-slate-400 font-mono">{p.ean}</p>
                    </td>
                    <td className="px-6 py-4 text-center font-black text-slate-600">{p.quantityExpected}</td>
                    <td className="px-6 py-4 text-center font-black text-blue-600">{p.quantityChecked}</td>
                    <td className={`px-6 py-4 text-center font-black ${isSobra ? 'text-blue-600' : 'text-red-600'}`}>
                      {diff > 0 ? `+${diff}` : diff}
                    </td>
                    <td className="px-6 py-4 text-center">
                      <span className={`px-3 py-1 rounded-lg text-[10px] font-black uppercase tracking-tighter ${isSobra ? 'bg-blue-100 text-blue-700' : 'bg-red-100 text-red-700'}`}>
                        {isSobra ? 'SOBRA' : 'FALTA'}
                      </span>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>

        <div className="space-y-4">
          <div className="flex items-center gap-2 ml-1">
            <CheckCircle2 size={16} className="text-slate-400" />
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Justificativa da Liberação</label>
          </div>
          <textarea
            autoFocus
            value={justification}
            onChange={(e) => setJustification(e.target.value)}
            className="w-full bg-slate-50 border border-slate-200 rounded-2xl p-6 min-h-[140px] focus:ring-2 focus:ring-blue-500 focus:outline-none transition-all font-medium text-slate-700"
            placeholder="Descreva detalhadamente o motivo da aprovação deste lote com divergência..."
          ></textarea>

          {error && <p className="text-red-500 text-xs font-bold bg-red-50 p-3 rounded-xl">{error}</p>}

          <div className="flex gap-4 pt-4">
            <button
              onClick={onReject}
              className="flex-1 bg-white border border-slate-200 hover:bg-red-50 hover:text-red-600 text-slate-600 py-5 rounded-2xl font-bold transition-all flex items-center justify-center gap-3"
            >
              <XCircle size={22} />
              Recusar e Reiniciar
            </button>
            <button
              onClick={submitApproval}
              className="flex-1 bg-green-600 hover:bg-green-700 text-white py-5 rounded-2xl font-bold transition-all shadow-xl shadow-green-500/20 flex items-center justify-center gap-3"
            >
              <CheckCircle2 size={22} />
              Autorizar Conclusão
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

