import React, { useState } from 'react';
import { ShieldCheck, AlertCircle, CheckCircle2, XCircle, Info, Lock, User as UserIcon } from 'lucide-react';
import { ConferenceBatch, User, UserRole } from '../types';

interface SupervisorCheckProps {
  batch: ConferenceBatch;
  users: User[];
  onApprove: (supervisor: User, justification: string) => void;
  onReject: () => void;
}

const SupervisorCheck: React.FC<SupervisorCheckProps> = ({ batch, users, onApprove, onReject }) => {
  const [supervisorUser, setSupervisorUser] = useState('');
  const [supervisorPass, setSupervisorPass] = useState('');
  const [justification, setJustification] = useState('');
  const [error, setError] = useState('');
  const [validatedUser, setValidatedUser] = useState<User | null>(null);

  const discrepancies = batch.products.filter(p => p.quantityExpected !== p.quantityChecked);

  const handleValidate = () => {
    const found = users.find(u => 
      (u.role === UserRole.SUPERVISOR || u.role === UserRole.ADMIN) && 
      u.username.toLowerCase() === supervisorUser.toLowerCase() &&
      u.password === supervisorPass
    );

    if (found) {
      setValidatedUser(found);
      setError('');
    } else {
      setError('Acesso negado. Usuário/senha inválidos ou perfil sem permissão de supervisor.');
    }
  };

  const submitApproval = () => {
    if (!justification.trim()) {
      setError('A justificativa é obrigatória para aprovação com divergência.');
      return;
    }
    if (validatedUser) {
      onApprove(validatedUser, justification);
    }
  };

  if (!validatedUser) {
    return (
      <div className="max-w-md mx-auto mt-20 bg-white p-8 rounded-2xl shadow-xl border border-slate-100 animate-in fade-in zoom-in duration-300">
        <div className="text-center mb-8">
          <div className="bg-orange-100 w-16 h-16 rounded-full flex items-center justify-center mx-auto mb-4">
            <ShieldCheck className="text-orange-600" size={32} />
          </div>
          <h2 className="text-2xl font-black text-slate-800 uppercase tracking-tight">Validação Requerida</h2>
          <p className="text-slate-500 mt-2 text-sm font-medium">Apenas supervisores podem autorizar divergências.</p>
        </div>

        <div className="space-y-4">
          <div className="bg-orange-50 p-4 rounded-xl border border-orange-100 flex gap-3 text-orange-800 text-sm">
            <AlertCircle size={20} className="shrink-0" />
            <p>O lote contém diferenças entre o XML e o físico. Insira credenciais de supervisor.</p>
          </div>

          <div className="space-y-3">
            <div className="relative">
              <UserIcon className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
              <input
                type="text"
                value={supervisorUser}
                onChange={(e) => setSupervisorUser(e.target.value)}
                placeholder="Login do Supervisor"
                className="w-full bg-slate-50 border border-slate-200 rounded-xl py-4 pl-12 pr-4 focus:ring-2 focus:ring-orange-500 focus:outline-none font-medium"
              />
            </div>

            <div className="relative">
              <Lock className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
              <input
                type="password"
                value={supervisorPass}
                onChange={(e) => setSupervisorPass(e.target.value)}
                placeholder="Senha"
                className="w-full bg-slate-50 border border-slate-200 rounded-xl py-4 pl-12 pr-4 focus:ring-2 focus:ring-orange-500 focus:outline-none"
              />
            </div>
          </div>

          {error && <p className="text-red-500 text-xs font-bold text-center bg-red-50 py-3 rounded-xl">{error}</p>}

          <button
            onClick={handleValidate}
            className="w-full bg-slate-900 hover:bg-black text-white py-4 rounded-xl font-bold transition-all shadow-lg flex items-center justify-center gap-2"
          >
            <ShieldCheck size={18} />
            Autorizar como Supervisor
          </button>

          <button
            onClick={onReject}
            className="w-full bg-white border border-slate-200 hover:bg-slate-50 text-slate-600 py-4 rounded-xl font-bold transition-all"
          >
            Voltar para Conferência
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-5xl mx-auto space-y-6 animate-in slide-in-from-bottom-4 duration-500">
      <div className="bg-white p-8 rounded-2xl shadow-sm border border-slate-100">
        <div className="flex justify-between items-start mb-8">
          <div>
            <h2 className="text-2xl font-black text-slate-800 tracking-tight uppercase">Análise de Divergências</h2>
            <p className="text-slate-500 font-medium">Validado por: <span className="text-orange-600 font-bold">{validatedUser.name}</span></p>
          </div>
          <span className="bg-orange-100 text-orange-700 px-4 py-2 rounded-full text-[10px] font-black uppercase tracking-widest flex items-center gap-2">
            <Info size={16} />
            Divergência Crítica
          </span>
        </div>

        <div className="overflow-hidden border border-slate-100 rounded-2xl mb-8 shadow-sm">
          <table className="w-full text-left">
            <thead className="bg-slate-50 text-slate-400 text-[10px] font-black uppercase tracking-widest">
              <tr>
                <th className="px-6 py-4">Produto</th>
                <th className="px-6 py-4 text-center">XML (Faturado)</th>
                <th className="px-6 py-4 text-center">Físico (Lido)</th>
                <th className="px-6 py-4 text-center">Diferença</th>
                <th className="px-6 py-4 text-center">Status</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {discrepancies.map((p) => {
                const diff = p.quantityChecked - p.quantityExpected;
                const isSobra = diff > 0;
                return (
                  <tr key={p.id} className="hover:bg-slate-50/50 transition-colors">
                    <td className="px-6 py-4">
                      <p className="font-bold text-slate-800 text-sm">{p.description}</p>
                      <p className="text-xs text-slate-400 font-mono">{p.ean}</p>
                    </td>
                    <td className="px-6 py-4 text-center font-black text-slate-600">{p.quantityExpected}</td>
                    <td className="px-6 py-4 text-center font-black text-blue-600">{p.quantityChecked}</td>
                    <td className={`px-6 py-4 text-center font-black ${isSobra ? 'text-blue-600' : 'text-red-600'}`}>
                      {diff > 0 ? `+${diff}` : diff}
                    </td>
                    <td className="px-6 py-4 text-center">
                      <span className={`px-3 py-1 rounded-lg text-[10px] font-black uppercase tracking-tighter ${isSobra ? 'bg-blue-100 text-blue-700' : 'bg-red-100 text-red-700'}`}>
                        {isSobra ? 'SOBRA' : 'FALTA'}
                      </span>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>

        <div className="space-y-4">
          <div className="flex items-center gap-2 ml-1">
            <CheckCircle2 size={16} className="text-slate-400" />
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Justificativa da Liberação</label>
          </div>
          <textarea
            autoFocus
            value={justification}
            onChange={(e) => setJustification(e.target.value)}
            className="w-full bg-slate-50 border border-slate-200 rounded-2xl p-6 min-h-[140px] focus:ring-2 focus:ring-blue-500 focus:outline-none transition-all font-medium text-slate-700"
            placeholder="Descreva detalhadamente o motivo da aprovação deste lote com divergência..."
          ></textarea>

          {error && <p className="text-red-500 text-xs font-bold bg-red-50 p-3 rounded-xl">{error}</p>}

          <div className="flex gap-4 pt-4">
            <button
              onClick={onReject}
              className="flex-1 bg-white border border-slate-200 hover:bg-slate-100 text-slate-600 py-5 rounded-2xl font-bold transition-all flex items-center justify-center gap-3"
            >
              <XCircle size={22} />
              Voltar para Ajustes
            </button>
            <button
              onClick={submitApproval}
              className="flex-1 bg-green-600 hover:bg-green-700 text-white py-5 rounded-2xl font-bold transition-all shadow-xl shadow-green-500/20 flex items-center justify-center gap-3"
            >
              <CheckCircle2 size={22} />
              Autorizar Conclusão
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default SupervisorCheck;

import React, { useState, useEffect } from 'react';
import { User, UserRole, ConferenceBatch } from './types';
import { INITIAL_USERS, STORAGE_KEYS } from './constants';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import XMLUpload from './components/XMLUpload';
import BlindCheck from './components/BlindCheck';
import SupervisorCheck from './components/SupervisorCheck';
import AdminPanel from './components/AdminPanel';
import ReportModal from './components/ReportModal';
import { LogIn, PackageCheck, Eye } from 'lucide-react';

const App: React.FC = () => {
  // Auth State
  const [user, setUser] = useState<User | null>(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.CURRENT_USER);
    return saved ? JSON.parse(saved) : null;
  });
  const [loginForm, setLoginForm] = useState({ username: '', password: '' });
  const [loginError, setLoginError] = useState('');

  // App State
  const [activeTab, setActiveTab] = useState('dashboard');
  const [users, setUsers] = useState<User[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.USERS);
    return saved ? JSON.parse(saved) : INITIAL_USERS;
  });
  const [batches, setBatches] = useState<ConferenceBatch[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.BATCHES);
    return saved ? JSON.parse(saved) : [];
  });

  // Lote em andamento (Pausável/Persistente)
  const [currentBatch, setCurrentBatch] = useState<ConferenceBatch | null>(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.ACTIVE_BATCH);
    return saved ? JSON.parse(saved) : null;
  });

  const [isSupervisorView, setIsSupervisorView] = useState(false);
  const [viewingReport, setViewingReport] = useState<ConferenceBatch | null>(null);

  // Sync with LocalStorage
  useEffect(() => localStorage.setItem(STORAGE_KEYS.USERS, JSON.stringify(users)), [users]);
  useEffect(() => localStorage.setItem(STORAGE_KEYS.BATCHES, JSON.stringify(batches)), [batches]);

  // Persistência Crítica: Lote Ativo
  useEffect(() => {
    if (currentBatch) {
      localStorage.setItem(STORAGE_KEYS.ACTIVE_BATCH, JSON.stringify(currentBatch));
    } else {
      localStorage.removeItem(STORAGE_KEYS.ACTIVE_BATCH);
    }
  }, [currentBatch]);

  useEffect(() => {
    if (user) localStorage.setItem(STORAGE_KEYS.CURRENT_USER, JSON.stringify(user));
    else localStorage.removeItem(STORAGE_KEYS.CURRENT_USER);
  }, [user]);

  // Se houver um lote ativo ao carregar, redireciona para a aba de conferência
  useEffect(() => {
    if (currentBatch && user && activeTab === 'dashboard') {
      setActiveTab('checking');
    }
  }, [user]);

  // Auth Handlers
  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const found = users.find(u => u.username === loginForm.username && u.password === loginForm.password);
    if (found) {
      setUser(found);
      if (currentBatch) {
        setActiveTab('checking');
      } else if (found.role === UserRole.CONFERENTE) {
        setActiveTab('upload');
      } else {
        setActiveTab('dashboard');
      }
    } else {
      setLoginError('Credenciais inválidas. Verifique usuário e senha.');
    }
  };

  const handleLogout = () => {
    setUser(null);
    setIsSupervisorView(false);
    setLoginForm({ username: '', password: '' });
    setLoginError('');
  };

  const handleUpdateUser = (updatedUser: User) => {
    setUsers(users.map(u => u.id === updatedUser.id ? updatedUser : u));
    if (user && user.id === updatedUser.id) {
      setUser(updatedUser);
    }
  };

  // Conference Handlers
  const startConference = (batch: ConferenceBatch) => {
    setCurrentBatch(batch);
    setActiveTab('checking');
  };

  const finalizeConference = () => {
    if (!currentBatch) return;

    const hasDivergence = currentBatch.products.some(p => p.quantityExpected !== p.quantityChecked);

    if (hasDivergence) {
      setIsSupervisorView(true);
    } else {
      const finalBatch = { ...currentBatch, status: 'APPROVED' as const, endTime: new Date().toISOString() };
      setBatches([finalBatch, ...batches]);
      setCurrentBatch(null); // Limpa o lote ativo
      setActiveTab('history');
      setViewingReport(finalBatch);
    }
  };

  const handleSupervisorApprove = (supervisor: User, justification: string) => {
    if (!currentBatch) return;
    const finalBatch = { 
      ...currentBatch, 
      status: 'APPROVED' as const, 
      endTime: new Date().toISOString(),
      supervisorId: supervisor.id,
      supervisorName: supervisor.name,
      justification
    };
    setBatches([finalBatch, ...batches]);
    setCurrentBatch(null); // Limpa o lote ativo
    setIsSupervisorView(false);
    setActiveTab('history');
    setViewingReport(finalBatch);
  };

  const cancelActiveConference = () => {
    if (window.confirm("Deseja REALMENTE DESCARTAR este lote? Todo o progresso de contagem será perdido permanentemente.")) {
      setCurrentBatch(null);
      setActiveTab('upload');
    }
  };

  const pauseActiveConference = () => {
    setActiveTab('dashboard');
  };

  // Login Screen
  if (!user) {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center p-4">
        <div className="max-w-md w-full bg-white rounded-3xl shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-300">
          <div className="p-10 text-center bg-slate-50 border-b border-slate-100">
            <div className="bg-blue-600 w-16 h-16 rounded-2xl flex items-center justify-center mx-auto mb-6 shadow-lg shadow-blue-500/30">
              <PackageCheck className="text-white" size={40} />
            </div>
            <h1 className="text-3xl font-black text-slate-800 tracking-tight">CheckMaster</h1>
            <p className="text-slate-500 mt-2 font-medium">Logística & Conferência Cega</p>
          </div>

          <div className="p-10">
            <form onSubmit={handleLogin} className="space-y-6">
              <div>
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1.5 ml-1">Usuário / Login</label>
                <input 
                  type="text" 
                  className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-5 py-4 focus:outline-none focus:ring-2 focus:ring-blue-500 transition-all font-medium"
                  value={loginForm.username}
                  onChange={e => setLoginForm({...loginForm, username: e.target.value})}
                  placeholder="Seu login"
                  required
                />
              </div>
              <div>
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1.5 ml-1">Senha</label>
                <input 
                  type="password" 
                  className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-5 py-4 focus:outline-none focus:ring-2 focus:ring-blue-500 transition-all"
                  value={loginForm.password}
                  onChange={e => setLoginForm({...loginForm, password: e.target.value})}
                  placeholder="••••••••"
                  required
                />
              </div>

              {loginError && <p className="text-red-500 text-xs font-bold text-center bg-red-50 py-3 rounded-xl animate-shake">{loginError}</p>}

              <button 
                type="submit"
                className="w-full bg-blue-600 hover:bg-blue-700 text-white font-black py-5 rounded-2xl shadow-xl shadow-blue-500/30 transition-all flex items-center justify-center gap-2 group text-sm uppercase tracking-widest"
              >
                Acessar Sistema
                <LogIn size={20} className="group-hover:translate-x-1 transition-transform" />
              </button>
            </form>
            <div className="mt-8 text-center">
              <p className="text-slate-300 text-[9px] font-black uppercase tracking-widest">Enterprise Logistics Solution v1.0.7</p>
            </div>
          </div>
        </div>
      </div>
    );
  }

  // Active UI logic
  let content;
  if (isSupervisorView && currentBatch) {
    content = (
      <SupervisorCheck 
        batch={currentBatch} 
        users={users}
        onApprove={handleSupervisorApprove}
        onReject={() => {
          setIsSupervisorView(false);
          setActiveTab('checking');
        }}
      />
    );
  } else if (currentBatch && activeTab === 'checking') {
    content = (
      <BlindCheck 
        batch={currentBatch} 
        onUpdateBatch={setCurrentBatch} 
        onFinish={finalizeConference}
        onCancel={cancelActiveConference}
        onPause={pauseActiveConference}
      />
    );
  } else {
    switch (activeTab) {
      case 'dashboard': 
        if (user.role === UserRole.CONFERENTE && !currentBatch) {
          content = <XMLUpload currentUser={user} onStartConference={startConference} />;
          break;
        }
        content = <Dashboard batches={batches} />; 
        break;
      case 'upload': 
        if (currentBatch) {
          content = (
            <div className="max-w-xl mx-auto mt-10 text-center space-y-6 bg-white p-10 rounded-3xl shadow-sm border border-slate-100">
              <div className="bg-orange-100 w-20 h-20 rounded-full flex items-center justify-center mx-auto">
                <PackageCheck className="text-orange-600" size={40} />
              </div>
              <div>
                <h3 className="text-2xl font-black text-slate-800 uppercase tracking-tight">Conferência em Aberto</h3>
                <p className="text-slate-500 mt-2">Você já possui um lote iniciado que não foi finalizado. O que deseja fazer?</p>
              </div>
              <div className="flex flex-col gap-3">
                <button 
                  onClick={() => setActiveTab('checking')}
                  className="bg-blue-600 hover:bg-blue-700 text-white py-4 rounded-xl font-bold shadow-lg shadow-blue-500/20 transition-all flex items-center justify-center gap-2"
                >
                  Continuar Conferência Atual
                </button>
                <button 
                  onClick={cancelActiveConference}
                  className="text-red-600 hover:bg-red-50 py-4 rounded-xl font-bold transition-all"
                >
                  Descartar Lote e Iniciar Novo XML
                </button>
              </div>
            </div>
          );
        } else {
          content = <XMLUpload currentUser={user} onStartConference={startConference} />;
        }
        break;
      case 'history': 
        content = (
          <div className="space-y-6 animate-in fade-in duration-500">
            <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
              <table className="w-full text-left">
                <thead className="bg-slate-50 text-slate-400 text-[10px] font-black uppercase tracking-widest">
                  <tr>
                    <th className="px-6 py-4">Data/Hora</th>
                    <th className="px-6 py-4">Lote ID</th>
                    <th className="px-6 py-4">Conferente</th>
                    <th className="px-6 py-4">Status</th>
                    <th className="px-6 py-4 text-right">Ações</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50">
                  {batches.map(b => (
                    <tr key={b.id} className="hover:bg-slate-50/50 group transition-colors">
                      <td className="px-6 py-4 text-xs font-bold text-slate-500">
                        {new Date(b.endTime || b.startTime).toLocaleString('pt-BR')}
                      </td>
                      <td className="px-6 py-4 text-sm font-mono font-black text-blue-600 uppercase tracking-tighter">#{b.id}</td>
                      <td className="px-6 py-4 text-sm font-bold text-slate-800">{b.conferenteName}</td>
                      <td className="px-6 py-4">
                        <span className={`px-3 py-1 rounded-lg text-[10px] font-black tracking-widest uppercase ${
                          b.status === 'APPROVED' ? 'bg-green-100 text-green-700' : 'bg-orange-100 text-orange-700'
                        }`}>
                          {b.status}
                        </span>
                      </td>
                      <td className="px-6 py-4 text-right">
                        <div className="flex justify-end gap-2">
                           <button 
                            onClick={() => setViewingReport(b)}
                            className="bg-slate-100 text-slate-600 hover:bg-blue-600 hover:text-white px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all flex items-center gap-2"
                          >
                            <Eye size={14} />
                            Relatório
                          </button>
                        </div>
                      </td>
                    </tr>
                  ))}
                  {batches.length === 0 && (
                    <tr>
                      <td colSpan={5} className="px-6 py-20 text-center text-slate-300 font-bold uppercase text-[10px] tracking-widest">Nenhum histórico disponível.</td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          </div>
        );
        break;
      case 'admin': 
        if (user.role === UserRole.CONFERENTE) {
          content = <XMLUpload currentUser={user} onStartConference={startConference} />;
          break;
        }
        content = (
          <AdminPanel 
            users={users} 
            currentUser={user}
            onAddUser={(u) => setUsers([...users, u])} 
            onDeleteUser={(id) => setUsers(users.filter(u => u.id !== id))}
            onUpdateUser={handleUpdateUser}
          />
        ); break;
      default: 
        content = user.role === UserRole.CONFERENTE ? 
          <XMLUpload currentUser={user} onStartConference={startConference} /> : 
          <Dashboard batches={batches} />;
    }
  }

  return (
    <Layout user={user} onLogout={handleLogout} activeTab={activeTab} setActiveTab={setActiveTab}>
      {content}
      {viewingReport && (
        <ReportModal 
          batch={viewingReport} 
          onClose={() => setViewingReport(null)} 
        />
      )}
    </Layout>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { 
  Scan, 
  Keyboard, 
  Search, 
  CheckCircle, 
  ArrowRight,
  AlertCircle,
  Package,
  Plus,
  Minus,
  Save,
  LogOut,
  Trash2
} from 'lucide-react';
import { ConferenceBatch, NFeProduct } from '../types';

interface BlindCheckProps {
  batch: ConferenceBatch;
  onUpdateBatch: (batch: ConferenceBatch) => void;
  onFinish: () => void;
  onCancel: () => void;
  onPause: () => void;
}

const BlindCheck: React.FC<BlindCheckProps> = ({ batch, onUpdateBatch, onFinish, onCancel, onPause }) => {
  const [searchInput, setSearchInput] = useState('');
  const [manualQty, setManualQty] = useState<number>(1);
  const [errorMsg, setErrorMsg] = useState('');
  const [lastScanned, setLastScanned] = useState<NFeProduct | null>(null);

  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    inputRef.current?.focus();
  }, []);

  const totalExpected = batch.products.reduce((acc, p) => acc + p.quantityExpected, 0);
  const totalChecked = batch.products.reduce((acc, p) => acc + p.quantityChecked, 0);
  const progress = Math.min(Math.round((totalChecked / totalExpected) * 100), 100);

  const handleScan = (e: React.FormEvent) => {
    e.preventDefault();
    if (!searchInput.trim()) return;

    const term = searchInput.trim().toUpperCase();
    const productIndex = batch.products.findIndex(p => 
      p.ean === term || p.code.toUpperCase() === term
    );

    if (productIndex === -1) {
      setErrorMsg(`Produto "${term}" não encontrado no lote.`);
      setTimeout(() => setErrorMsg(''), 3000);
    } else {
      const updatedProducts = [...batch.products];
      updatedProducts[productIndex].quantityChecked += manualQty;

      onUpdateBatch({ ...batch, products: updatedProducts });
      setLastScanned(updatedProducts[productIndex]);
      setSearchInput('');
      setManualQty(1);
    }
    inputRef.current?.focus();
  };

  const updateQuantity = (index: number, delta: number) => {
    const updatedProducts = [...batch.products];
    const newQty = updatedProducts[index].quantityChecked + delta;
    if (newQty >= 0) {
      updatedProducts[index].quantityChecked = newQty;
      onUpdateBatch({ ...batch, products: updatedProducts });
    }
  };

  return (
    <div className="max-w-6xl mx-auto flex flex-col h-full gap-6 pb-20">
      {/* Top Status Bar */}
      <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex items-center justify-between">
        <div className="flex items-center gap-6">
          <div className="bg-blue-50 p-4 rounded-xl">
            <Package className="text-blue-600" size={32} />
          </div>
          <div>
            <h3 className="text-xl font-bold text-slate-800">Conferência em Lote: {batch.notes.length} Notas</h3>
            <div className="flex items-center gap-2 text-slate-500 text-sm mt-1">
              <Save size={14} className="text-green-500" />
              <span>Salvamento Automático Ativo</span>
            </div>
          </div>
        </div>

        <div className="flex flex-col items-end gap-2 w-64">
          <div className="flex justify-between w-full text-sm font-semibold text-slate-600">
            <span>Progresso da Conferência</span>
            <span>{progress}%</span>
          </div>
          <div className="w-full bg-slate-100 h-3 rounded-full overflow-hidden">
            <div 
              className={`h-full transition-all duration-500 ${progress >= 100 ? 'bg-green-500' : 'bg-blue-500'}`}
              style={{ width: `${progress}%` }}
            ></div>
          </div>
        </div>
      </div>

      {/* Main Checking Area */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 flex-1 min-h-0">
        {/* Input Panel */}
        <div className="lg:col-span-1 flex flex-col gap-6">
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
            <h4 className="font-bold text-slate-700 mb-4 flex items-center gap-2">
              <Scan size={20} className="text-blue-500" />
              Entrada de Mercadoria
            </h4>

            <form onSubmit={handleScan} className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-slate-500 mb-1">EAN ou Código</label>
                <div className="relative">
                  <input
                    ref={inputRef}
                    type="text"
                    value={searchInput}
                    onChange={(e) => setSearchInput(e.target.value)}
                    className="w-full bg-slate-50 border border-slate-200 rounded-xl py-4 pl-12 pr-4 font-mono text-lg focus:outline-none focus:ring-2 focus:ring-blue-500 transition-all"
                    placeholder="Bipe o código..."
                    autoComplete="off"
                  />
                  <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={24} />
                </div>
              </div>

              <div className="flex gap-4">
                <div className="flex-1">
                  <label className="block text-sm font-medium text-slate-500 mb-1">Quantidade</label>
                  <input
                    type="number"
                    min="1"
                    value={manualQty}
                    onChange={(e) => setManualQty(Number(e.target.value))}
                    className="w-full bg-slate-50 border border-slate-200 rounded-xl py-3 px-4 font-bold text-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
                  />
                </div>
                <div className="flex items-end">
                  <button 
                    type="submit"
                    className="bg-blue-600 hover:bg-blue-700 text-white px-8 py-4 rounded-xl font-bold transition-all shadow-lg flex items-center gap-2"
                  >
                    Confirmar
                    <ArrowRight size={18} />
                  </button>
                </div>
              </div>
            </form>

            {errorMsg && (
              <div className="mt-4 p-4 bg-red-50 text-red-600 rounded-lg flex items-center gap-2 animate-bounce">
                <AlertCircle size={20} />
                <span className="font-medium">{errorMsg}</span>
              </div>
            )}
          </div>

          <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex flex-col gap-3">
            <h4 className="font-bold text-slate-700 text-sm">Controle do Lote</h4>
            <button 
              onClick={onPause}
              className="w-full bg-slate-100 hover:bg-slate-200 text-slate-700 font-bold py-3 rounded-xl transition-all flex items-center justify-center gap-2"
            >
              <Save size={18} />
              Pausar / Salvar
            </button>
            <button 
              onClick={onCancel}
              className="w-full bg-red-50 hover:bg-red-100 text-red-600 font-bold py-3 rounded-xl transition-all flex items-center justify-center gap-2"
            >
              <Trash2 size={18} />
              Descartar e Sair
            </button>
          </div>

          {lastScanned && (
            <div className="bg-green-50 p-6 rounded-2xl border border-green-100 animate-in fade-in slide-in-from-bottom-2">
              <h4 className="text-green-800 font-bold mb-2">Último Lido:</h4>
              <p className="text-green-700 font-medium">{lastScanned.description}</p>
              <div className="mt-2 flex justify-between items-end">
                <span className="text-xs text-green-600 font-mono">{lastScanned.ean}</span>
                <span className="text-2xl font-black text-green-800">+{manualQty}</span>
              </div>
            </div>
          )}
        </div>

        {/* List Panel */}
        <div className="lg:col-span-2 bg-white rounded-2xl shadow-sm border border-slate-100 flex flex-col min-h-0">
          <div className="p-4 border-b border-slate-100 bg-slate-50/50 flex justify-between items-center">
            <h4 className="font-bold text-slate-700 uppercase tracking-wider text-xs">Itens Conferidos</h4>
            <span className="text-xs font-semibold text-slate-500">{batch.products.filter(p => p.quantityChecked > 0).length} Itens Diferentes</span>
          </div>
          <div className="flex-1 overflow-y-auto">
            <table className="w-full text-left">
              <thead className="sticky top-0 bg-white shadow-sm">
                <tr className="border-b border-slate-100 text-slate-400 text-xs uppercase font-bold">
                  <th className="px-6 py-4">Produto</th>
                  <th className="px-6 py-4 text-center">EAN</th>
                  <th className="px-6 py-4 text-right">Contagem</th>
                  <th className="px-6 py-4 text-center">Ações</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {batch.products
                  .filter(p => p.quantityChecked > 0)
                  .map((p, idx) => {
                    const productIdx = batch.products.findIndex(bp => bp.id === p.id);
                    return (
                      <tr key={p.id} className="hover:bg-slate-50/50 transition-colors">
                        <td className="px-6 py-4">
                          <p className="font-bold text-slate-800 text-sm line-clamp-1">{p.description}</p>
                          <p className="text-xs text-slate-500">Cód: {p.code}</p>
                        </td>
                        <td className="px-6 py-4 text-center font-mono text-xs text-slate-500">{p.ean}</td>
                        <td className="px-6 py-4 text-right">
                          <span className="inline-block px-3 py-1 bg-slate-100 rounded-full font-bold text-slate-800 min-w-[3rem] text-center">
                            {p.quantityChecked}
                          </span>
                        </td>
                        <td className="px-6 py-4 text-center">
                          <div className="flex justify-center gap-2">
                            <button 
                              onClick={() => updateQuantity(productIdx, -1)}
                              className="p-1.5 hover:bg-red-100 hover:text-red-600 text-slate-400 rounded-lg"
                            >
                              <Minus size={16} />
                            </button>
                            <button 
                              onClick={() => updateQuantity(productIdx, 1)}
                              className="p-1.5 hover:bg-blue-100 hover:text-blue-600 text-slate-400 rounded-lg"
                            >
                              <Plus size={16} />
                            </button>
                          </div>
                        </td>
                      </tr>
                    );
                  })}
                {batch.products.every(p => p.quantityChecked === 0) && (
                  <tr>
                    <td colSpan={4} className="px-6 py-12 text-center text-slate-400">
                      <div className="flex flex-col items-center gap-2">
                        <Keyboard size={48} className="opacity-20" />
                        <p>Nenhum produto conferido ainda.</p>
                        <p className="text-xs">Bipe um código para começar.</p>
                      </div>
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
          <div className="p-4 bg-slate-50 border-t border-slate-100 flex justify-end">
            <button 
              onClick={onFinish}
              className="bg-slate-900 hover:bg-black text-white px-10 py-3 rounded-xl font-bold transition-all shadow-xl flex items-center gap-2"
            >
              Finalizar Conferência
              <CheckCircle size={20} />
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default BlindCheck;

import React, { useState, useEffect } from 'react';
import { User, UserRole, ConferenceBatch } from './types';
import { INITIAL_USERS, STORAGE_KEYS } from './constants';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import XMLUpload from './components/XMLUpload';
import BlindCheck from './components/BlindCheck';
import SupervisorCheck from './components/SupervisorCheck';
import AdminPanel from './components/AdminPanel';
import ReportModal from './components/ReportModal';
import { LogIn, PackageCheck, Eye } from 'lucide-react';

const App: React.FC = () => {
  // Auth State
  const [user, setUser] = useState<User | null>(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.CURRENT_USER);
    return saved ? JSON.parse(saved) : null;
  });
  const [loginForm, setLoginForm] = useState({ username: '', password: '' });
  const [loginError, setLoginError] = useState('');

  // App State
  const [activeTab, setActiveTab] = useState('dashboard');
  const [users, setUsers] = useState<User[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.USERS);
    return saved ? JSON.parse(saved) : INITIAL_USERS;
  });
  const [batches, setBatches] = useState<ConferenceBatch[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.BATCHES);
    return saved ? JSON.parse(saved) : [];
  });

  // Lote em andamento (Pausável/Persistente)
  const [currentBatch, setCurrentBatch] = useState<ConferenceBatch | null>(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.ACTIVE_BATCH);
    return saved ? JSON.parse(saved) : null;
  });

  const [isSupervisorView, setIsSupervisorView] = useState(false);
  const [viewingReport, setViewingReport] = useState<ConferenceBatch | null>(null);

  // Sync with LocalStorage
  useEffect(() => localStorage.setItem(STORAGE_KEYS.USERS, JSON.stringify(users)), [users]);
  useEffect(() => localStorage.setItem(STORAGE_KEYS.BATCHES, JSON.stringify(batches)), [batches]);

  // Persistência Crítica: Lote Ativo
  useEffect(() => {
    if (currentBatch) {
      localStorage.setItem(STORAGE_KEYS.ACTIVE_BATCH, JSON.stringify(currentBatch));
    } else {
      localStorage.removeItem(STORAGE_KEYS.ACTIVE_BATCH);
    }
  }, [currentBatch]);

  useEffect(() => {
    if (user) localStorage.setItem(STORAGE_KEYS.CURRENT_USER, JSON.stringify(user));
    else localStorage.removeItem(STORAGE_KEYS.CURRENT_USER);
  }, [user]);

  // Se houver um lote ativo ao carregar, redireciona para a aba de conferência
  useEffect(() => {
    if (currentBatch && user && activeTab === 'dashboard') {
      setActiveTab('checking');
    }
  }, [user]);

  // Auth Handlers
  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const found = users.find(u => u.username === loginForm.username && u.password === loginForm.password);
    if (found) {
      setUser(found);
      if (currentBatch) {
        setActiveTab('checking');
      } else if (found.role === UserRole.CONFERENTE) {
        setActiveTab('upload');
      } else {
        setActiveTab('dashboard');
      }
    } else {
      setLoginError('Credenciais inválidas. Verifique usuário e senha.');
    }
  };

  const handleLogout = () => {
    setUser(null);
    setIsSupervisorView(false);
    setLoginForm({ username: '', password: '' });
    setLoginError('');
  };

  const handleUpdateUser = (updatedUser: User) => {
    setUsers(users.map(u => u.id === updatedUser.id ? updatedUser : u));
    if (user && user.id === updatedUser.id) {
      setUser(updatedUser);
    }
  };

  // Conference Handlers
  const startConference = (batch: ConferenceBatch) => {
    setCurrentBatch(batch);
    setIsSupervisorView(false);
    setActiveTab('checking');
  };

  const finalizeConference = () => {
    if (!currentBatch) return;

    const hasDivergence = currentBatch.products.some(p => p.quantityExpected !== p.quantityChecked);

    if (hasDivergence) {
      setIsSupervisorView(true);
    } else {
      const finalBatch = { ...currentBatch, status: 'APPROVED' as const, endTime: new Date().toISOString() };
      setBatches([finalBatch, ...batches]);
      setCurrentBatch(null); // Limpa o lote ativo
      setActiveTab('history');
      setViewingReport(finalBatch);
    }
  };

  const handleSupervisorApprove = (supervisor: User, justification: string) => {
    if (!currentBatch) return;
    const finalBatch = { 
      ...currentBatch, 
      status: 'APPROVED' as const, 
      endTime: new Date().toISOString(),
      supervisorId: supervisor.id,
      supervisorName: supervisor.name,
      justification
    };
    setBatches([finalBatch, ...batches]);
    setCurrentBatch(null); // Limpa o lote ativo
    setIsSupervisorView(false);
    setActiveTab('history');
    setViewingReport(finalBatch);
  };

  const cancelActiveConference = () => {
    if (window.confirm("ATENÇÃO: Deseja realmente DESCARTAR este lote? \n\nTodo o progresso de contagem física será perdido permanentemente e os arquivos XML precisarão ser importados novamente.")) {
      setCurrentBatch(null);
      setIsSupervisorView(false);
      setActiveTab('upload');
    }
  };

  const pauseActiveConference = () => {
    setActiveTab('dashboard');
  };

  // Login Screen
  if (!user) {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center p-4">
        <div className="max-w-md w-full bg-white rounded-3xl shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-300">
          <div className="p-10 text-center bg-slate-50 border-b border-slate-100">
            <div className="bg-blue-600 w-16 h-16 rounded-2xl flex items-center justify-center mx-auto mb-6 shadow-lg shadow-blue-500/30">
              <PackageCheck className="text-white" size={40} />
            </div>
            <h1 className="text-3xl font-black text-slate-800 tracking-tight">CheckMaster</h1>
            <p className="text-slate-500 mt-2 font-medium">Logística & Conferência Cega</p>
          </div>

          <div className="p-10">
            <form onSubmit={handleLogin} className="space-y-6">
              <div>
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1.5 ml-1">Usuário / Login</label>
                <input 
                  type="text" 
                  className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-5 py-4 focus:outline-none focus:ring-2 focus:ring-blue-500 transition-all font-medium"
                  value={loginForm.username}
                  onChange={e => setLoginForm({...loginForm, username: e.target.value})}
                  placeholder="Seu login"
                  required
                />
              </div>
              <div>
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1.5 ml-1">Senha</label>
                <input 
                  type="password" 
                  className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-5 py-4 focus:outline-none focus:ring-2 focus:ring-blue-500 transition-all"
                  value={loginForm.password}
                  onChange={e => setLoginForm({...loginForm, password: e.target.value})}
                  placeholder="••••••••"
                  required
                />
              </div>

              {loginError && <p className="text-red-500 text-xs font-bold text-center bg-red-50 py-3 rounded-xl animate-shake">{loginError}</p>}

              <button 
                type="submit"
                className="w-full bg-blue-600 hover:bg-blue-700 text-white font-black py-5 rounded-2xl shadow-xl shadow-blue-500/30 transition-all flex items-center justify-center gap-2 group text-sm uppercase tracking-widest"
              >
                Acessar Sistema
                <LogIn size={20} className="group-hover:translate-x-1 transition-transform" />
              </button>
            </form>
            <div className="mt-8 text-center">
