  }, [user]);

  // Handlers de Lote com Atualização Funcional para evitar bugs de estado
  const startNewConference = (batch: ConferenceBatch) => {
    if (currentBatch) {
      // Se já houver um lote ativo, move para a fila de pausa usando prev
      setPausedBatches(prev => [currentBatch, ...prev]);
    }
    setCurrentBatch(batch);
    setActiveTab('checking');
  };

  const handlePauseActive = () => {
    if (currentBatch) {
      setPausedBatches(prev => [currentBatch, ...prev]);
      setCurrentBatch(null);
      setActiveTab('upload');
    }
  };

  const handleResumeBatch = (batchToResume: ConferenceBatch) => {
    if (currentBatch) {
      if (window.confirm("Você possui uma conferência ativa agora. Deseja pausá-la para retomar esta?")) {
        const batchToPause = { ...currentBatch };
        setPausedBatches(prev => [batchToPause, ...prev.filter(b => b.id !== batchToResume.id)]);
        setCurrentBatch(batchToResume);
        setActiveTab('checking');
      }
    } else {
      setPausedBatches(prev => prev.filter(b => b.id !== batchToResume.id));
      setCurrentBatch(batchToResume);
      setActiveTab('checking');
    }
  };

  const deletePausedBatch = (id: string) => {
    if (window.confirm("Deseja realmente excluir permanentemente este lote pausado?")) {
      setPausedBatches(prev => prev.filter(b => b.id !== id));
    }
  };

  // Auth Handlers
  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const found = users.find(u => u.username === loginForm.username && u.password === loginForm.password);
    if (found) {
      setUser(found);
      if (currentBatch) setActiveTab('checking');
      else if (found.role === UserRole.CONFERENTE) setActiveTab('upload');
      else setActiveTab('dashboard');
    } else {
      setLoginError('Credenciais inválidas.');
    }
  };

  const handleLogout = () => {
    setUser(null);
    setIsSupervisorView(false);
  };

  const finalizeConference = () => {
    if (!currentBatch) return;
    const hasDivergence = currentBatch.products.some(p => p.quantityExpected !== p.quantityChecked);
    if (hasDivergence) setIsSupervisorView(true);
    else {
      const finalBatch = { ...currentBatch, status: 'APPROVED' as const, endTime: new Date().toISOString() };
      setBatches(prev => [finalBatch, ...prev]);
      setCurrentBatch(null);
      setActiveTab('history');
      setViewingReport(finalBatch);
    }
  };

  const handleSupervisorApprove = (supervisor: User, justification: string) => {
    if (!currentBatch) return;
    const finalBatch = { 
      ...currentBatch, 
      status: 'APPROVED' as const, 
      endTime: new Date().toISOString(),
      supervisorId: supervisor.id,
      supervisorName: supervisor.name,
      justification
    };
    setBatches(prev => [finalBatch, ...prev]);
    setCurrentBatch(null);
    setIsSupervisorView(false);
    setActiveTab('history');
    setViewingReport(finalBatch);
  };

  // UI Logic
  let content;
  if (isSupervisorView && currentBatch) {
    content = <SupervisorCheck batch={currentBatch} users={users} onApprove={handleSupervisorApprove} onReject={() => { setIsSupervisorView(false); setActiveTab('checking'); }} />;
  } else if (currentBatch && activeTab === 'checking') {
    content = <BlindCheck batch={currentBatch} onUpdateBatch={setCurrentBatch} onFinish={finalizeConference} onCancel={() => { setCurrentBatch(null); setActiveTab('upload'); }} onPause={handlePauseActive} />;
  } else {
    switch (activeTab) {
      case 'dashboard': content = <Dashboard batches={batches} />; break;
      case 'upload': content = <XMLUpload currentUser={user!} onStartConference={startNewConference} />; break;
      case 'paused': content = <PausedBatches pausedBatches={pausedBatches} onResume={handleResumeBatch} onDelete={deletePausedBatch} />; break;
      case 'history': content = (
        <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
          <table className="w-full text-left">
            <thead className="bg-slate-50 text-slate-400 text-[10px] font-black uppercase tracking-widest">
              <tr><th className="px-6 py-4">Data/Hora</th><th className="px-6 py-4">Lote ID</th><th className="px-6 py-4">Conferente</th><th className="px-6 py-4">Status</th><th className="px-6 py-4 text-right">Ações</th></tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {batches.map(b => (
                <tr key={b.id} className="hover:bg-slate-50/50 group transition-colors">
                  <td className="px-6 py-4 text-xs font-bold text-slate-500">{new Date(b.endTime || b.startTime).toLocaleString('pt-BR')}</td>
                  <td className="px-6 py-4 text-sm font-mono font-black text-blue-600 uppercase tracking-tighter">#{b.id}</td>
                  <td className="px-6 py-4 text-sm font-bold text-slate-800">{b.conferenteName}</td>
                  <td className="px-6 py-4">
                    <span className={`px-3 py-1 rounded-lg text-[10px] font-black tracking-widest uppercase ${b.status === 'APPROVED' ? 'bg-green-100 text-green-700' : 'bg-orange-100 text-orange-700'}`}>{b.status}</span>
                  </td>
                  <td className="px-6 py-4 text-right">
                    <button onClick={() => setViewingReport(b)} className="bg-slate-100 text-slate-600 hover:bg-blue-600 hover:text-white px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all flex items-center gap-2 ml-auto"><Eye size={14} /> Relatório</button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      ); break;
      case 'admin': content = <AdminPanel users={users} currentUser={user!} onAddUser={(u) => setUsers(prev => [...prev, u])} onDeleteUser={(id) => setUsers(prev => prev.filter(u => u.id !== id))} onUpdateUser={(u) => setUsers(prev => prev.map(us => us.id === u.id ? u : us))} />; break;
      default: content = user?.role === UserRole.CONFERENTE ? <XMLUpload currentUser={user!} onStartConference={startNewConference} /> : <Dashboard batches={batches} />;
    }
  }

  if (!user) {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center p-4">
        <div className="max-w-md w-full bg-white rounded-3xl shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-300">
          <div className="p-10 text-center bg-slate-50 border-b border-slate-100">
            <div className="bg-blue-600 w-16 h-16 rounded-2xl flex items-center justify-center mx-auto mb-6 shadow-lg shadow-blue-500/30">
              <PackageCheck className="text-white" size={40} />
            </div>
            <h1 className="text-3xl font-black text-slate-800 tracking-tight">CheckMaster</h1>
            <p className="text-slate-500 mt-2 font-medium">Logística & Conferência Cega</p>
          </div>
          <div className="p-10">
            <form onSubmit={handleLogin} className="space-y-6">
              <div><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1.5 ml-1">Usuário / Login</label><input type="text" className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-5 py-4 focus:ring-2 focus:ring-blue-500 outline-none" value={loginForm.username} onChange={e => setLoginForm({...loginForm, username: e.target.value})} placeholder="Seu login" required /></div>
              <div><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1.5 ml-1">Senha</label><input type="password" className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-5 py-4 focus:ring-2 focus:ring-blue-500 outline-none" value={loginForm.password} onChange={e => setLoginForm({...loginForm, password: e.target.value})} placeholder="••••••••" required /></div>
              {loginError && <p className="text-red-500 text-xs font-bold text-center bg-red-50 py-3 rounded-xl">{loginError}</p>}
              <button type="submit" className="w-full bg-blue-600 hover:bg-blue-700 text-white font-black py-5 rounded-2xl shadow-xl shadow-blue-500/30 transition-all flex items-center justify-center gap-2 group text-sm uppercase tracking-widest">Acessar Sistema</button>
            </form>
          </div>
        </div>
      </div>
    );
  }

  return (
    <Layout user={user} onLogout={handleLogout} activeTab={activeTab} setActiveTab={setActiveTab} pausedCount={pausedBatches.length}>
      {content}
      {viewingReport && <ReportModal batch={viewingReport} onClose={() => setViewingReport(null)} />}
    </Layout>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { ConferenceBatch } from '../types';
import { 
  Play, 
  Trash2, 
  Clock, 
  Package, 
  FileText, 
  Search, 
  FilterX, 
  AlertTriangle,
  X
} from 'lucide-react';

interface PausedBatchesProps {
  pausedBatches: ConferenceBatch[];
  onResume: (batch: ConferenceBatch) => void;
  onDelete: (id: string) => void;
}

const PausedBatches: React.FC<PausedBatchesProps> = ({ pausedBatches, onResume, onDelete }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [batchToDelete, setBatchToDelete] = useState<string | null>(null);

  const filteredPaused = useMemo(() => {
    if (!searchTerm.trim()) return pausedBatches;

    const term = searchTerm.trim().toLowerCase();
    return pausedBatches.filter(batch => {
      const matchesNF = batch.notes.some(note => note.number.toLowerCase().includes(term));
      const matchesBatchId = batch.id.toLowerCase().includes(term);
      return matchesNF || matchesBatchId;
    });
  }, [pausedBatches, searchTerm]);

  const confirmDelete = () => {
    if (batchToDelete) {
      onDelete(batchToDelete);
      setBatchToDelete(null);
    }
  };

  if (pausedBatches.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center py-20 bg-white rounded-[32px] border-2 border-dashed border-slate-100">
        <Clock size={64} className="text-slate-200 mb-4" />
        <h3 className="text-xl font-bold text-slate-400 uppercase tracking-widest">Fila de Espera Vazia</h3>
        <p className="text-slate-300 text-sm">Nenhuma conferência pausada no momento.</p>
      </div>
    );
  }

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      {/* Barra de Pesquisa */}
      <div className="relative">
        <div className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-400">
          <Search size={20} />
        </div>
        <input 
          type="text"
          placeholder="Pesquisar por número da Nota Fiscal (NF) ou ID do lote..."
          className="w-full bg-white border border-slate-200 rounded-2xl py-5 pl-14 pr-14 focus:ring-2 focus:ring-blue-500 focus:outline-none shadow-sm transition-all font-medium text-slate-700"
          value={searchTerm}
          onChange={e => setSearchTerm(e.target.value)}
        />
        {searchTerm && (
          <button 
            onClick={() => setSearchTerm('')}
            className="absolute right-5 top-1/2 -translate-y-1/2 text-slate-300 hover:text-slate-500 transition-colors"
          >
            <FilterX size={20} />
          </button>
        )}
      </div>

      {filteredPaused.length > 0 ? (
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          {filteredPaused.map((batch) => {
            const totalChecked = batch.products.reduce((acc, p) => acc + p.quantityChecked, 0);
            const totalExpected = batch.products.reduce((acc, p) => acc + p.quantityExpected, 0);
            const progress = Math.min(Math.round((totalChecked / totalExpected) * 100), 100);

            return (
              <div key={batch.id} className="bg-white rounded-3xl p-6 shadow-sm border border-slate-100 hover:shadow-md transition-all group border-l-4 border-l-orange-400">
                <div className="flex justify-between items-start mb-6">
                  <div className="flex items-center gap-3">
                    <div className="bg-orange-50 p-3 rounded-2xl">
                      <Clock className="text-orange-500" size={24} />
                    </div>
                    <div>
                      <h4 className="font-black text-slate-800 uppercase tracking-tight">Lote #{batch.id}</h4>
                      <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">Pausado em {new Date(batch.startTime).toLocaleString('pt-BR')}</p>
                    </div>
                  </div>
                  <button 
                    onClick={() => setBatchToDelete(batch.id)}
                    className="text-slate-300 hover:text-red-500 p-2.5 bg-slate-50 hover:bg-red-50 rounded-xl transition-all"
                    title="Excluir Lote"
                  >
                    <Trash2 size={20} />
                  </button>
                </div>

                <div className="grid grid-cols-1 gap-4 mb-6">
                  <div className="bg-blue-50/50 p-3 rounded-xl border border-blue-100">
                    <div className="flex items-center gap-2 text-blue-400 text-[10px] font-black uppercase tracking-widest mb-1">
                      <FileText size={12} /> Notas Fiscais (NF)
                    </div>
                    <p className="text-xs font-black text-blue-700 truncate">
                      {batch.notes.map(n => n.number).join(', ')}
                    </p>
                  </div>
                </div>

                <div className="grid grid-cols-2 gap-4 mb-6">
                  <div className="bg-slate-50 p-3 rounded-xl border border-slate-100">
                    <div className="flex items-center gap-2 text-slate-400 text-[10px] font-black uppercase tracking-widest mb-1">
                      <Package size={12} /> SKUs
                    </div>
                    <p className="text-xs font-bold text-slate-700">{batch.products.length} Itens</p>
                  </div>
                  <div className="bg-slate-50 p-3 rounded-xl border border-slate-100">
                    <div className="flex items-center gap-2 text-slate-400 text-[10px] font-black uppercase tracking-widest mb-1">
                      <Clock size={12} /> Responsável
                    </div>
                    <p className="text-xs font-bold text-slate-700 truncate">{batch.conferenteName}</p>
                  </div>
                </div>

                <div className="space-y-2 mb-6">
                  <div className="flex justify-between text-[10px] font-black text-slate-400 uppercase tracking-widest">
                    <span>Progresso Salvo</span>
                    <span>{progress}%</span>
                  </div>
                  <div className="w-full bg-slate-100 h-2 rounded-full overflow-hidden">
                    <div 
                      className="bg-orange-400 h-full transition-all duration-500" 
                      style={{ width: `${progress}%` }}
                    ></div>
                  </div>
                </div>

                <button 
                  onClick={() => onResume(batch)}
                  className="w-full bg-slate-900 hover:bg-black text-white py-4 rounded-2xl font-black uppercase tracking-widest text-[10px] flex items-center justify-center gap-2 transition-all shadow-xl shadow-slate-900/10 group-hover:scale-[1.01]"
                >
                  Retomar Conferência
                  <Play size={14} fill="currentColor" />
                </button>
              </div>
            );
          })}
        </div>
      ) : (
        <div className="flex flex-col items-center justify-center py-20 bg-white rounded-[32px] border-2 border-dashed border-slate-100">
          <Search size={48} className="text-slate-200 mb-4" />
          <h3 className="text-xl font-bold text-slate-400 uppercase tracking-widest">Nenhuma NF encontrada</h3>
          <p className="text-slate-300 text-sm">Não encontramos conferências pausadas com o termo "{searchTerm}".</p>
        </div>
      )}

      {/* Modal de Confirmação de Exclusão */}
      {batchToDelete && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/70 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-md rounded-[32px] shadow-2xl overflow-hidden animate-in zoom-in duration-200 border border-slate-100">
            <div className="p-8 text-center">
              <div className="bg-red-100 w-20 h-20 rounded-full flex items-center justify-center mx-auto mb-6 text-red-600">
                <AlertTriangle size={40} />
              </div>
              <h3 className="text-2xl font-black text-slate-800 uppercase tracking-tight mb-3">Excluir Lote Pausado?</h3>
              <p className="text-slate-500 font-medium leading-relaxed">
                Esta ação removerá permanentemente este lote da fila de espera. Deseja continuar?
              </p>

              <div className="mt-10 flex flex-col gap-3">
                <button 
                  onClick={confirmDelete}
                  className="w-full bg-red-600 hover:bg-red-700 text-white py-5 rounded-2xl font-black uppercase tracking-widest text-xs transition-all shadow-xl shadow-red-500/20 flex items-center justify-center gap-2"
                >
                  SIM, Excluir Lote
                </button>
                <button 
                  onClick={() => setBatchToDelete(null)}
                  className="w-full bg-white border-2 border-slate-100 hover:bg-slate-50 text-slate-600 py-5 rounded-2xl font-black uppercase tracking-widest text-xs transition-all flex items-center justify-center gap-2"
                >
                  NÃO, Manter na Fila
                </button>
              </div>
            </div>
            <div className="bg-slate-50 p-4 text-center border-t border-slate-100">
               <button 
                onClick={() => setBatchToDelete(null)}
                className="text-slate-400 hover:text-slate-600 text-[10px] font-bold uppercase tracking-widest flex items-center justify-center gap-1 mx-auto"
              >
                <X size={14} /> Fechar
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default PausedBatches;

import React, { useState, useEffect } from 'react';
import { User, UserRole, ConferenceBatch } from './types';
import { INITIAL_USERS, STORAGE_KEYS } from './constants';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import XMLUpload from './components/XMLUpload';
import BlindCheck from './components/BlindCheck';
import SupervisorCheck from './components/SupervisorCheck';
import AdminPanel from './components/AdminPanel';
import ReportModal from './components/ReportModal';
import PausedBatches from './components/PausedBatches';
import { LogIn, PackageCheck, Eye } from 'lucide-react';

const App: React.FC = () => {
  // Auth State
  const [user, setUser] = useState<User | null>(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.CURRENT_USER);
    return saved ? JSON.parse(saved) : null;
  });
  const [loginForm, setLoginForm] = useState({ username: '', password: '' });
  const [loginError, setLoginError] = useState('');

  // App State
  const [activeTab, setActiveTab] = useState('dashboard');
  const [users, setUsers] = useState<User[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.USERS);
    return saved ? JSON.parse(saved) : INITIAL_USERS;
  });
  const [batches, setBatches] = useState<ConferenceBatch[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.BATCHES);
    return saved ? JSON.parse(saved) : [];
  });

  // Lote Ativo
  const [currentBatch, setCurrentBatch] = useState<ConferenceBatch | null>(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.ACTIVE_BATCH);
    return saved ? JSON.parse(saved) : null;
  });

  // Fila de Lotes Pausados
  const [pausedBatches, setPausedBatches] = useState<ConferenceBatch[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.PAUSED_BATCHES);
    return saved ? JSON.parse(saved) : [];
  });

  const [isSupervisorView, setIsSupervisorView] = useState(false);
  const [viewingReport, setViewingReport] = useState<ConferenceBatch | null>(null);

  // Sync Storage
  useEffect(() => localStorage.setItem(STORAGE_KEYS.USERS, JSON.stringify(users)), [users]);
  useEffect(() => localStorage.setItem(STORAGE_KEYS.BATCHES, JSON.stringify(batches)), [batches]);
  useEffect(() => localStorage.setItem(STORAGE_KEYS.PAUSED_BATCHES, JSON.stringify(pausedBatches)), [pausedBatches]);

  useEffect(() => {
    if (currentBatch) {
      localStorage.setItem(STORAGE_KEYS.ACTIVE_BATCH, JSON.stringify(currentBatch));
    } else {
      localStorage.removeItem(STORAGE_KEYS.ACTIVE_BATCH);
    }
  }, [currentBatch]);

  useEffect(() => {
    if (user) localStorage.setItem(STORAGE_KEYS.CURRENT_USER, JSON.stringify(user));
    else localStorage.removeItem(STORAGE_KEYS.CURRENT_USER);
  }, [user]);

  // Redirecionamento Automático
  useEffect(() => {
    if (currentBatch && user && activeTab === 'dashboard') {
      setActiveTab('checking');
    }
  }, [user]);

  // Handlers de Lote com Atualização Funcional
  const startNewConference = (batch: ConferenceBatch) => {
    if (currentBatch) {
      setPausedBatches(prev => [currentBatch, ...prev]);
    }
    setCurrentBatch(batch);
    setActiveTab('checking');
  };

  const handlePauseActive = () => {
    if (currentBatch) {
      setPausedBatches(prev => [currentBatch, ...prev]);
      setCurrentBatch(null);
      setActiveTab('upload');
    }
  };

  const handleResumeBatch = (batchToResume: ConferenceBatch) => {
    if (currentBatch) {
      if (window.confirm("Você possui uma conferência ativa agora. Deseja pausá-la para retomar esta?")) {
        const batchToPause = { ...currentBatch };
        setPausedBatches(prev => [batchToPause, ...prev.filter(b => b.id !== batchToResume.id)]);
        setCurrentBatch(batchToResume);
        setActiveTab('checking');
      }
    } else {
      setPausedBatches(prev => prev.filter(b => b.id !== batchToResume.id));
      setCurrentBatch(batchToResume);
      setActiveTab('checking');
    }
  };

  // Removido o window.confirm daqui, pois o componente PausedBatches já gerencia o modal de confirmação
  const deletePausedBatch = (id: string) => {
    setPausedBatches(prev => prev.filter(b => b.id !== id));
  };

  // Auth Handlers
  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const found = users.find(u => u.username === loginForm.username && u.password === loginForm.password);
    if (found) {
      setUser(found);
      if (currentBatch) setActiveTab('checking');
      else if (found.role === UserRole.CONFERENTE) setActiveTab('upload');
      else setActiveTab('dashboard');
    } else {
      setLoginError('Credenciais inválidas.');
    }
  };

  const handleLogout = () => {
    setUser(null);
    setIsSupervisorView(false);
  };

  const finalizeConference = () => {
    if (!currentBatch) return;
    const hasDivergence = currentBatch.products.some(p => p.quantityExpected !== p.quantityChecked);
    if (hasDivergence) setIsSupervisorView(true);
    else {
      const finalBatch = { ...currentBatch, status: 'APPROVED' as const, endTime: new Date().toISOString() };
      setBatches(prev => [finalBatch, ...prev]);
      setCurrentBatch(null);
      setActiveTab('history');
      setViewingReport(finalBatch);
    }
  };

  const handleSupervisorApprove = (supervisor: User, justification: string) => {
    if (!currentBatch) return;
    const finalBatch = { 
      ...currentBatch, 
      status: 'APPROVED' as const, 
      endTime: new Date().toISOString(),
      supervisorId: supervisor.id,
      supervisorName: supervisor.name,
      justification
    };
    setBatches(prev => [finalBatch, ...prev]);
    setCurrentBatch(null);
    setIsSupervisorView(false);
    setActiveTab('history');
    setViewingReport(finalBatch);
  };

  // UI Logic
  let content;
  if (isSupervisorView && currentBatch) {
    content = <SupervisorCheck batch={currentBatch} users={users} onApprove={handleSupervisorApprove} onReject={() => { setIsSupervisorView(false); setActiveTab('checking'); }} />;
  } else if (currentBatch && activeTab === 'checking') {
    content = <BlindCheck batch={currentBatch} onUpdateBatch={setCurrentBatch} onFinish={finalizeConference} onCancel={() => { setCurrentBatch(null); setActiveTab('upload'); }} onPause={handlePauseActive} />;
  } else {
    switch (activeTab) {
      case 'dashboard': content = <Dashboard batches={batches} />; break;
      case 'upload': content = <XMLUpload currentUser={user!} onStartConference={startNewConference} />; break;
      case 'paused': content = <PausedBatches pausedBatches={pausedBatches} onResume={handleResumeBatch} onDelete={deletePausedBatch} />; break;
      case 'history': content = (
        <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
          <table className="w-full text-left">
            <thead className="bg-slate-50 text-slate-400 text-[10px] font-black uppercase tracking-widest">
              <tr><th className="px-6 py-4">Data/Hora</th><th className="px-6 py-4">Lote ID</th><th className="px-6 py-4">Conferente</th><th className="px-6 py-4">Status</th><th className="px-6 py-4 text-right">Ações</th></tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {batches.map(b => (
                <tr key={b.id} className="hover:bg-slate-50/50 group transition-colors">
                  <td className="px-6 py-4 text-xs font-bold text-slate-500">{new Date(b.endTime || b.startTime).toLocaleString('pt-BR')}</td>
                  <td className="px-6 py-4 text-sm font-mono font-black text-blue-600 uppercase tracking-tighter">#{b.id}</td>
                  <td className="px-6 py-4 text-sm font-bold text-slate-800">{b.conferenteName}</td>
                  <td className="px-6 py-4">
                    <span className={`px-3 py-1 rounded-lg text-[10px] font-black tracking-widest uppercase ${b.status === 'APPROVED' ? 'bg-green-100 text-green-700' : 'bg-orange-100 text-orange-700'}`}>{b.status}</span>
                  </td>
                  <td className="px-6 py-4 text-right">
                    <button onClick={() => setViewingReport(b)} className="bg-slate-100 text-slate-600 hover:bg-blue-600 hover:text-white px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all flex items-center gap-2 ml-auto"><Eye size={14} /> Relatório</button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      ); break;
      case 'admin': content = <AdminPanel users={users} currentUser={user!} onAddUser={(u) => setUsers(prev => [...prev, u])} onDeleteUser={(id) => setUsers(prev => prev.filter(u => u.id !== id))} onUpdateUser={(u) => setUsers(prev => prev.map(us => us.id === u.id ? u : us))} />; break;
      default: content = user?.role === UserRole.CONFERENTE ? <XMLUpload currentUser={user!} onStartConference={startNewConference} /> : <Dashboard batches={batches} />;
    }
  }

  if (!user) {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center p-4">
        <div className="max-w-md w-full bg-white rounded-3xl shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-300">
          <div className="p-10 text-center bg-slate-50 border-b border-slate-100">
            <div className="bg-blue-600 w-16 h-16 rounded-2xl flex items-center justify-center mx-auto mb-6 shadow-lg shadow-blue-500/30">
              <PackageCheck className="text-white" size={40} />
            </div>
            <h1 className="text-3xl font-black text-slate-800 tracking-tight">CheckMaster</h1>
            <p className="text-slate-500 mt-2 font-medium">Logística & Conferência Cega</p>
          </div>
          <div className="p-10">
            <form onSubmit={handleLogin} className="space-y-6">
              <div><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1.5 ml-1">Usuário / Login</label><input type="text" className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-5 py-4 focus:ring-2 focus:ring-blue-500 outline-none" value={loginForm.username} onChange={e => setLoginForm({...loginForm, username: e.target.value})} placeholder="Seu login" required /></div>
              <div><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1.5 ml-1">Senha</label><input type="password" className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-5 py-4 focus:ring-2 focus:ring-blue-500 outline-none" value={loginForm.password} onChange={e => setLoginForm({...loginForm, password: e.target.value})} placeholder="••••••••" required /></div>
              {loginError && <p className="text-red-500 text-xs font-bold text-center bg-red-50 py-3 rounded-xl">{loginError}</p>}
              <button type="submit" className="w-full bg-blue-600 hover:bg-blue-700 text-white font-black py-5 rounded-2xl shadow-xl shadow-blue-500/30 transition-all flex items-center justify-center gap-2 group text-sm uppercase tracking-widest">Acessar Sistema</button>
            </form>
          </div>
        </div>
      </div>
    );
  }

  return (
    <Layout user={user} onLogout={handleLogout} activeTab={activeTab} setActiveTab={setActiveTab} pausedCount={pausedBatches.length}>
      {content}
      {viewingReport && <ReportModal batch={viewingReport} onClose={() => setViewingReport(null)} />}
    </Layout>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { ConferenceBatch } from '../types';
import { 
  Play, 
  Trash2, 
  Clock, 
  Package, 
  FileText, 
  Search, 
  FilterX, 
  AlertTriangle,
  X
} from 'lucide-react';

interface PausedBatchesProps {
  pausedBatches: ConferenceBatch[];
  onResume: (batch: ConferenceBatch) => void;
  onDelete: (id: string) => void;
}

const PausedBatches: React.FC<PausedBatchesProps> = ({ pausedBatches, onResume, onDelete }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [batchToDelete, setBatchToDelete] = useState<string | null>(null);

  const filteredPaused = useMemo(() => {
    if (!searchTerm.trim()) return pausedBatches;

    const term = searchTerm.trim().toLowerCase();
    return pausedBatches.filter(batch => {
      const matchesNF = batch.notes.some(note => note.number.toLowerCase().includes(term));
      const matchesBatchId = batch.id.toLowerCase().includes(term);
      return matchesNF || matchesBatchId;
    });
  }, [pausedBatches, searchTerm]);

  const confirmDelete = () => {
    if (batchToDelete) {
      onDelete(batchToDelete);
      setBatchToDelete(null);
    }
  };

  if (pausedBatches.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center py-20 bg-white rounded-[32px] border-2 border-dashed border-slate-100">
        <Clock size={64} className="text-slate-200 mb-4" />
        <h3 className="text-xl font-bold text-slate-400 uppercase tracking-widest">Fila de Espera Vazia</h3>
        <p className="text-slate-300 text-sm">Nenhuma conferência pausada no momento.</p>
      </div>
    );
  }

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      {/* Barra de Pesquisa */}
      <div className="relative">
        <div className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-400">
          <Search size={20} />
        </div>
        <input 
          type="text"
          placeholder="Pesquisar por número da Nota Fiscal (NF) ou ID do lote..."
          className="w-full bg-white border border-slate-200 rounded-2xl py-5 pl-14 pr-14 focus:ring-2 focus:ring-blue-500 focus:outline-none shadow-sm transition-all font-medium text-slate-700"
          value={searchTerm}
          onChange={e => setSearchTerm(e.target.value)}
        />
        {searchTerm && (
          <button 
            onClick={() => setSearchTerm('')}
            className="absolute right-5 top-1/2 -translate-y-1/2 text-slate-300 hover:text-slate-500 transition-colors"
          >
            <FilterX size={20} />
          </button>
        )}
      </div>

      {filteredPaused.length > 0 ? (
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          {filteredPaused.map((batch) => {
            const totalChecked = batch.products.reduce((acc, p) => acc + p.quantityChecked, 0);
            const totalExpected = batch.products.reduce((acc, p) => acc + p.quantityExpected, 0);
            const progress = Math.min(Math.round((totalChecked / totalExpected) * 100), 100);

            return (
              <div key={batch.id} className="bg-white rounded-3xl p-6 shadow-sm border border-slate-100 hover:shadow-md transition-all group border-l-4 border-l-orange-400">
                <div className="flex justify-between items-start mb-6">
                  <div className="flex items-center gap-3">
                    <div className="bg-orange-50 p-3 rounded-2xl">
                      <Clock className="text-orange-500" size={24} />
                    </div>
                    <div>
                      <h4 className="font-black text-slate-800 uppercase tracking-tight">Lote #{batch.id}</h4>
                      <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">Pausado em {new Date(batch.startTime).toLocaleString('pt-BR')}</p>
                    </div>
                  </div>
                  <button 
                    onClick={() => setBatchToDelete(batch.id)}
                    className="text-slate-300 hover:text-red-600 p-2.5 bg-slate-50 hover:bg-red-50 rounded-xl transition-all"
                    title="Excluir Lote"
                  >
                    <Trash2 size={20} />
                  </button>
                </div>

                <div className="grid grid-cols-1 gap-4 mb-6">
                  <div className="bg-blue-50/50 p-3 rounded-xl border border-blue-100">
                    <div className="flex items-center gap-2 text-blue-400 text-[10px] font-black uppercase tracking-widest mb-1">
                      <FileText size={12} /> Notas Fiscais (NF)
                    </div>
                    <p className="text-xs font-black text-blue-700 truncate">
                      {batch.notes.map(n => n.number).join(', ')}
                    </p>
                  </div>
                </div>

                <div className="grid grid-cols-2 gap-4 mb-6">
                  <div className="bg-slate-50 p-3 rounded-xl border border-slate-100">
                    <div className="flex items-center gap-2 text-slate-400 text-[10px] font-black uppercase tracking-widest mb-1">
                      <Package size={12} /> SKUs
                    </div>
                    <p className="text-xs font-bold text-slate-700">{batch.products.length} Itens</p>
                  </div>
                  <div className="bg-slate-50 p-3 rounded-xl border border-slate-100">
                    <div className="flex items-center gap-2 text-slate-400 text-[10px] font-black uppercase tracking-widest mb-1">
                      <Clock size={12} /> Responsável
                    </div>
                    <p className="text-xs font-bold text-slate-700 truncate">{batch.conferenteName}</p>
                  </div>
                </div>

                <div className="space-y-2 mb-6">
                  <div className="flex justify-between text-[10px] font-black text-slate-400 uppercase tracking-widest">
                    <span>Progresso Salvo</span>
                    <span>{progress}%</span>
                  </div>
                  <div className="w-full bg-slate-100 h-2 rounded-full overflow-hidden">
                    <div 
                      className="bg-orange-400 h-full transition-all duration-500" 
                      style={{ width: `${progress}%` }}
                    ></div>
                  </div>
                </div>

                <button 
                  onClick={() => onResume(batch)}
                  className="w-full bg-slate-900 hover:bg-black text-white py-4 rounded-2xl font-black uppercase tracking-widest text-[10px] flex items-center justify-center gap-2 transition-all shadow-xl shadow-slate-900/10 group-hover:scale-[1.01]"
                >
                  Retomar Conferência
                  <Play size={14} fill="currentColor" />
                </button>
              </div>
            );
          })}
        </div>
      ) : (
        <div className="flex flex-col items-center justify-center py-20 bg-white rounded-[32px] border-2 border-dashed border-slate-100">
          <Search size={48} className="text-slate-200 mb-4" />
          <h3 className="text-xl font-bold text-slate-400 uppercase tracking-widest">Nenhuma NF encontrada</h3>
          <p className="text-slate-300 text-sm">Não encontramos conferências pausadas com o termo "{searchTerm}".</p>
        </div>
      )}

      {/* Modal de Confirmação de Exclusão */}
      {batchToDelete && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/70 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-md rounded-[32px] shadow-2xl overflow-hidden animate-in zoom-in duration-200 border border-slate-100">
            <div className="p-8 text-center">
              <div className="bg-red-100 w-20 h-20 rounded-full flex items-center justify-center mx-auto mb-6 text-red-600">
                <AlertTriangle size={40} />
              </div>
              <h3 className="text-2xl font-black text-slate-800 uppercase tracking-tight mb-3">Excluir Lote Pausado?</h3>
              <p className="text-slate-500 font-medium leading-relaxed">
                Esta ação removerá permanentemente este lote da fila de espera. Deseja continuar?
              </p>

              <div className="mt-10 flex flex-col gap-3">
                <button 
                  onClick={confirmDelete}
                  className="w-full bg-red-600 hover:bg-red-700 text-white py-5 rounded-2xl font-black uppercase tracking-widest text-xs transition-all shadow-xl shadow-red-500/20 flex items-center justify-center gap-2"
                >
                  SIM
                </button>
                <button 
                  onClick={() => setBatchToDelete(null)}
                  className="w-full bg-white border-2 border-slate-100 hover:bg-slate-50 text-slate-600 py-5 rounded-2xl font-black uppercase tracking-widest text-xs transition-all flex items-center justify-center gap-2"
                >
                  NÃO
                </button>
              </div>
            </div>
            <div className="bg-slate-50 p-4 text-center border-t border-slate-100">
               <button 
                onClick={() => setBatchToDelete(null)}
                className="text-slate-400 hover:text-slate-600 text-[10px] font-bold uppercase tracking-widest flex items-center justify-center gap-1 mx-auto"
              >
                <X size={14} /> Fechar
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default PausedBatches;

import React, { useState, useEffect } from 'react';
import { User, UserRole, ConferenceBatch } from './types';
import { INITIAL_USERS, STORAGE_KEYS } from './constants';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import XMLUpload from './components/XMLUpload';
import BlindCheck from './components/BlindCheck';
import SupervisorCheck from './components/SupervisorCheck';
import AdminPanel from './components/AdminPanel';
import ReportModal from './components/ReportModal';
import PausedBatches from './components/PausedBatches';
import { LogIn, PackageCheck, Eye } from 'lucide-react';

const App: React.FC = () => {
  // Auth State
  const [user, setUser] = useState<User | null>(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.CURRENT_USER);
    return saved ? JSON.parse(saved) : null;
  });
  const [loginForm, setLoginForm] = useState({ username: '', password: '' });
  const [loginError, setLoginError] = useState('');

  // App State
  const [activeTab, setActiveTab] = useState('dashboard');
  const [users, setUsers] = useState<User[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.USERS);
    return saved ? JSON.parse(saved) : INITIAL_USERS;
  });
  const [batches, setBatches] = useState<ConferenceBatch[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.BATCHES);
    return saved ? JSON.parse(saved) : [];
  });

  // Lote Ativo
  const [currentBatch, setCurrentBatch] = useState<ConferenceBatch | null>(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.ACTIVE_BATCH);
    return saved ? JSON.parse(saved) : null;
  });

  // Fila de Lotes Pausados
  const [pausedBatches, setPausedBatches] = useState<ConferenceBatch[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.PAUSED_BATCHES);
    return saved ? JSON.parse(saved) : [];
  });

  const [isSupervisorView, setIsSupervisorView] = useState(false);
  const [viewingReport, setViewingReport] = useState<ConferenceBatch | null>(null);

  // Sync Storage
  useEffect(() => localStorage.setItem(STORAGE_KEYS.USERS, JSON.stringify(users)), [users]);
  useEffect(() => localStorage.setItem(STORAGE_KEYS.BATCHES, JSON.stringify(batches)), [batches]);
  useEffect(() => localStorage.setItem(STORAGE_KEYS.PAUSED_BATCHES, JSON.stringify(pausedBatches)), [pausedBatches]);

  useEffect(() => {
    if (currentBatch) {
      localStorage.setItem(STORAGE_KEYS.ACTIVE_BATCH, JSON.stringify(currentBatch));
    } else {
      localStorage.removeItem(STORAGE_KEYS.ACTIVE_BATCH);
    }
  }, [currentBatch]);

  useEffect(() => {
    if (user) localStorage.setItem(STORAGE_KEYS.CURRENT_USER, JSON.stringify(user));
    else localStorage.removeItem(STORAGE_KEYS.CURRENT_USER);
  }, [user]);

  // Redirecionamento Automático
  useEffect(() => {
    if (currentBatch && user && activeTab === 'dashboard') {
      setActiveTab('checking');
    }
  }, [user]);

  // Handlers de Lote com Atualização Funcional
  const startNewConference = (batch: ConferenceBatch) => {
    if (currentBatch) {
      setPausedBatches(prev => [currentBatch, ...prev]);
    }
    setCurrentBatch(batch);
    setActiveTab('checking');
  };

  const handlePauseActive = () => {
    if (currentBatch) {
      setPausedBatches(prev => [currentBatch, ...prev]);
      setCurrentBatch(null);
      setActiveTab('upload');
    }
  };

  const handleResumeBatch = (batchToResume: ConferenceBatch) => {
    if (currentBatch) {
      if (window.confirm("Você possui uma conferência ativa agora. Deseja pausá-la para retomar esta?")) {
        const batchToPause = { ...currentBatch };
        setPausedBatches(prev => [batchToPause, ...prev.filter(b => b.id !== batchToResume.id)]);
        setCurrentBatch(batchToResume);
        setActiveTab('checking');
      }
    } else {
      setPausedBatches(prev => prev.filter(b => b.id !== batchToResume.id));
      setCurrentBatch(batchToResume);
      setActiveTab('checking');
    }
  };

  const deletePausedBatch = (id: string) => {
    setPausedBatches(prev => prev.filter(b => b.id !== id));
  };

  // Auth Handlers
  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const found = users.find(u => u.username === loginForm.username && u.password === loginForm.password);
    if (found) {
      setUser(found);
      setLoginError(''); // Limpa erro ao logar com sucesso
      if (currentBatch) setActiveTab('checking');
      else if (found.role === UserRole.CONFERENTE) setActiveTab('upload');
      else setActiveTab('dashboard');
    } else {
      setLoginError('Credenciais inválidas.');
    }
  };

  const handleLogout = () => {
    // 1. Limpa o usuário da sessão
    setUser(null);
    // 2. Reseta o formulário de login (Limpa Usuário e Senha da tela)
    setLoginForm({ username: '', password: '' });
    // 3. Limpa mensagens de erro
    setLoginError('');
    // 4. Reseta estados de visualização
    setIsSupervisorView(false);
    setActiveTab('dashboard');
    setViewingReport(null);
    // 5. Garante limpeza no localStorage
    localStorage.removeItem(STORAGE_KEYS.CURRENT_USER);
  };

  const finalizeConference = () => {
    if (!currentBatch) return;
    const hasDivergence = currentBatch.products.some(p => p.quantityExpected !== p.quantityChecked);
    if (hasDivergence) setIsSupervisorView(true);
    else {
      const finalBatch = { ...currentBatch, status: 'APPROVED' as const, endTime: new Date().toISOString() };
      setBatches(prev => [finalBatch, ...prev]);
      setCurrentBatch(null);
      setActiveTab('history');
      setViewingReport(finalBatch);
    }
  };

  const handleSupervisorApprove = (supervisor: User, justification: string) => {
    if (!currentBatch) return;
    const finalBatch = { 
      ...currentBatch, 
      status: 'APPROVED' as const, 
      endTime: new Date().toISOString(),
      supervisorId: supervisor.id,
      supervisorName: supervisor.name,
      justification
    };
    setBatches(prev => [finalBatch, ...prev]);
    setCurrentBatch(null);
    setIsSupervisorView(false);
    setActiveTab('history');
    setViewingReport(finalBatch);
  };

  // UI Logic
  let content;
  if (isSupervisorView && currentBatch) {
    content = <SupervisorCheck batch={currentBatch} users={users} onApprove={handleSupervisorApprove} onReject={() => { setIsSupervisorView(false); setActiveTab('checking'); }} />;
  } else if (currentBatch && activeTab === 'checking') {
    content = <BlindCheck batch={currentBatch} onUpdateBatch={setCurrentBatch} onFinish={finalizeConference} onCancel={() => { setCurrentBatch(null); setActiveTab('upload'); }} onPause={handlePauseActive} />;
  } else {
    switch (activeTab) {
      case 'dashboard': content = <Dashboard batches={batches} />; break;
      case 'upload': content = <XMLUpload currentUser={user!} onStartConference={startNewConference} />; break;
      case 'paused': content = <PausedBatches pausedBatches={pausedBatches} onResume={handleResumeBatch} onDelete={deletePausedBatch} />; break;
      case 'history': content = (
        <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
          <table className="w-full text-left">
            <thead className="bg-slate-50 text-slate-400 text-[10px] font-black uppercase tracking-widest">
              <tr><th className="px-6 py-4">Data/Hora</th><th className="px-6 py-4">Lote ID</th><th className="px-6 py-4">Conferente</th><th className="px-6 py-4">Status</th><th className="px-6 py-4 text-right">Ações</th></tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {batches.map(b => (
                <tr key={b.id} className="hover:bg-slate-50/50 group transition-colors">
                  <td className="px-6 py-4 text-xs font-bold text-slate-500">{new Date(b.endTime || b.startTime).toLocaleString('pt-BR')}</td>
                  <td className="px-6 py-4 text-sm font-mono font-black text-blue-600 uppercase tracking-tighter">#{b.id}</td>
                  <td className="px-6 py-4 text-sm font-bold text-slate-800">{b.conferenteName}</td>
                  <td className="px-6 py-4">
                    <span className={`px-3 py-1 rounded-lg text-[10px] font-black tracking-widest uppercase ${b.status === 'APPROVED' ? 'bg-green-100 text-green-700' : 'bg-orange-100 text-orange-700'}`}>{b.status}</span>
                  </td>
                  <td className="px-6 py-4 text-right">
                    <button onClick={() => setViewingReport(b)} className="bg-slate-100 text-slate-600 hover:bg-blue-600 hover:text-white px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all flex items-center gap-2 ml-auto"><Eye size={14} /> Relatório</button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      ); break;
      case 'admin': content = <AdminPanel users={users} currentUser={user!} onAddUser={(u) => setUsers(prev => [...prev, u])} onDeleteUser={(id) => setUsers(prev => prev.filter(u => u.id !== id))} onUpdateUser={(u) => setUsers(prev => prev.map(us => us.id === u.id ? u : us))} />; break;
      default: content = user?.role === UserRole.CONFERENTE ? <XMLUpload currentUser={user!} onStartConference={startNewConference} /> : <Dashboard batches={batches} />;
    }
  }

  if (!user) {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center p-4">
        <div className="max-w-md w-full bg-white rounded-3xl shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-300">
          <div className="p-10 text-center bg-slate-50 border-b border-slate-100">
            <div className="bg-blue-600 w-16 h-16 rounded-2xl flex items-center justify-center mx-auto mb-6 shadow-lg shadow-blue-500/30">
              <PackageCheck className="text-white" size={40} />
            </div>
            <h1 className="text-3xl font-black text-slate-800 tracking-tight">CheckMaster</h1>
            <p className="text-slate-500 mt-2 font-medium">Logística & Conferência Cega</p>
          </div>
          <div className="p-10">
            <form onSubmit={handleLogin} className="space-y-6" autoComplete="off">
              <div>
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1.5 ml-1">Usuário / Login</label>
                <input 
                  type="text" 
                  autoComplete="off"
                  className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-5 py-4 focus:ring-2 focus:ring-blue-500 outline-none" 
                  value={loginForm.username} 
                  onChange={e => setLoginForm({...loginForm, username: e.target.value})} 
                  placeholder="Seu login" 
                  required 
                />
              </div>
              <div>
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1.5 ml-1">Senha</label>
                <input 
                  type="password" 
                  autoComplete="new-password"
                  className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-5 py-4 focus:ring-2 focus:ring-blue-500 outline-none" 
                  value={loginForm.password} 
                  onChange={e => setLoginForm({...loginForm, password: e.target.value})} 
                  placeholder="••••••••" 
                  required 
                />
              </div>
              {loginError && <p className="text-red-500 text-xs font-bold text-center bg-red-50 py-3 rounded-xl">{loginError}</p>}
              <button type="submit" className="w-full bg-blue-600 hover:bg-blue-700 text-white font-black py-5 rounded-2xl shadow-xl shadow-blue-500/30 transition-all flex items-center justify-center gap-2 group text-sm uppercase tracking-widest">Acessar Sistema</button>
            </form>
          </div>
        </div>
      </div>
    );
  }

  return (
    <Layout user={user} onLogout={handleLogout} activeTab={activeTab} setActiveTab={setActiveTab} pausedCount={pausedBatches.length}>
      {content}
      {viewingReport && <ReportModal batch={viewingReport} onClose={() => setViewingReport(null)} />}
    </Layout>
  );
};

