import React, { useState } from 'react';
import { Upload, FileText, X, CheckCircle, Building2 } from 'lucide-react';
import { parseNFeXML, consolidateProducts } from '../services/xmlParser';
import { NFeInfo, NFeProduct, ConferenceBatch, User, Branch } from '../types';

interface XMLUploadProps {
  currentUser: User;
  branches: Branch[];
  onStartConference: (batch: ConferenceBatch) => void;
}

const XMLUpload: React.FC<XMLUploadProps> = ({ currentUser, branches, onStartConference }) => {
  const [files, setFiles] = useState<File[]>([]);
  const [loading, setLoading] = useState(false);
  const [parsedData, setParsedData] = useState<{ info: NFeInfo; products: NFeProduct[] }[]>([]);

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!e.target.files) return;
    setLoading(true);
    const newFiles = Array.from(e.target.files) as File[];

    try {
      const results = await Promise.all(newFiles.map(file => parseNFeXML(file)));
      setFiles(prev => [...prev, ...newFiles]);
      setParsedData(prev => [...prev, ...results]);
    } catch (err) {
      alert("Erro ao processar um ou mais arquivos XML.");
    } finally {
      setLoading(false);
    }
  };

  const removeFile = (index: number) => {
    setFiles(prev => prev.filter((_, i) => i !== index));
    setParsedData(prev => prev.filter((_, i) => i !== index));
  };

  const getOriginName = (cnpj: string, vendorName: string) => {
    const found = branches.find(b => b.cnpj === cnpj);
    return found ? found.name : vendorName;
  };

  const initConference = () => {
    if (parsedData.length === 0) return;

    const allNfes = parsedData.map(d => d.info);
    const allProds = parsedData.flatMap(d => d.products);
    const consolidated = consolidateProducts(allProds);

    const newBatch: ConferenceBatch = {
      id: Math.random().toString(36).substr(2, 9),
      notes: allNfes,
      products: consolidated,
      startTime: new Date().toISOString(),
      status: 'OPEN',
      conferenteId: currentUser.id,
      conferenteName: currentUser.name
    };

    onStartConference(newBatch);
  };

  return (
    <div className="max-w-4xl mx-auto space-y-6">
      <div className="bg-white p-8 rounded-2xl shadow-sm border border-slate-100 text-center">
        <div className="flex flex-col items-center justify-center border-2 border-dashed border-slate-200 rounded-xl p-12 hover:border-blue-400 transition-colors group cursor-pointer relative">
          <input 
            type="file" 
            multiple 
            accept=".xml" 
            className="absolute inset-0 opacity-0 cursor-pointer"
            onChange={handleFileChange}
          />
          <div className="bg-blue-50 p-4 rounded-full group-hover:bg-blue-100 transition-colors mb-4">
            <Upload className="text-blue-600" size={32} />
          </div>
          <h3 className="text-xl font-bold text-slate-800">Arraste seus XMLs ou clique para selecionar</h3>
          <p className="text-slate-500 mt-2">Formatos aceitos: .xml (NF-e)</p>
        </div>
      </div>

      {files.length > 0 && (
        <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
          <div className="p-4 bg-slate-50 border-b border-slate-100 flex justify-between items-center">
            <h4 className="font-semibold text-slate-700">Arquivos Preparados ({files.length})</h4>
            <button 
              onClick={initConference}
              disabled={loading}
              className="bg-blue-600 hover:bg-blue-700 text-white px-6 py-2 rounded-lg font-bold transition-all shadow-md flex items-center gap-2"
            >
              <CheckCircle size={18} />
              Iniciar Lote de Conferência
            </button>
          </div>
          <div className="max-h-[300px] overflow-y-auto p-4 space-y-2">
            {parsedData.map((data, idx) => (
              <div key={idx} className="flex items-center justify-between p-3 bg-slate-50 rounded-lg border border-slate-200">
                <div className="flex items-center gap-3">
                  <FileText className="text-blue-500" size={20} />
                  <div>
                    <p className="text-sm font-bold text-slate-800">NF-e: {data.info.number}</p>
                    <div className="flex items-center gap-1.5 mt-0.5">
                      <Building2 size={12} className="text-slate-400" />
                      <p className="text-[10px] font-black text-slate-500 uppercase tracking-tight">
                        {getOriginName(data.info.vendorCnpj, data.info.vendorName)}
                      </p>
                      <span className="text-slate-300 mx-1">|</span>
                      <p className="text-[10px] text-slate-400">{data.info.vendorCnpj}</p>
                    </div>
                  </div>
                </div>
                <button onClick={() => removeFile(idx)} className="text-slate-400 hover:text-red-500 p-1">
                  <X size={18} />
                </button>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

export default XMLUpload;

