  });

  // Lote Ativo
  const [currentBatch, setCurrentBatch] = useState<ConferenceBatch | null>(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.ACTIVE_BATCH);
    return saved ? JSON.parse(saved) : null;
  });

  // Fila de Lotes Pausados
  const [pausedBatches, setPausedBatches] = useState<ConferenceBatch[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.PAUSED_BATCHES);
    return saved ? JSON.parse(saved) : [];
  });

  const [isSupervisorView, setIsSupervisorView] = useState(false);
  const [viewingReport, setViewingReport] = useState<ConferenceBatch | null>(null);

  // Sync Storage
  useEffect(() => localStorage.setItem(STORAGE_KEYS.USERS, JSON.stringify(users)), [users]);
  useEffect(() => localStorage.setItem(STORAGE_KEYS.BRANCHES, JSON.stringify(branches)), [branches]);
  useEffect(() => localStorage.setItem(STORAGE_KEYS.BATCHES, JSON.stringify(batches)), [batches]);
  useEffect(() => localStorage.setItem(STORAGE_KEYS.PAUSED_BATCHES, JSON.stringify(pausedBatches)), [pausedBatches]);

  useEffect(() => {
    if (currentBatch) {
      localStorage.setItem(STORAGE_KEYS.ACTIVE_BATCH, JSON.stringify(currentBatch));
    } else {
      localStorage.removeItem(STORAGE_KEYS.ACTIVE_BATCH);
    }
  }, [currentBatch]);

  useEffect(() => {
    if (user) localStorage.setItem(STORAGE_KEYS.CURRENT_USER, JSON.stringify(user));
    else localStorage.removeItem(STORAGE_KEYS.CURRENT_USER);
  }, [user]);

  // Handlers
  const startNewConference = (batch: ConferenceBatch) => {
    if (currentBatch) {
      setPausedBatches(prev => [currentBatch, ...prev]);
    }
    setCurrentBatch(batch);
    setActiveTab('checking');
  };

  const handlePauseActive = () => {
    if (currentBatch) {
      setPausedBatches(prev => [currentBatch, ...prev]);
      setCurrentBatch(null);
      setActiveTab('upload');
    }
  };

  const handleResumeBatch = (batchToResume: ConferenceBatch) => {
    if (currentBatch) {
      if (window.confirm("Você possui uma conferência ativa agora. Deseja pausá-la para retomar esta?")) {
        const batchToPause = { ...currentBatch };
        setPausedBatches(prev => [batchToPause, ...prev.filter(b => b.id !== batchToResume.id)]);
        setCurrentBatch(batchToResume);
        setActiveTab('checking');
      }
    } else {
      setPausedBatches(prev => prev.filter(b => b.id !== batchToResume.id));
      setCurrentBatch(batchToResume);
      setActiveTab('checking');
    }
  };

  const deletePausedBatch = (id: string) => {
    setPausedBatches(prev => prev.filter(b => b.id !== id));
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const found = users.find(u => u.username === loginForm.username && u.password === loginForm.password);
    if (found) {
      setUser(found);
      setLoginError('');
      if (currentBatch) setActiveTab('checking');
      else if (found.role === UserRole.CONFERENTE) setActiveTab('upload');
      else setActiveTab('dashboard');
    } else {
      setLoginError('Credenciais inválidas.');
    }
  };

  const handleLogout = () => {
    setUser(null);
    setLoginForm({ username: '', password: '' });
    setLoginError('');
    setIsSupervisorView(false);
    setActiveTab('dashboard');
    setViewingReport(null);
  };

  const finalizeConference = () => {
    if (!currentBatch) return;
    const hasDivergence = currentBatch.products.some(p => p.quantityExpected !== p.quantityChecked);
    if (hasDivergence) setIsSupervisorView(true);
    else {
      const finalBatch = { ...currentBatch, status: 'APPROVED' as const, endTime: new Date().toISOString() };
      setBatches(prev => [finalBatch, ...prev]);
      setCurrentBatch(null);
      setActiveTab('history');
      setViewingReport(finalBatch);
    }
  };

  const handleSupervisorApprove = (supervisor: User, justification: string) => {
    if (!currentBatch) return;
    const finalBatch = { 
      ...currentBatch, 
      status: 'APPROVED' as const, 
      endTime: new Date().toISOString(),
      supervisorId: supervisor.id,
      supervisorName: supervisor.name,
      justification
    };
    setBatches(prev => [finalBatch, ...prev]);
    setCurrentBatch(null);
    setIsSupervisorView(false);
    setActiveTab('history');
    setViewingReport(finalBatch);
  };

  // UI Logic
  let content;
  if (isSupervisorView && currentBatch) {
    content = <SupervisorCheck batch={currentBatch} users={users} onApprove={handleSupervisorApprove} onReject={() => { setIsSupervisorView(false); setActiveTab('checking'); }} />;
  } else if (currentBatch && activeTab === 'checking') {
    content = <BlindCheck batch={currentBatch} onUpdateBatch={setCurrentBatch} onFinish={finalizeConference} onCancel={() => { setCurrentBatch(null); setActiveTab('upload'); }} onPause={handlePauseActive} />;
  } else {
    switch (activeTab) {
      case 'dashboard': content = <Dashboard batches={batches} />; break;
      case 'upload': content = <XMLUpload currentUser={user!} branches={branches} onStartConference={startNewConference} />; break;
      case 'paused': content = <PausedBatches pausedBatches={pausedBatches} onResume={handleResumeBatch} onDelete={deletePausedBatch} />; break;
      case 'history': content = (
        <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
          <table className="w-full text-left">
            <thead className="bg-slate-50 text-slate-400 text-[10px] font-black uppercase tracking-widest">
              <tr><th className="px-6 py-4">Data/Hora</th><th className="px-6 py-4">Lote ID</th><th className="px-6 py-4">Conferente</th><th className="px-6 py-4">Status</th><th className="px-6 py-4 text-right">Ações</th></tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {batches.map(b => (
                <tr key={b.id} className="hover:bg-slate-50/50 group transition-colors">
                  <td className="px-6 py-4 text-xs font-bold text-slate-500">{new Date(b.endTime || b.startTime).toLocaleString('pt-BR')}</td>
                  <td className="px-6 py-4 text-sm font-mono font-black text-blue-600 uppercase tracking-tighter">#{b.id}</td>
                  <td className="px-6 py-4 text-sm font-bold text-slate-800">{b.conferenteName}</td>
                  <td className="px-6 py-4">
                    <span className={`px-3 py-1 rounded-lg text-[10px] font-black tracking-widest uppercase ${b.status === 'APPROVED' ? 'bg-green-100 text-green-700' : 'bg-orange-100 text-orange-700'}`}>{b.status}</span>
                  </td>
                  <td className="px-6 py-4 text-right">
                    <button onClick={() => setViewingReport(b)} className="bg-slate-100 text-slate-600 hover:bg-blue-600 hover:text-white px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all">Relatório</button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      ); break;
      case 'branches': content = <BranchPanel branches={branches} onAddBranch={(b) => setBranches(prev => [...prev, b])} onDeleteBranch={(id) => setBranches(prev => prev.filter(b => b.id !== id))} />; break;
      case 'admin': content = <AdminPanel users={users} currentUser={user!} onAddUser={(u) => setUsers(prev => [...prev, u])} onDeleteUser={(id) => setUsers(prev => prev.filter(u => u.id !== id))} onUpdateUser={(u) => setUsers(prev => prev.map(us => us.id === u.id ? u : us))} />; break;
      default: content = <Dashboard batches={batches} />;
    }
  }

  if (!user) {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center p-4">
        <div className="max-w-md w-full bg-white rounded-3xl shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-300">
          <div className="p-10 text-center bg-slate-50 border-b border-slate-100">
            <div className="bg-blue-600 w-16 h-16 rounded-2xl flex items-center justify-center mx-auto mb-6 shadow-lg shadow-blue-500/30">
              <PackageCheck className="text-white" size={40} />
            </div>
            <h1 className="text-3xl font-black text-slate-800 tracking-tight">CheckMaster</h1>
            <p className="text-slate-500 mt-2 font-medium">Logística & Conferência Cega</p>
          </div>
          <div className="p-10">
            <form onSubmit={handleLogin} className="space-y-6" autoComplete="off">
              <div>
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1.5 ml-1">Usuário / Login</label>
                <input type="text" className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-5 py-4 focus:ring-2 focus:ring-blue-500 outline-none" value={loginForm.username} onChange={e => setLoginForm({...loginForm, username: e.target.value})} placeholder="Seu login" required />
              </div>
              <div>
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1.5 ml-1">Senha</label>
                <input type="password" className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-5 py-4 focus:ring-2 focus:ring-blue-500 outline-none" value={loginForm.password} onChange={e => setLoginForm({...loginForm, password: e.target.value})} placeholder="••••••••" required />
              </div>
              {loginError && <p className="text-red-500 text-xs font-bold text-center bg-red-50 py-3 rounded-xl">{loginError}</p>}
              <button type="submit" className="w-full bg-blue-600 hover:bg-blue-700 text-white font-black py-5 rounded-2xl shadow-xl shadow-blue-500/30 transition-all flex items-center justify-center gap-2 group text-sm uppercase tracking-widest">Acessar Sistema</button>
            </form>
          </div>
        </div>
      </div>
    );
  }

  return (
    <Layout user={user} onLogout={handleLogout} activeTab={activeTab} setActiveTab={setActiveTab} pausedCount={pausedBatches.length}>
      {content}
      {viewingReport && <ReportModal batch={viewingReport} onClose={() => setViewingReport(null)} />}
    </Layout>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { 
  Scan, 
  Keyboard, 
  Search, 
  CheckCircle, 
  ArrowRight,
  AlertCircle,
  Package,
  Save,
  Trash2,
  X,
  AlertTriangle
} from 'lucide-react';
import { ConferenceBatch, NFeProduct } from '../types';

interface BlindCheckProps {
  batch: ConferenceBatch;
  onUpdateBatch: (batch: ConferenceBatch) => void;
  onFinish: () => void;
  onCancel: () => void;
  onPause: () => void;
}

const BlindCheck: React.FC<BlindCheckProps> = ({ batch, onUpdateBatch, onFinish, onCancel, onPause }) => {
  const [searchInput, setSearchInput] = useState('');
  const [manualQty, setManualQty] = useState<number>(1);
  const [errorMsg, setErrorMsg] = useState('');
  const [lastScanned, setLastScanned] = useState<NFeProduct | null>(null);
  const [showDiscardConfirm, setShowDiscardConfirm] = useState(false);

  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    inputRef.current?.focus();
  }, []);

  const totalExpected = batch.products.reduce((acc, p) => acc + p.quantityExpected, 0);
  const totalChecked = batch.products.reduce((acc, p) => acc + p.quantityChecked, 0);
  const progress = Math.min(Math.round((totalChecked / totalExpected) * 100), 100);

  const handleScan = (e: React.FormEvent) => {
    e.preventDefault();
    if (!searchInput.trim()) return;

    const term = searchInput.trim().toUpperCase();
    const productIndex = batch.products.findIndex(p => 
      p.ean === term || p.code.toUpperCase() === term
    );

    if (productIndex === -1) {
      setErrorMsg(`Produto "${term}" não encontrado no lote.`);
      setTimeout(() => setErrorMsg(''), 3000);
    } else {
      const updatedProducts = [...batch.products];
      updatedProducts[productIndex].quantityChecked += manualQty;

      onUpdateBatch({ ...batch, products: updatedProducts });
      setLastScanned(updatedProducts[productIndex]);
      setSearchInput('');
      setManualQty(1);
    }
    inputRef.current?.focus();
  };

  const removeItem = (id: string) => {
    const updatedProducts = batch.products.map(p => 
      p.id === id ? { ...p, quantityChecked: 0 } : p
    );
    onUpdateBatch({ ...batch, products: updatedProducts });
  };

  const handleConfirmDiscard = () => {
    setShowDiscardConfirm(false);
    onCancel(); // Chama a função que limpa o currentBatch no App.tsx
  };

  return (
    <div className="max-w-6xl mx-auto flex flex-col h-full gap-6 pb-20">
      {/* Top Status Bar */}
      <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex items-center justify-between">
        <div className="flex items-center gap-6">
          <div className="bg-blue-50 p-4 rounded-xl">
            <Package className="text-blue-600" size={32} />
          </div>
          <div>
            <h3 className="text-xl font-bold text-slate-800">Conferência em Lote: {batch.notes.length} Notas</h3>
            <div className="flex items-center gap-2 text-slate-500 text-sm mt-1">
              <Save size={14} className="text-green-500" />
              <span>Salvamento Automático Ativo</span>
            </div>
          </div>
        </div>

        <div className="flex flex-col items-end gap-2 w-64">
          <div className="flex justify-between w-full text-sm font-semibold text-slate-600">
            <span>Progresso da Conferência</span>
            <span>{progress}%</span>
          </div>
          <div className="w-full bg-slate-100 h-3 rounded-full overflow-hidden">
            <div 
              className={`h-full transition-all duration-500 ${progress >= 100 ? 'bg-green-500' : 'bg-blue-500'}`}
              style={{ width: `${progress}%` }}
            ></div>
          </div>
        </div>
      </div>

      {/* Main Checking Area */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 flex-1 min-h-0">
        {/* Input Panel */}
        <div className="lg:col-span-1 flex flex-col gap-6">
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
            <h4 className="font-bold text-slate-700 mb-4 flex items-center gap-2">
              <Scan size={20} className="text-blue-500" />
              Entrada de Mercadoria
            </h4>

            <form onSubmit={handleScan} className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-slate-500 mb-1">EAN ou Código</label>
                <div className="relative">
                  <input
                    ref={inputRef}
                    type="text"
                    value={searchInput}
                    onChange={(e) => setSearchInput(e.target.value)}
                    className="w-full bg-slate-50 border border-slate-200 rounded-xl py-4 pl-12 pr-4 font-mono text-lg focus:outline-none focus:ring-2 focus:ring-blue-500 transition-all"
                    placeholder="Bipe o código..."
                    autoComplete="off"
                  />
                  <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={24} />
                </div>
              </div>

              <div className="flex gap-4">
                <div className="flex-1">
                  <label className="block text-sm font-medium text-slate-500 mb-1">Quantidade</label>
                  <input
                    type="number"
                    min="1"
                    value={manualQty}
                    onChange={(e) => setManualQty(Number(e.target.value))}
                    className="w-full bg-slate-50 border border-slate-200 rounded-xl py-3 px-4 font-bold text-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
                  />
                </div>
                <div className="flex items-end">
                  <button 
                    type="submit"
                    className="bg-blue-600 hover:bg-blue-700 text-white px-8 py-4 rounded-xl font-bold transition-all shadow-lg flex items-center gap-2"
                  >
                    Confirmar
                    <ArrowRight size={18} />
                  </button>
                </div>
              </div>
            </form>

            {errorMsg && (
              <div className="mt-4 p-4 bg-red-50 text-red-600 rounded-lg flex items-center gap-2 animate-bounce">
                <AlertCircle size={20} />
                <span className="font-medium">{errorMsg}</span>
              </div>
            )}
          </div>

          <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex flex-col gap-3">
            <h4 className="font-bold text-slate-700 text-sm">Controle do Lote</h4>
            <button 
              onClick={onPause}
              className="w-full bg-slate-100 hover:bg-slate-200 text-slate-700 font-bold py-3 rounded-xl transition-all flex items-center justify-center gap-2"
            >
              <Save size={18} />
              Pausar / Salvar
            </button>
            <button 
              onClick={() => setShowDiscardConfirm(true)}
              className="w-full bg-red-50 hover:bg-red-100 text-red-600 font-bold py-3 rounded-xl transition-all flex items-center justify-center gap-2"
            >
              <Trash2 size={18} />
              Descartar e Sair
            </button>
          </div>

          {lastScanned && (
            <div className="bg-green-50 p-6 rounded-2xl border border-green-100 animate-in fade-in slide-in-from-bottom-2">
              <h4 className="text-green-800 font-bold mb-2">Último Lido:</h4>
              <p className="text-green-700 font-medium">{lastScanned.description}</p>
              <div className="mt-2 flex justify-between items-end">
                <span className="text-xs text-green-600 font-mono">{lastScanned.ean}</span>
                <span className="text-2xl font-black text-green-800">+{manualQty}</span>
              </div>
            </div>
          )}
        </div>

        {/* List Panel */}
        <div className="lg:col-span-2 bg-white rounded-2xl shadow-sm border border-slate-100 flex flex-col min-h-0">
          <div className="p-4 border-b border-slate-100 bg-slate-50/50 flex justify-between items-center">
            <h4 className="font-bold text-slate-700 uppercase tracking-wider text-xs">Itens Conferidos</h4>
            <span className="text-xs font-semibold text-slate-500">{batch.products.filter(p => p.quantityChecked > 0).length} Itens Diferentes</span>
          </div>
          <div className="flex-1 overflow-y-auto">
            <table className="w-full text-left">
              <thead className="sticky top-0 bg-white shadow-sm">
                <tr className="border-b border-slate-100 text-slate-400 text-xs uppercase font-bold">
                  <th className="px-6 py-4">Produto</th>
                  <th className="px-6 py-4 text-center">EAN</th>
                  <th className="px-6 py-4 text-right">Contagem Total</th>
                  <th className="px-6 py-4 text-center">Excluir</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {batch.products
                  .filter(p => p.quantityChecked > 0)
                  .map((p) => {
                    return (
                      <tr key={p.id} className="hover:bg-slate-50/50 transition-colors group">
                        <td className="px-6 py-4">
                          <p className="font-bold text-slate-800 text-sm line-clamp-1">{p.description}</p>
                          <p className="text-xs text-slate-500">Cód: {p.code}</p>
                        </td>
                        <td className="px-6 py-4 text-center font-mono text-xs text-slate-500">{p.ean}</td>
                        <td className="px-6 py-4 text-right">
                          <span className="inline-block px-3 py-1 bg-blue-50 text-blue-700 rounded-full font-black min-w-[3.5rem] text-center border border-blue-100">
                            {p.quantityChecked}
                          </span>
                        </td>
                        <td className="px-6 py-4 text-center">
                          <button 
                            onClick={() => removeItem(p.id)}
                            title="Remover conferência deste item"
                            className="p-2.5 bg-red-50 hover:bg-red-600 text-red-500 hover:text-white rounded-xl transition-all shadow-sm flex items-center justify-center mx-auto"
                          >
                            <Trash2 size={16} />
                          </button>
                        </td>
                      </tr>
                    );
                  })}
                {batch.products.every(p => p.quantityChecked === 0) && (
                  <tr>
                    <td colSpan={4} className="px-6 py-12 text-center text-slate-400">
                      <div className="flex flex-col items-center gap-2">
                        <Keyboard size={48} className="opacity-20" />
                        <p>Nenhum produto conferido ainda.</p>
                        <p className="text-xs">Bipe um código para começar.</p>
                      </div>
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
          <div className="p-4 bg-slate-50 border-t border-slate-100 flex justify-end">
            <button 
              onClick={onFinish}
              className="bg-slate-900 hover:bg-black text-white px-10 py-3 rounded-xl font-bold transition-all shadow-xl flex items-center gap-2"
            >
              Finalizar Conferência
              <CheckCircle size={20} />
            </button>
          </div>
        </div>
      </div>

      {/* Custom Discard Confirmation Modal */}
      {showDiscardConfirm && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/70 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-md rounded-[32px] shadow-2xl overflow-hidden animate-in zoom-in duration-200 border border-slate-100">
            <div className="p-8 text-center">
              <div className="bg-red-100 w-20 h-20 rounded-full flex items-center justify-center mx-auto mb-6 text-red-600">
                <AlertTriangle size={40} />
              </div>
              <h3 className="text-2xl font-black text-slate-800 uppercase tracking-tight mb-3">Confirmar Descarte?</h3>
              <p className="text-slate-500 font-medium leading-relaxed">
                Esta ação removerá todo o progresso físico deste lote e retornará para a tela de importação. Deseja continuar?
              </p>

              <div className="mt-10 flex flex-col gap-3">
                <button 
                  onClick={handleConfirmDiscard}
                  className="w-full bg-red-600 hover:bg-red-700 text-white py-5 rounded-2xl font-black uppercase tracking-widest text-xs transition-all shadow-xl shadow-red-500/20 flex items-center justify-center gap-2"
                >
                  SIM, Descartar e Sair
                </button>
                <button 
                  onClick={() => setShowDiscardConfirm(false)}
                  className="w-full bg-white border-2 border-slate-100 hover:bg-slate-50 text-slate-600 py-5 rounded-2xl font-black uppercase tracking-widest text-xs transition-all flex items-center justify-center gap-2"
                >
                  NÃO, Manter Conferência
                </button>
              </div>
            </div>
            <div className="bg-slate-50 p-4 text-center border-t border-slate-100">
               <button 
                onClick={() => setShowDiscardConfirm(false)}
                className="text-slate-400 hover:text-slate-600 text-[10px] font-bold uppercase tracking-widest flex items-center justify-center gap-1 mx-auto"
              >
                <X size={14} /> Fechar
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default BlindCheck;

import React from 'react';
import { 
  LayoutDashboard, 
  FileUp, 
  ClipboardCheck, 
  History, 
  Users, 
  LogOut,
  PackageCheck,
  Shield,
  PauseCircle,
  Building2
} from 'lucide-react';
import { User, UserRole } from '../types';

interface LayoutProps {
  user: User;
  onLogout: () => void;
  activeTab: string;
  setActiveTab: (tab: string) => void;
  children: React.ReactNode;
  pausedCount?: number;
}

const Layout: React.FC<LayoutProps> = ({ user, onLogout, activeTab, setActiveTab, children, pausedCount = 0 }) => {
  const menuItems = [
    { id: 'dashboard', label: 'Dashboard', icon: LayoutDashboard, roles: [UserRole.ADMIN, UserRole.SUPERVISOR, UserRole.CONFERENTE] },
    { id: 'upload', label: 'Importar XML', icon: FileUp, roles: [UserRole.ADMIN, UserRole.SUPERVISOR, UserRole.CONFERENTE] },
    { id: 'checking', label: 'Conferência', icon: ClipboardCheck, roles: [UserRole.ADMIN, UserRole.SUPERVISOR, UserRole.CONFERENTE] },
    { id: 'paused', label: 'Pausadas', icon: PauseCircle, roles: [UserRole.ADMIN, UserRole.SUPERVISOR, UserRole.CONFERENTE], badge: pausedCount },
    { id: 'history', label: 'Histórico', icon: History, roles: [UserRole.ADMIN, UserRole.SUPERVISOR, UserRole.CONFERENTE] },
    { id: 'branches', label: 'Filiais', icon: Building2, roles: [UserRole.ADMIN, UserRole.SUPERVISOR] },
    { id: 'admin', label: 'Usuários & Perfis', icon: Users, roles: [UserRole.ADMIN, UserRole.SUPERVISOR] },
  ];

  return (
    <div className="flex h-screen bg-gray-50 overflow-hidden">
      {/* Sidebar */}
      <aside className="w-64 bg-slate-900 text-white flex flex-col shadow-xl z-20">
        <div className="p-6 flex items-center gap-3 border-b border-slate-800">
          <PackageCheck className="text-blue-400" size={32} />
          <span className="font-bold text-xl tracking-tight">CheckMaster</span>
        </div>

        <nav className="flex-1 mt-6 px-4 space-y-2">
          {menuItems
            .filter(item => item.roles.includes(user.role))
            .map(item => (
              <button
                key={item.id}
                onClick={() => setActiveTab(item.id)}
                className={`w-full flex items-center justify-between px-4 py-3 rounded-lg transition-all ${
                  activeTab === item.id 
                  ? 'bg-blue-600 text-white shadow-lg' 
                  : 'text-slate-400 hover:bg-slate-800 hover:text-white'
