import React, { useState, useEffect, useRef } from 'react';
import { 
  Scan, 
  Keyboard, 
  Search, 
  CheckCircle, 
  ArrowRight,
  AlertCircle,
  Package,
  Save,
  Trash2,
  X,
  AlertTriangle
} from 'lucide-react';
import { ConferenceBatch, NFeProduct } from '../types';

interface BlindCheckProps {
  batch: ConferenceBatch;
  onUpdateBatch: (batch: ConferenceBatch) => void;
  onFinish: () => void;
  onCancel: () => void;
  onPause: () => void;
}

const BlindCheck: React.FC<BlindCheckProps> = ({ batch, onUpdateBatch, onFinish, onCancel, onPause }) => {
  const [searchInput, setSearchInput] = useState('');
  const [manualQty, setManualQty] = useState<number>(1);
  const [errorMsg, setErrorMsg] = useState('');
  const [lastScanned, setLastScanned] = useState<NFeProduct | null>(null);
  const [showDiscardConfirm, setShowDiscardConfirm] = useState(false);

  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    inputRef.current?.focus();
  }, []);

  const totalExpected = batch.products.reduce((acc, p) => acc + p.quantityExpected, 0);
  const totalChecked = batch.products.reduce((acc, p) => acc + p.quantityChecked, 0);
  const progress = Math.min(Math.round((totalChecked / totalExpected) * 100), 100);

  const formatNumber = (num: number) => {
    return num.toLocaleString('pt-BR', { 
      minimumFractionDigits: 0, 
      maximumFractionDigits: 3 
    });
  };

  const handleScan = (e: React.FormEvent) => {
    e.preventDefault();
    if (!searchInput.trim()) return;

    const term = searchInput.trim().toUpperCase();
    const productIndex = batch.products.findIndex(p => 
      p.ean === term || p.code.toUpperCase() === term
    );

    if (productIndex === -1) {
      setErrorMsg(`Produto "${term}" não encontrado no lote.`);
      setTimeout(() => setErrorMsg(''), 3000);
    } else {
      const updatedProducts = [...batch.products];
      // Incrementa a quantidade (suporta decimais agora)
      updatedProducts[productIndex].quantityChecked = parseFloat((updatedProducts[productIndex].quantityChecked + manualQty).toFixed(3));

      onUpdateBatch({ ...batch, products: updatedProducts });
      setLastScanned(updatedProducts[productIndex]);
      setSearchInput('');
      setManualQty(1);
    }
    inputRef.current?.focus();
  };

  const removeItem = (id: string) => {
    const updatedProducts = batch.products.map(p => 
      p.id === id ? { ...p, quantityChecked: 0 } : p
    );
    onUpdateBatch({ ...batch, products: updatedProducts });
  };

  const handleConfirmDiscard = () => {
    setShowDiscardConfirm(false);
    onCancel();
  };

  return (
    <div className="max-w-6xl mx-auto flex flex-col h-full gap-6 pb-20">
      {/* Top Status Bar */}
      <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex items-center justify-between">
        <div className="flex items-center gap-6">
          <div className="bg-blue-50 p-4 rounded-xl">
            <Package className="text-blue-600" size={32} />
          </div>
          <div>
            <h3 className="text-xl font-bold text-slate-800">Conferência em Lote: {batch.notes.length} Notas</h3>
            <div className="flex items-center gap-2 text-slate-500 text-sm mt-1">
              <Save size={14} className="text-green-500" />
              <span>Salvamento Automático Ativo</span>
            </div>
          </div>
        </div>

        <div className="flex flex-col items-end gap-2 w-64">
          <div className="flex justify-between w-full text-sm font-semibold text-slate-600">
            <span>Progresso da Conferência</span>
            <span>{progress}%</span>
          </div>
          <div className="w-full bg-slate-100 h-3 rounded-full overflow-hidden">
            <div 
              className={`h-full transition-all duration-500 ${progress >= 100 ? 'bg-green-500' : 'bg-blue-500'}`}
              style={{ width: `${progress}%` }}
            ></div>
          </div>
        </div>
      </div>

      {/* Main Checking Area */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 flex-1 min-h-0">
        {/* Input Panel */}
        <div className="lg:col-span-1 flex flex-col gap-6">
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
            <h4 className="font-bold text-slate-700 mb-4 flex items-center gap-2">
              <Scan size={20} className="text-blue-500" />
              Entrada de Mercadoria
            </h4>

            <form onSubmit={handleScan} className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-slate-500 mb-1">EAN ou Código</label>
                <div className="relative">
                  <input
                    ref={inputRef}
                    type="text"
                    value={searchInput}
                    onChange={(e) => setSearchInput(e.target.value)}
                    className="w-full bg-slate-50 border border-slate-200 rounded-xl py-4 pl-12 pr-4 font-mono text-lg focus:outline-none focus:ring-2 focus:ring-blue-500 transition-all"
                    placeholder="Bipe o código..."
                    autoComplete="off"
                  />
                  <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={24} />
                </div>
              </div>

              <div className="flex gap-4">
                <div className="flex-1">
                  <label className="block text-sm font-medium text-slate-500 mb-1">Quantidade</label>
                  <input
                    type="number"
                    min="0.001"
                    step="0.001"
                    value={manualQty}
                    onChange={(e) => setManualQty(parseFloat(e.target.value) || 0)}
