    window.print();
  };

  const handleDownloadPDF = async () => {
    const reportElement = document.getElementById('printable-report');
    if (!reportElement) return;

    setIsExporting(true);
    try {
      // Capturamos o elemento com escala alta para qualidade
      const canvas = await html2canvas(reportElement, {
        scale: 2,
        useCORS: true,
        logging: false,
        backgroundColor: '#ffffff',
        windowWidth: 1200 // Fixamos uma largura de captura para consistência
      });

      const imgData = canvas.toDataURL('image/jpeg', 0.95);
      const pdf = new jsPDF({
        orientation: 'portrait',
        unit: 'mm',
        format: 'a4'
      });

      const pdfWidth = pdf.internal.pageSize.getWidth();
      const pdfHeight = pdf.internal.pageSize.getHeight();

      // Calculamos as dimensões da imagem no PDF mantendo a proporção
      const imgWidth = pdfWidth - 20; // 10mm de margem em cada lado
      const imgHeight = (canvas.height * imgWidth) / canvas.width;

      let heightLeft = imgHeight;
      let position = 10; // Margem superior inicial

      // Adicionamos a primeira página
