              <FileText size={20} />
            </div>
            <div>
              <span className="font-black text-slate-800 text-sm uppercase tracking-tight">Visualização de Relatório</span>
              <p className="text-[10px] text-slate-400 font-bold uppercase">Lote #{batch.id}</p>
            </div>
          </div>

          <div className="flex items-center gap-2">
            <button 
              onClick={handleDownloadPDF}
              disabled={isExporting}
              className="flex items-center gap-2 bg-slate-100 hover:bg-slate-200 text-slate-700 px-4 py-2.5 rounded-xl font-bold transition-all text-xs disabled:opacity-50"
            >
              {isExporting ? <Loader2 size={16} className="animate-spin" /> : <Download size={16} />}
              <span className="hidden sm:inline">Download PDF</span>
            </button>
            <button 
              onClick={handleNativePrint}
              className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-4 py-2.5 rounded-xl font-bold transition-all text-xs shadow-lg shadow-blue-500/20"
            >
              <Printer size={16} />
              <span className="hidden sm:inline">Imprimir Relatório</span>
