            >
              {isPreviewing ? <Loader2 size={16} className="animate-spin" /> : <Eye size={16} />}
              <span className="hidden sm:inline">Visualizar PDF</span>
            </button>
            <button 
              onClick={handleDownloadPDF}
              disabled={isPreviewing || isExporting}
              className="flex items-center gap-2 bg-slate-100 hover:bg-slate-200 text-slate-700 px-4 py-2.5 rounded-xl font-bold transition-all text-xs disabled:opacity-50"
            >
              {isExporting ? <Loader2 size={16} className="animate-spin" /> : <Download size={16} />}
              <span className="hidden sm:inline">Salvar Arquivo</span>
            </button>
            <button 
              onClick={handleNativePrint}
              disabled={isPreviewing || isExporting}
              className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-4 py-2.5 rounded-xl font-bold transition-all text-xs shadow-lg shadow-blue-500/20"
            >
              <Printer size={16} />
              <span className="hidden sm:inline">Imprimir Agora</span>
              <span className="sm:hidden">Imprimir</span>
            </button>
            <div className="w-px h-6 bg-slate-200 mx-2"></div>
            <button 
              onClick={onClose}
              className="p-2.5 hover:bg-red-50 hover:text-red-500 rounded-xl transition-all text-slate-400"
