import { jsPDF } from 'jspdf';
import html2canvas from 'html2canvas';

interface ReportModalProps {
  batch: ConferenceBatch;
  onClose: () => void;
}

const ReportModal: React.FC<ReportModalProps> = ({ batch, onClose }) => {
  const [isExporting, setIsExporting] = useState(false);
  const [isPreviewing, setIsPreviewing] = useState(false);

  const formatNumber = (num: number) => {
    return num.toLocaleString('pt-BR', { 
      minimumFractionDigits: 0, 
      maximumFractionDigits: 3 
    });
  };

  // Função centralizada para gerar o objeto PDF com margens de 1,27cm (12.7mm)
  const generatePDFObject = async (element: HTMLElement) => {
    const originalHeight = element.style.height;
    const originalMaxHeight = element.style.maxHeight;
    const originalOverflow = element.style.overflow;
    const originalWidth = element.style.width;

    // Força expansão total para captura fiel
    element.style.height = 'auto';
    element.style.maxHeight = 'none';
    element.style.overflow = 'visible';
    element.style.width = '1000px'; 

    try {
      const canvas = await html2canvas(element, {
        scale: 2,
        useCORS: true,
        logging: false,
        backgroundColor: '#ffffff',
        width: 1000,
        height: element.scrollHeight,
        windowWidth: 1000,
        scrollY: 0
      });

      const imgData = canvas.toDataURL('image/jpeg', 0.95);
      const pdf = new jsPDF({
        orientation: 'portrait',
        unit: 'mm',
        format: 'a4'
      });

      const pdfWidth = pdf.internal.pageSize.getWidth();
      const pdfHeight = pdf.internal.pageSize.getHeight();

      // Margens padrão: 1,27 cm = 12,7 mm
      const margin = 12.7;
      const imgWidth = pdfWidth - (margin * 2); 
      const imgHeight = (canvas.height * imgWidth) / canvas.width;

      let heightLeft = imgHeight;
      let position = margin;

      // Primeira página
      pdf.addImage(imgData, 'JPEG', margin, position, imgWidth, imgHeight);
      heightLeft -= (pdfHeight - (margin * 2));

      // Páginas subsequentes
      while (heightLeft > 0) {
        position = heightLeft - imgHeight + margin;
        pdf.addPage();
        pdf.addImage(imgData, 'JPEG', margin, position, imgWidth, imgHeight);
        heightLeft -= (pdfHeight - (margin * 2));
      }

      return pdf;
    } finally {
      element.style.height = originalHeight;
      element.style.maxHeight = originalMaxHeight;
      element.style.overflow = originalOverflow;
      element.style.width = originalWidth;
    }
  };

  const handlePreviewPDF = async () => {
    const reportElement = document.getElementById('printable-report');
    if (!reportElement) return;

    setIsPreviewing(true);
    try {
      const pdf = await generatePDFObject(reportElement);
      const blob = pdf.output('blob');
      const url = URL.createObjectURL(blob);
      const win = window.open(url, '_blank');
      if (!win) {
        alert('O navegador bloqueou a abertura da nova aba. Por favor, autorize pop-ups.');
      }
    } catch (error) {
      console.error('Erro ao visualizar PDF:', error);
      alert('Erro ao gerar visualização do PDF.');
    } finally {
      setIsPreviewing(false);
    }
  };

