          {/* Área de Assinaturas */}
          <div className="mt-32 grid grid-cols-2 gap-20 pt-10 border-t border-slate-100">
            <div className="text-center">
              <div className="h-px bg-slate-200 w-full mb-4"></div>
              <p className="text-xs font-bold text-slate-800 mb-1 uppercase tracking-tight">{batch.conferenteName}</p>
              <p className="text-[9px] text-slate-400 font-black uppercase tracking-[0.2em]">Assinatura do Conferente</p>
            </div>
            <div className="text-center">
              <div className="h-px bg-slate-200 w-full mb-4"></div>
              <p className="text-xs font-bold text-slate-800 mb-1 uppercase tracking-tight">{batch.supervisorName || '________________________'}</p>
              <p className="text-[9px] text-slate-400 font-black uppercase tracking-[0.2em]">Assinatura do Supervisor</p>
            </div>
          </div>

          {/* Rodapé Final */}
          <div className="mt-20 text-center opacity-30">
            <div className="flex items-center justify-center gap-4 mb-4">
              <div className="h-px bg-slate-200 flex-1"></div>
              <Package size={16} className="text-slate-400" />
              <div className="h-px bg-slate-200 flex-1"></div>
            </div>
            <p className="text-[9px] text-slate-500 font-bold uppercase tracking-[0.3em]">
              Gerado via CheckMaster Logistics Cloud em {new Date().toLocaleString('pt-BR')}
            </p>
          </div>
        </div>
      </div>
    </div>
  );
};

