import React, { useState, useMemo } from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, 
  Cell, PieChart, Pie
} from 'recharts';
import { ConferenceBatch, UserRole } from '../types';
import { 
  CheckCircle2, 
  AlertTriangle, 
  Calendar, 
  Package, 
  ClipboardCheck, 
  TrendingUp,
  FilterX,
  Users,
  Trophy,
  History as HistoryIcon,
  ArrowRight
} from 'lucide-react';

interface DashboardProps {
  batches: ConferenceBatch[];
}

const Dashboard: React.FC<DashboardProps> = ({ batches }) => {
  const [startDate, setStartDate] = useState<string>(() => {
    const d = new Date();
    d.setDate(d.getDate() - 7);
    return d.toISOString().split('T')[0];
  });
  const [endDate, setEndDate] = useState<string>(new Date().toISOString().split('T')[0]);

  const filteredBatches = useMemo(() => {
    return batches.filter(b => {
      const bDate = (b.endTime || b.startTime).split('T')[0];
      return bDate >= startDate && bDate <= endDate;
    });
  }, [batches, startDate, endDate]);

  const stats = useMemo(() => {
    const totalConferences = filteredBatches.length;
    const totalDivergences = filteredBatches.filter(b => 
      b.products.some(p => parseFloat(p.quantityExpected.toFixed(3)) !== parseFloat(p.quantityChecked.toFixed(3)))
    ).length;

    const totalItems = filteredBatches.reduce((acc, b) => acc + b.products.length, 0);
    const accuracyRate = totalConferences > 0 ? ((totalConferences - totalDivergences) / totalConferences) * 100 : 100;

    return [
      { label: 'Lotes Concluídos', value: totalConferences, icon: ClipboardCheck, color: 'text-blue-600', bg: 'bg-blue-50' },
      { label: 'SKUs Processados', value: totalItems, icon: Package, color: 'text-indigo-600', bg: 'bg-indigo-50' },
      { label: 'Índice de Acuracidade', value: `${accuracyRate.toFixed(1)}%`, icon: CheckCircle2, color: 'text-green-600', bg: 'bg-green-50' },
      { label: 'Lotes Divergentes', value: totalDivergences, icon: AlertTriangle, color: 'text-orange-600', bg: 'bg-orange-50' },
    ];
  }, [filteredBatches]);

  const ranking = useMemo(() => {
    const map: Record<string, { count: number, accuracy: number }> = {};
    filteredBatches.forEach(b => {
      if (!map[b.conferenteName]) map[b.conferenteName] = { count: 0, accuracy: 0 };
      map[b.conferenteName].count += 1;
      const hasDiv = b.products.some(p => parseFloat(p.quantityExpected.toFixed(3)) !== parseFloat(p.quantityChecked.toFixed(3)));
      if (!hasDiv) map[b.conferenteName].accuracy += 1;
    });

    return Object.entries(map)
      .map(([name, data]) => ({
        name,
        count: data.count,
        rate: (data.accuracy / data.count) * 100
      }))
      .sort((a, b) => b.count - a.count)
      .slice(0, 5);
  }, [filteredBatches]);

  const COLORS = ['#2563eb', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6'];

  return (
    <div className="space-y-6 animate-in fade-in duration-500 max-w-7xl mx-auto">
      {/* Filtros Estratégicos */}
      <div className="bg-white p-6 rounded-[32px] shadow-sm border border-slate-100 flex flex-col md:flex-row items-end gap-6">
        <div className="flex-1 grid grid-cols-1 sm:grid-cols-2 gap-4 w-full">
          <div>
            <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1 flex items-center gap-2">
              <Calendar size={14} className="text-blue-500" /> Início do Período
            </label>
            <input 
              type="date" 
              value={startDate}
              onChange={(e) => setStartDate(e.target.value)}
              className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-5 py-3 text-sm font-bold text-slate-700 focus:ring-2 focus:ring-blue-500 outline-none transition-all"
            />
          </div>
          <div>
            <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1 flex items-center gap-2">
              <Calendar size={14} className="text-blue-500" /> Fim do Período
            </label>
            <input 
              type="date" 
              value={endDate}
              onChange={(e) => setEndDate(e.target.value)}
              className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-5 py-3 text-sm font-bold text-slate-700 focus:ring-2 focus:ring-blue-500 outline-none transition-all"
            />
          </div>
        </div>
        <button 
          onClick={() => {
            setStartDate("");
            setEndDate(new Date().toISOString().split('T')[0]);
          }}
          className="bg-slate-100 hover:bg-slate-200 text-slate-500 p-4 rounded-2xl transition-all border border-slate-200"
          title="Limpar Filtros"
        >
          <FilterX size={20} />
        </button>
      </div>

      {/* KPIs de Gestão */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
        {stats.map((stat, i) => (
          <div key={i} className="bg-white p-6 rounded-[32px] shadow-sm border border-slate-100 hover:shadow-lg transition-all border-b-4 border-b-transparent hover:border-b-blue-500">
            <div className="flex items-center justify-between mb-4">
              <div className={`${stat.bg} p-3 rounded-2xl`}>
                <stat.icon className={stat.color} size={24} />
              </div>
              <TrendingUp size={16} className="text-slate-200" />
            </div>
            <p className="text-slate-400 text-[10px] font-black uppercase tracking-[0.15em]">{stat.label}</p>
            <p className="text-3xl font-black text-slate-800 mt-1 tracking-tight">{stat.value}</p>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Gráfico de Tendência */}
        <div className="lg:col-span-2 bg-white p-8 rounded-[40px] shadow-sm border border-slate-100">
          <div className="flex items-center justify-between mb-8">
            <div>
              <h3 className="text-lg font-black text-slate-800 tracking-tight uppercase">Fluxo de Conferência</h3>
              <p className="text-slate-400 text-xs font-medium">Histórico de lotes processados por dia</p>
            </div>
            <div className="bg-blue-50 text-blue-600 p-2 px-4 rounded-full text-[10px] font-black uppercase tracking-widest">
              Produtividade
            </div>
          </div>

          <div className="h-[300px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={ranking.map(r => ({ name: r.name.split(' ')[0], qty: r.count }))}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 10, fontWeight: 700}} dy={10} />
                <YAxis axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 10, fontWeight: 700}} />
                <Tooltip cursor={{fill: '#f8fafc'}} contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)' }} />
                <Bar dataKey="qty" fill="#2563eb" radius={[8, 8, 0, 0]} barSize={32} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* Ranking de Conferentes */}
        <div className="bg-white p-8 rounded-[40px] shadow-sm border border-slate-100 flex flex-col">
          <div className="flex items-center gap-3 mb-8">
            <div className="bg-yellow-100 p-3 rounded-2xl">
              <Trophy className="text-yellow-600" size={24} />
            </div>
            <div>
              <h3 className="text-lg font-black text-slate-800 tracking-tight uppercase">Top Performance</h3>
              <p className="text-slate-400 text-xs font-medium">Lotes por Conferente</p>
            </div>
          </div>

          <div className="flex-1 space-y-4">
            {ranking.map((item, idx) => (
              <div key={idx} className="flex items-center justify-between p-4 bg-slate-50 rounded-[20px] border border-slate-100 transition-transform hover:scale-[1.02]">
                <div className="flex items-center gap-3">
                  <div className="w-8 h-8 rounded-full bg-white border-2 border-slate-200 flex items-center justify-center text-xs font-black text-slate-400">
                    {idx + 1}
                  </div>
                  <div>
                    <p className="text-xs font-black text-slate-800 uppercase tracking-tight">{item.name}</p>
                    <p className="text-[10px] text-slate-400 font-bold uppercase">{item.rate.toFixed(0)}% acuracidade</p>
                  </div>
                </div>
                <div className="text-right">
                  <p className="text-lg font-black text-blue-600">{item.count}</p>
                  <p className="text-[8px] text-slate-400 font-black uppercase tracking-widest">Lotes</p>
                </div>
              </div>
            ))}
            {ranking.length === 0 && (
              <div className="h-full flex flex-col items-center justify-center text-slate-300 gap-4 opacity-40">
                <Users size={48} />
                <p className="text-[10px] font-black uppercase tracking-widest text-center">Sem dados de<br/>performance no período</p>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState, useEffect, useRef } from 'react';
import { 
  Scan, 
  Search, 
  CheckCircle, 
  ArrowRight,
  AlertCircle,
  Package,
  Save,
  Trash2,
  X,
  AlertTriangle,
  History,
  Zap
} from 'lucide-react';
import { ConferenceBatch, NFeProduct } from '../types';

interface BlindCheckProps {
  batch: ConferenceBatch;
  onUpdateBatch: (batch: ConferenceBatch) => void;
  onFinish: () => void;
  onCancel: () => void;
  onPause: () => void;
}

const BlindCheck: React.FC<BlindCheckProps> = ({ batch, onUpdateBatch, onFinish, onCancel, onPause }) => {
  const [searchInput, setSearchInput] = useState('');
  const [manualQty, setManualQty] = useState<number>(1);
  const [errorMsg, setErrorMsg] = useState('');
  const [lastScanned, setLastScanned] = useState<NFeProduct | null>(null);
  const [showDiscardConfirm, setShowDiscardConfirm] = useState(false);
  const [scanHistory, setScanHistory] = useState<NFeProduct[]>([]);

  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    inputRef.current?.focus();
  }, []);

  const totalExpected = batch.products.reduce((acc, p) => acc + p.quantityExpected, 0);
  const totalChecked = batch.products.reduce((acc, p) => acc + p.quantityChecked, 0);
  const progress = Math.min(Math.round((totalChecked / totalExpected) * 100), 100);

  const formatNumber = (num: number) => {
    return num.toLocaleString('pt-BR', { 
      minimumFractionDigits: 0, 
      maximumFractionDigits: 3 
    });
  };

  const handleScan = (e: React.FormEvent) => {
    e.preventDefault();
    if (!searchInput.trim()) return;

    const term = searchInput.trim().toUpperCase();
    const productIndex = batch.products.findIndex(p => 
      p.ean === term || p.code.toUpperCase() === term
    );

    if (productIndex === -1) {
      setErrorMsg(`ITEM "${term}" NÃO ENCONTRADO NO LOTE`);
      setTimeout(() => setErrorMsg(''), 3000);
      // Feedback tátil/sonoro simulado seria aqui
    } else {
      const updatedProducts = [...batch.products];
      updatedProducts[productIndex].quantityChecked = parseFloat((updatedProducts[productIndex].quantityChecked + manualQty).toFixed(3));

      onUpdateBatch({ ...batch, products: updatedProducts });
      setLastScanned(updatedProducts[productIndex]);
      setScanHistory(prev => [updatedProducts[productIndex], ...prev].slice(0, 5));
      setSearchInput('');
      setManualQty(1);
    }
    inputRef.current?.focus();
  };

  const removeItem = (id: string) => {
    const updatedProducts = batch.products.map(p => 
      p.id === id ? { ...p, quantityChecked: 0 } : p
    );
    onUpdateBatch({ ...batch, products: updatedProducts });
  };

  return (
    <div className="max-w-7xl mx-auto flex flex-col h-full gap-6 pb-20 animate-in fade-in duration-300">

      {/* Workspace de Operação */}
      <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 flex-1 min-h-0">

        {/* Painel de Comando (Esquerda) */}
        <div className="lg:col-span-4 flex flex-col gap-6">
          <div className="bg-slate-900 text-white p-8 rounded-[40px] shadow-2xl relative overflow-hidden group">
            <div className="absolute top-0 right-0 p-8 opacity-10">
              <Zap size={120} />
            </div>

            <h4 className="font-black text-[10px] uppercase tracking-[0.3em] text-blue-400 mb-6 flex items-center gap-2">
              <Scan size={14} /> Terminal de Bipagem
            </h4>

            <form onSubmit={handleScan} className="space-y-6 relative z-10">
              <div>
                <label className="block text-[10px] font-black text-slate-500 uppercase tracking-widest mb-2 ml-1">Leitura de Código (EAN/CÓD)</label>
                <div className="relative">
                  <input
                    ref={inputRef}
                    type="text"
                    value={searchInput}
                    onChange={(e) => setSearchInput(e.target.value)}
                    className="w-full bg-slate-800 border-2 border-slate-700 rounded-[24px] py-5 pl-14 pr-4 font-mono text-xl focus:outline-none focus:border-blue-500 focus:ring-4 focus:ring-blue-500/20 transition-all text-blue-100"
                    placeholder="Bipe agora..."
                    autoComplete="off"
                  />
                  <Search className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-500" size={24} />
                </div>
              </div>

              <div className="flex gap-4">
                <div className="w-1/3">
                  <label className="block text-[10px] font-black text-slate-500 uppercase tracking-widest mb-2 ml-1">Quantidade</label>
                  <input
                    type="number"
                    min="0.001"
                    step="0.001"
                    value={manualQty}
                    onChange={(e) => setManualQty(parseFloat(e.target.value) || 0)}
                    className="w-full bg-slate-800 border-2 border-slate-700 rounded-[24px] py-4 px-4 font-black text-xl text-center focus:outline-none focus:border-blue-500 text-white"
                  />
                </div>
                <div className="flex-1 flex items-end">
                  <button 
                    type="submit"
                    className="w-full bg-blue-600 hover:bg-blue-500 text-white py-4 rounded-[24px] font-black uppercase tracking-widest text-xs transition-all shadow-xl shadow-blue-600/20 flex items-center justify-center gap-2"
                  >
                    Confirmar <ArrowRight size={18} />
                  </button>
                </div>
              </div>
            </form>

            {errorMsg && (
              <div className="mt-6 p-4 bg-red-500/20 text-red-400 border border-red-500/30 rounded-2xl flex items-center gap-3 animate-pulse">
                <AlertTriangle size={20} />
                <span className="font-black text-[10px] uppercase tracking-widest">{errorMsg}</span>
              </div>
            )}
          </div>

          {/* Status Real-time do Lote */}
          <div className="bg-white p-8 rounded-[40px] shadow-sm border border-slate-100">
            <div className="flex justify-between items-end mb-4">
              <div>
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Acuracidade do Lote</p>
                <h3 className="text-3xl font-black text-slate-800">{progress}%</h3>
              </div>
              <div className="text-right">
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Total Lido</p>
                <p className="text-sm font-black text-blue-600">{formatNumber(totalChecked)} / {formatNumber(totalExpected)}</p>
              </div>
            </div>
            <div className="w-full bg-slate-100 h-4 rounded-full overflow-hidden">
              <div 
                className={`h-full transition-all duration-700 ease-out ${progress >= 100 ? 'bg-green-500' : 'bg-blue-600'}`}
                style={{ width: `${progress}%` }}
              ></div>
            </div>
          </div>

          {/* Últimos Movimentos */}
          <div className="flex-1 bg-slate-50 p-6 rounded-[40px] border border-slate-200/50 flex flex-col">
            <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-4 flex items-center gap-2">
              <History size={14} /> Histórico de Leitura
            </h4>
            <div className="space-y-3 overflow-y-auto max-h-[300px] pr-2">
              {scanHistory.map((item, idx) => (
                <div key={idx} className={`p-4 rounded-2xl bg-white border border-slate-100 shadow-sm flex justify-between items-center animate-in slide-in-from-left-2 duration-300 opacity-${100 - (idx * 15)}`}>
                  <div className="max-w-[70%]">
                    <p className="text-[10px] font-black text-slate-800 uppercase truncate">{item.description}</p>
                    <p className="text-[9px] text-slate-400 font-mono mt-0.5">{item.ean}</p>
                  </div>
                  <div className="bg-blue-50 px-3 py-1 rounded-full text-[10px] font-black text-blue-600">
                    OK
                  </div>
                </div>
              ))}
              {scanHistory.length === 0 && (
                <div className="flex flex-col items-center justify-center py-10 opacity-20 grayscale">
                  <Scan size={40} className="mb-2" />
                  <p className="text-[10px] font-black uppercase tracking-widest text-center">Aguardando primeira leitura...</p>
                </div>
              )}
            </div>
          </div>
        </div>

        {/* Lista de Conferência (Direita) */}
        <div className="lg:col-span-8 bg-white rounded-[48px] shadow-sm border border-slate-100 flex flex-col min-h-0 overflow-hidden">
          <div className="px-8 py-6 border-b border-slate-100 bg-slate-50/50 flex justify-between items-center">
            <div className="flex items-center gap-4">
              <div className="bg-blue-600 p-2 rounded-xl text-white">
                <Package size={20} />
              </div>
              <div>
                <h4 className="font-black text-slate-800 uppercase tracking-tight text-sm">Itens no Lote</h4>
                <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">Resumo Operacional de SKU</p>
              </div>
            </div>
            <div className="flex items-center gap-3">
               <button 
                onClick={onPause}
                className="bg-white border border-slate-200 hover:bg-slate-50 text-slate-600 px-5 py-2.5 rounded-2xl font-black text-[10px] uppercase tracking-widest transition-all flex items-center gap-2"
              >
                <Save size={14} /> Pausar
              </button>
              <button 
                onClick={() => setShowDiscardConfirm(true)}
                className="bg-red-50 hover:bg-red-100 text-red-600 px-5 py-2.5 rounded-2xl font-black text-[10px] uppercase tracking-widest transition-all flex items-center gap-2"
              >
                <Trash2 size={14} /> Descartar
              </button>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto">
            <table className="w-full text-left border-separate border-spacing-0">
              <thead className="sticky top-0 bg-white/90 backdrop-blur-md z-10">
                <tr className="text-slate-400 text-[9px] uppercase font-black tracking-widest border-b border-slate-100">
                  <th className="px-8 py-5">Produto / EAN</th>
                  <th className="px-8 py-5 text-center">Contagem Atual</th>
                  <th className="px-8 py-5 text-right">Ações</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {batch.products
                  .filter(p => p.quantityChecked > 0)
                  .sort((a, b) => b.quantityChecked - a.quantityChecked)
                  .map((p) => (
                    <tr key={p.id} className="hover:bg-slate-50/80 transition-colors group">
                      <td className="px-8 py-6">
                        <p className="font-black text-slate-800 text-xs uppercase tracking-tight line-clamp-1">{p.description}</p>
                        <p className="text-[10px] text-slate-400 font-mono mt-1">COD: {p.code} | EAN: {p.ean}</p>
                      </td>
                      <td className="px-8 py-6 text-center">
                        <span className="inline-block px-5 py-2 bg-blue-50 text-blue-700 rounded-[14px] font-black text-sm min-w-[5rem] border border-blue-100/50">
                          {formatNumber(p.quantityChecked)}
                        </span>
                      </td>
                      <td className="px-8 py-6 text-right">
                        <button 
                          onClick={() => removeItem(p.id)}
                          className="p-3 bg-slate-50 hover:bg-red-50 text-slate-400 hover:text-red-500 rounded-2xl transition-all inline-flex items-center justify-center"
                        >
                          <Trash2 size={18} />
                        </button>
                      </td>
                    </tr>
                  ))}
                {batch.products.every(p => p.quantityChecked === 0) && (
                  <tr>
                    <td colSpan={3} className="px-8 py-32 text-center">
                      <div className="flex flex-col items-center gap-4 grayscale opacity-20">
                        <Scan size={80} className="animate-pulse" />
                        <h5 className="font-black text-xl uppercase tracking-widest">Pronto para bípagem</h5>
                        <p className="text-xs font-bold uppercase tracking-widest">O lote está aguardando as primeiras mercadorias</p>
                      </div>
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>

          <div className="px-8 py-8 bg-slate-50 border-t border-slate-100 flex justify-between items-center">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">
              Total de Itens Diferentes Lido: {batch.products.filter(p => p.quantityChecked > 0).length}
            </p>
            <button 
              onClick={onFinish}
              className="bg-slate-900 hover:bg-black text-white px-12 py-4 rounded-[24px] font-black uppercase tracking-widest text-[11px] transition-all shadow-2xl flex items-center gap-3 transform hover:scale-105 active:scale-95"
            >
              Finalizar Conferência <CheckCircle size={20} />
            </button>
          </div>
        </div>
      </div>

      {/* Modal de Descarte */}
      {showDiscardConfirm && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/80 backdrop-blur-xl animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-md rounded-[48px] shadow-2xl p-10 animate-in zoom-in duration-200 text-center">
            <div className="bg-red-100 w-24 h-24 rounded-full flex items-center justify-center mx-auto mb-8 text-red-600">
              <AlertTriangle size={48} />
            </div>
