import React, { useState, useEffect } from 'react';
import { X, Download, FileText, CheckCircle2, AlertTriangle, Package, Loader2, User, Eye, Hash, MapPin } from 'lucide-react';
import { ConferenceBatch, Branch } from '../types';
import { INITIAL_BRANCHES } from '../constants';
import { jsPDF } from 'jspdf';
import html2canvas from 'html2canvas';

interface ReportModalProps {
  batch: ConferenceBatch;
  onClose: () => void;
}

const ReportModal: React.FC<ReportModalProps> = ({ batch, onClose }) => {
  const [isExporting, setIsExporting] = useState(false);
  const [isPreviewing, setIsPreviewing] = useState(false);

  // Busca o nome da filial de destino baseada no CNPJ (ou assume a primeira nota)
  const branchName = INITIAL_BRANCHES.find(b => b.cnpj === batch.notes[0]?.vendorCnpj)?.name || 'FILIAL PADRÃO';

  const formatNumber = (num: number) => {
    return num.toLocaleString('pt-BR', { 
      minimumFractionDigits: 0, 
      maximumFractionDigits: 3 
    });
  };

  const generatePDF = async (action: 'preview' | 'download') => {
    const element = document.getElementById('printable-report');
    if (!element) return;

    if (action === 'preview') setIsPreviewing(true);
    else setIsExporting(true);

    // Configurações para captura fiel
    const originalStyle = element.getAttribute('style') || '';
    element.style.width = '190mm'; // Largura útil A4 (210 - 20)
    element.style.padding = '0';
    element.style.margin = '0';

    try {
      const canvas = await html2canvas(element, {
        scale: 2,
        useCORS: true,
        logging: false,
        backgroundColor: '#ffffff',
        width: element.offsetWidth,
        height: element.scrollHeight,
        windowWidth: element.offsetWidth
      });

      const pdf = new jsPDF('p', 'mm', 'a4');
      const pdfWidth = 210;
      const pdfHeight = 297;
      const margin = 20; // Margem de 2,0 cm exigida
      const contentWidth = pdfWidth - (2 * margin);
      const contentHeight = pdfHeight - (2 * margin);

      const canvasWidth = canvas.width;
      const canvasHeight = canvas.height;

      const imgWidth = contentWidth;
      const imgHeight = (canvasHeight * imgWidth) / canvasWidth;

      let heightLeft = imgHeight;
      let position = margin;
      let pageNum = 1;

      // Adiciona primeira página
      const imgData = canvas.toDataURL('image/jpeg', 1.0);
      pdf.addImage(imgData, 'JPEG', margin, position, imgWidth, imgHeight);

      // Rodapé da primeira página
      pdf.setFontSize(8);
      pdf.text(`Página ${pageNum}`, pdfWidth / 2, pdfHeight - 10, { align: 'center' });

      // Adiciona páginas subsequentes se necessário
      while (heightLeft >= contentHeight) {
        position = heightLeft - imgHeight + margin;
        pdf.addPage();
        pageNum++;
        pdf.addImage(imgData, 'JPEG', margin, position, imgWidth, imgHeight);
        pdf.text(`Página ${pageNum}`, pdfWidth / 2, pdfHeight - 10, { align: 'center' });
        heightLeft -= contentHeight;
      }

      if (action === 'preview') {
        const blob = pdf.output('blob');
        const url = URL.createObjectURL(blob);
        window.open(url, '_blank');
      } else {
        pdf.save(`MANIFESTO_${batch.id}.pdf`);
      }
