              <FileText size={20} />
            </div>
            <div>
              <span className="font-black text-slate-800 text-sm uppercase tracking-tight">Manifesto de Conferência</span>
              <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">A4 PORTRAIT • MARGENS 2CM</p>
            </div>
          </div>

          <div className="flex items-center gap-2">
            <button 
              onClick={() => generatePDF('preview')}
              disabled={isPreviewing || isExporting}
              className="flex items-center gap-2 bg-white border border-slate-200 hover:bg-slate-50 text-slate-700 px-4 py-2.5 rounded-xl font-bold transition-all text-xs disabled:opacity-50"
            >
              {isPreviewing ? <Loader2 size={16} className="animate-spin" /> : <Eye size={16} />}
              Visualizar PDF
            </button>
            <button 
              onClick={() => generatePDF('download')}
              disabled={isPreviewing || isExporting}
              className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-6 py-2.5 rounded-xl font-bold transition-all text-xs shadow-lg shadow-blue-500/20 disabled:opacity-50"
            >
              {isExporting ? <Loader2 size={16} className="animate-spin" /> : <Download size={16} />}
              Salvar Arquivo
            </button>
            <div className="w-px h-6 bg-slate-200 mx-2"></div>
            <button 
              onClick={onClose}
              className="p-2.5 hover:bg-red-50 hover:text-red-500 rounded-xl transition-all text-slate-400"
