import React, { useState } from 'react';
import { X, Download, FileText, CheckCircle2, AlertTriangle, Package, Loader2, Hash, MapPin, ReceiptText, Eye, User } from 'lucide-react';
import { ConferenceBatch } from '../types';
import { INITIAL_BRANCHES } from '../constants';
import { jsPDF } from 'jspdf';
import html2canvas from 'html2canvas';

interface ReportModalProps {
  batch: ConferenceBatch;
  onClose: () => void;
}

const ReportModal: React.FC<ReportModalProps> = ({ batch, onClose }) => {
  const [isExporting, setIsExporting] = useState(false);
  const [isPreviewing, setIsPreviewing] = useState(false);

  // Dados para o Cabeçalho
  const branchName = INITIAL_BRANCHES.find(b => b.cnpj === batch.notes[0]?.vendorCnpj)?.name || 'FILIAL PADRÃO';
  const nfeNumbers = batch.notes.map(n => n.number).join(', ');
  const conferenceDate = new Date(batch.endTime || batch.startTime).toLocaleDateString('pt-BR');
  const conferenceTime = new Date(batch.endTime || batch.startTime).toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' });

  const formatNumber = (num: number) => {
    return num.toLocaleString('pt-BR', { 
      minimumFractionDigits: 0, 
      maximumFractionDigits: 3 
    });
  };

  const generatePDF = async (action: 'preview' | 'download') => {
    const element = document.getElementById('printable-report');
    if (!element) return;

    if (action === 'preview') setIsPreviewing(true);
    else setIsExporting(true);

    // Configuração de Estilo para Captura Fiel (A4 170mm útil)
    const originalStyle = element.getAttribute('style') || '';
    element.style.width = '170mm';
    element.style.padding = '0';
    element.style.margin = '0';
    element.style.color = '#000';

    try {
      const canvas = await html2canvas(element, {
        scale: 3, // Ultra resolução para impressão profissional
        useCORS: true,
        logging: false,
        backgroundColor: '#ffffff',
      });

      const pdf = new jsPDF('p', 'mm', 'a4');
      const pdfWidth = 210;
      const pdfHeight = 297;
      const margin = 20; // Margens de 2,0 cm em todos os lados
      const contentWidth = pdfWidth - (2 * margin);
      const contentHeight = pdfHeight - (2 * margin);

      const imgData = canvas.toDataURL('image/jpeg', 1.0);
      const canvasWidth = canvas.width;
      const canvasHeight = canvas.height;

      const imgWidth = contentWidth;
      const imgHeight = (canvasHeight * imgWidth) / canvasWidth;

      let heightLeft = imgHeight;
      let position = margin;
      let pageNum = 1;

      // Cálculo de total de páginas
      const totalPages = Math.ceil(imgHeight / contentHeight);

      // Função para renderizar rodapé em cada página
      const drawFooter = (current: number) => {
        pdf.setFont('helvetica', 'bold');
        pdf.setFontSize(8);
        pdf.setTextColor(60, 60, 60);
        // Nome do Conferente
        pdf.text(`CONFERENTE: ${batch.conferenteName.toUpperCase()}`, margin, pdfHeight - 10);
        // Paginação
        pdf.text(`Página ${current} de ${totalPages}`, pdfWidth - margin, pdfHeight - 10, { align: 'right' });
      };

      // Adicionar Primeira Página
      pdf.addImage(imgData, 'JPEG', margin, position, imgWidth, imgHeight);
      drawFooter(pageNum);

      // Adicionar Páginas Subsequentes (Fatiamento)
      while (heightLeft >= contentHeight) {
        position = heightLeft - imgHeight + margin;
        pdf.addPage();
        pageNum++;
        pdf.addImage(imgData, 'JPEG', margin, position, imgWidth, imgHeight);
        drawFooter(pageNum);
        heightLeft -= contentHeight;
      }

      if (action === 'preview') {
        const blob = pdf.output('blob');
        const url = URL.createObjectURL(blob);
        window.open(url, '_blank');
      } else {
        pdf.save(`MANIFESTO_CONFERENCIA_${batch.id.toUpperCase()}.pdf`);
      }
    } catch (error) {
      console.error('Erro na geração do PDF:', error);
      alert('Houve um erro técnico ao processar o relatório.');
    } finally {
      element.setAttribute('style', originalStyle);
      setIsPreviewing(false);
      setIsExporting(false);
    }
  };

  return (
    <div id="print-modal-container" className="fixed inset-0 z-[150] flex items-center justify-center p-0 md:p-6 bg-slate-900/95 backdrop-blur-md no-print">
      <div className="bg-white w-full max-w-5xl h-full md:h-auto md:max-h-[98vh] rounded-none md:rounded-[24px] shadow-2xl flex flex-col overflow-hidden animate-in fade-in zoom-in duration-300">

        {/* Barra de Ferramentas (Não impressa) */}
        <div className="px-6 py-4 border-b border-slate-100 flex justify-between items-center bg-slate-50/90 no-print">
          <div className="flex items-center gap-4">
            <div className="bg-slate-900 p-2.5 rounded-xl text-white">
              <Package size={22} />
            </div>
            <div>
              <span className="font-black text-slate-800 text-sm uppercase tracking-tight">Relatório de Conferência Cega</span>
              <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">A4 PORTRAIT • PDF PROFISSIONAL</p>
            </div>
          </div>

          <div className="flex items-center gap-3">
            <button 
              onClick={() => generatePDF('preview')}
              disabled={isPreviewing || isExporting}
              className="flex items-center gap-2 bg-white border border-slate-300 hover:bg-slate-50 text-slate-700 px-5 py-2.5 rounded-xl font-bold transition-all text-xs disabled:opacity-50 shadow-sm"
            >
              {isPreviewing ? <Loader2 size={16} className="animate-spin" /> : <Eye size={16} />}
              Visualizar
            </button>
            <button 
              onClick={() => generatePDF('download')}
              disabled={isPreviewing || isExporting}
              className="flex items-center gap-2 bg-slate-900 hover:bg-black text-white px-6 py-2.5 rounded-xl font-bold transition-all text-xs shadow-xl disabled:opacity-50"
            >
              {isExporting ? <Loader2 size={16} className="animate-spin" /> : <Download size={16} />}
              Exportar PDF
            </button>
            <div className="w-px h-8 bg-slate-200 mx-2"></div>
            <button onClick={onClose} className="p-2.5 hover:bg-red-50 hover:text-red-500 rounded-xl transition-all text-slate-400">
              <X size={22} />
            </button>
          </div>
        </div>

        {/* ÁREA DE CAPTURA DO RELATÓRIO (FORMATO A4) */}
        <div 
          id="printable-report" 
          className="flex-1 overflow-y-auto bg-white mx-auto report-scrollbar"
          style={{ 
            fontFamily: 'Helvetica, Arial, sans-serif',
            width: '170mm', // Área útil (210mm - 40mm)
            padding: '0',
            color: '#000'
          }}
        >
          {/* Cabeçalho Centralizado */}
          <div className="text-center py-12 border-b-2 border-black mb-10">
            <h1 className="text-2xl font-bold uppercase tracking-tighter mb-8 leading-none">
