                <span className="text-[10px] font-bold text-slate-500 uppercase tracking-[0.2em] mb-1">Número do Manifesto</span>
                <span className="text-xl font-black text-black">#{batch.id.toUpperCase()}</span>
              </div>

              <div className="flex flex-col items-center">
                <span className="text-[10px] font-bold text-slate-500 uppercase tracking-[0.2em] mb-1">Filial de Destino</span>
                <span className="text-lg font-bold text-black uppercase">{branchName}</span>
              </div>

              <div className="flex flex-col items-center">
                <span className="text-[10px] font-bold text-slate-500 uppercase tracking-[0.2em] mb-1">Data da Operação</span>
                <span className="text-md font-bold text-black">{conferenceDate} às {conferenceTime}</span>
              </div>

              <div className="mt-4 pt-6 border-t border-slate-100 w-full flex flex-col items-center">
                <span className="text-[10px] font-bold text-slate-500 uppercase tracking-[0.2em] mb-2">Notas Fiscais Processadas</span>
                <span className="text-xs font-bold text-black bg-slate-100 px-6 py-2 rounded-full border border-slate-200">
                  {nfeNumbers || 'NÃO INFORMADO'}
                </span>
              </div>
            </div>
          </div>

          {/* Tabela de Itens (Proporcional ReportLab) */}
          <div className="mb-12">
            <h3 className="text-xs font-bold uppercase mb-4 text-black border-l-8 border-black pl-3 tracking-widest">
