                  <th className="border border-black p-2 text-[9px] font-bold uppercase text-center w-[15%]">Status</th>
                </tr>
              </thead>
              <tbody>
                {batch.products.map((p, idx) => {
                  const qExp = parseFloat(p.quantityExpected.toFixed(3));
                  const qChk = parseFloat(p.quantityChecked.toFixed(3));
                  const diff = qChk - qExp;

                  let statusLabel = 'CONFORME';
                  let statusColor = 'text-black';

                  if (diff > 0) {
                    statusLabel = 'SOBRA';
                    statusColor = 'text-blue-700';
                  } else if (diff < 0) {
