import React, { useState } from 'react';
import { X, Download, FileText, Package, Loader2, Eye } from 'lucide-react';
import { ConferenceBatch } from '../types';
import { INITIAL_BRANCHES } from '../constants';
import { jsPDF } from 'jspdf';
import autoTable from 'jspdf-autotable';

interface ReportModalProps {
  batch: ConferenceBatch;
  onClose: () => void;
}

const ReportModal: React.FC<ReportModalProps> = ({ batch, onClose }) => {
  const [isExporting, setIsExporting] = useState(false);
  const [isPreviewing, setIsPreviewing] = useState(false);

  const branchName = INITIAL_BRANCHES.find(b => b.cnpj === batch.notes[0]?.vendorCnpj)?.name || 'FILIAL PADRÃO';
  const nfeNumbers = batch.notes.map(n => n.number).join(', ');
  const totalItemsChecked = batch.products.reduce((acc, p) => acc + p.quantityChecked, 0);

  const formatNumber = (num: number) => {
    return num.toLocaleString('pt-BR', { 
      minimumFractionDigits: 0, 
      maximumFractionDigits: 3 
    });
  };

  const generatePDF = async (action: 'preview' | 'download') => {
    if (action === 'preview') setIsPreviewing(true);
    else setIsExporting(true);

    try {
      const doc = new jsPDF({
        orientation: 'portrait',
        unit: 'mm',
        format: 'a4'
      });

      const pageWidth = doc.internal.pageSize.getWidth();
      const pageHeight = doc.internal.pageSize.getHeight();
      const margin = 15;
      const contentWidth = pageWidth - (margin * 2);

      // --- Cabeçalho Centralizado ---
      doc.setFont('helvetica', 'bold');
      doc.setFontSize(14);
      doc.text('MANIFESTO DE CONFERÊNCIA CEGA', pageWidth / 2, 20, { align: 'center' });

      doc.setFontSize(10);
      doc.setFont('helvetica', 'normal');
      doc.text(`Manifesto: #${batch.id.toUpperCase()}`, pageWidth / 2, 26, { align: 'center' });
      doc.text(`Notas Fiscais: ${nfeNumbers}`, pageWidth / 2, 31, { align: 'center' });
      doc.text(`Filial Destino: ${branchName}`, pageWidth / 2, 36, { align: 'center' });
      doc.text(`Data: ${new Date(batch.endTime || batch.startTime).toLocaleString('pt-BR')}`, pageWidth / 2, 41, { align: 'center' });
      doc.text(`Conferente: ${batch.conferenteName}`, pageWidth / 2, 46, { align: 'center' });

      // --- Tabela Estruturada com autoTable ---
      const tableRows = batch.products.map(p => {
        const diff = p.quantityChecked - p.quantityExpected;
        const status = diff === 0 ? 'CONFORME' : diff > 0 ? 'SOBRA' : 'FALTA';
        return [
          p.code,
          p.ean,
          p.description.toUpperCase(),
          formatNumber(p.quantityChecked),
          status
        ];
      });

      autoTable(doc, {
        startY: 55,
        head: [['CÓDIGO', 'EAN', 'DESCRIÇÃO DO PRODUTO', 'QTD LIDA', 'STATUS']],
        body: tableRows,
        theme: 'grid',
        styles: {
          fontSize: 8,
          cellPadding: 3,
          overflow: 'linebreak',
          valign: 'middle'
        },
        headStyles: {
          fillColor: [40, 40, 40],
          textColor: [255, 255, 255],
          fontStyle: 'bold',
          halign: 'center'
        },
        columnStyles: {
          0: { cellWidth: 25, halign: 'left' },      // Código
          1: { cellWidth: 35, halign: 'left' },      // EAN
          2: { cellWidth: 'auto', halign: 'left' }, // Descrição (40%+)
          3: { cellWidth: 25, halign: 'center' },    // Quantidade
          4: { cellWidth: 25, halign: 'center' }     // Status
        },
        didDrawPage: (data) => {
          // --- Rodapé Automático ---
          const str = `Página ${doc.internal.getNumberOfPages()}`;
          doc.setFontSize(8);
          doc.setFont('helvetica', 'normal');
          doc.setTextColor(100);

          // Nome conferente e total de volumes
          doc.text(
            `Conferente: ${batch.conferenteName.toUpperCase()} | Total Volumes: ${formatNumber(totalItemsChecked)}`,
            margin,
            pageHeight - 10
          );

          // Paginação
          doc.text(str, pageWidth - margin, pageHeight - 10, { align: 'right' });
        },
        margin: { top: margin, bottom: 20, left: margin, right: margin },
      });

      if (action === 'preview') {
        const blob = doc.output('blob');
        const url = URL.createObjectURL(blob);
        window.open(url, '_blank');
      } else {
        doc.save(`MANIFESTO_${batch.id.toUpperCase()}.pdf`);
      }
    } catch (error) {
      console.error('Erro ao gerar PDF:', error);
      alert('Houve um erro técnico ao gerar o PDF vetorial.');
    } finally {
      setIsPreviewing(false);
      setIsExporting(false);
    }
  };

  return (
    <div id="print-modal-container" className="fixed inset-0 z-[200] flex items-center justify-center p-0 md:p-6 bg-slate-900/95 backdrop-blur-md no-print">
      <div className="bg-white w-full max-w-4xl h-full md:h-auto md:max-h-[90vh] rounded-none md:rounded-[24px] shadow-2xl flex flex-col overflow-hidden animate-in fade-in zoom-in duration-300">

        {/* Header UI */}
        <div className="px-8 py-6 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
          <div className="flex items-center gap-4">
            <div className="bg-slate-900 p-2.5 rounded-xl text-white">
              <FileText size={24} />
            </div>
            <div>
              <h2 className="font-black text-slate-800 text-lg uppercase tracking-tight">Gerador de Manifesto</h2>
              <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">PDF VETORIAL • AUTOTABLE ENGINE</p>
            </div>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-red-50 hover:text-red-500 rounded-xl transition-all">
            <X size={24} />
          </button>
        </div>

        {/* Content UI Preview */}
        <div className="flex-1 overflow-y-auto p-12 bg-white">
          <div className="max-w-2xl mx-auto border border-slate-100 p-10 rounded-3xl shadow-sm text-center">
            <Package size={64} className="mx-auto text-blue-500 mb-6 opacity-20" />
            <h3 className="text-xl font-black text-slate-800 uppercase tracking-tight mb-2">Relatório Pronto para Exportação</h3>
            <p className="text-slate-500 text-sm mb-8">
              O documento foi processado em formato vetorial de alta definição (A4 Portrait). 
              Clique abaixo para visualizar ou salvar no seu dispositivo.
            </p>

            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              <button 
                onClick={() => generatePDF('preview')}
                disabled={isPreviewing || isExporting}
                className="flex items-center justify-center gap-3 bg-white border-2 border-slate-200 hover:border-slate-300 text-slate-700 px-6 py-4 rounded-2xl font-black text-xs uppercase tracking-widest transition-all disabled:opacity-50"
              >
                {isPreviewing ? <Loader2 className="animate-spin" size={18} /> : <Eye size={18} />}
                Visualizar PDF
              </button>
              <button 
                onClick={() => generatePDF('download')}
                disabled={isPreviewing || isExporting}
                className="flex items-center justify-center gap-3 bg-blue-600 hover:bg-blue-700 text-white px-6 py-4 rounded-2xl font-black text-xs uppercase tracking-widest transition-all shadow-xl shadow-blue-500/20 disabled:opacity-50"
              >
                {isExporting ? <Loader2 className="animate-spin" size={18} /> : <Download size={18} />}
                Baixar Arquivo
              </button>
            </div>
          </div>
        </div>

        {/* Footer UI */}
        <div className="p-6 bg-slate-50 border-t border-slate-100 text-center">
          <p className="text-[9px] font-bold text-slate-400 uppercase tracking-[0.3em]">
            CheckMaster Logistics Engine - v2.5
          </p>
        </div>
      </div>
    </div>
  );
};

