import React, { useState } from 'react';
import { X, Download, FileText, Package, Loader2, Eye, ShieldCheck } from 'lucide-react';
import { ConferenceBatch } from '../types';
import { INITIAL_BRANCHES } from '../constants';
import { jsPDF } from 'jspdf';
import autoTable from 'jspdf-autotable';

interface ReportModalProps {
  batch: ConferenceBatch;
  onClose: () => void;
}

// Logo Normatel em Base64 para renderização vetorial imediata
const NORMATEL_LOGO = 'data:image/png;base64,';

const ReportModal: React.FC<ReportModalProps> = ({ batch, onClose }) => {
  const [isExporting, setIsExporting] = useState(false);
  const [isPreviewing, setIsPreviewing] = useState(false);

  const branchName = INITIAL_BRANCHES.find(b => b.cnpj === batch.notes[0]?.vendorCnpj)?.name || 'FILIAL PADRÃO';
  const nfeNumbers = batch.notes.map(n => n.number).join(', ');

  const formatNumber = (num: number) => {
    return num.toLocaleString('pt-BR', { 
      minimumFractionDigits: 0, 
      maximumFractionDigits: 3 
    });
  };

  const generatePDF = async (action: 'preview' | 'download') => {
    if (action === 'preview') setIsPreviewing(true);
    else setIsExporting(true);

    try {
      const doc = new jsPDF({
        orientation: 'portrait',
        unit: 'mm',
        format: 'a4'
      });

      const pageWidth = doc.internal.pageSize.getWidth();
      const pageHeight = doc.internal.pageSize.getHeight();
      const margin = 15;

      // 1. Cabeçalho Normatel
      // Logo
      doc.addImage(NORMATEL_LOGO, 'PNG', margin, 10, 25, 25);

      // Informações da Empresa
      doc.setFont('helvetica', 'bold');
      doc.setFontSize(14);
      doc.setTextColor(230, 107, 39); // Laranja Normatel (#E66B27)
      doc.text('NORMATEL HOME CENTER', 45, 18);

      doc.setFontSize(12);
      doc.setTextColor(40, 40, 40);
      doc.text('RELATÓRIO DE CONFERÊNCIA DE MANIFESTO', 45, 25);

      // Detalhes do Documento
      doc.setFontSize(9);
      doc.setFont('helvetica', 'normal');
      doc.setTextColor(80, 80, 80);
      doc.text(`Manifesto: #${batch.id.toUpperCase()}`, 45, 31);
      doc.text(`Filial: ${branchName}`, 45, 35);
      doc.text(`Data: ${new Date(batch.endTime || batch.startTime).toLocaleString('pt-BR')}`, pageWidth - margin, 31, { align: 'right' });
      doc.text(`Conferente: ${batch.conferenteName.toUpperCase()}`, pageWidth - margin, 35, { align: 'right' });

      // Linha Divisora
      doc.setDrawColor(230, 107, 39);
      doc.setLineWidth(0.5);
      doc.line(margin, 40, pageWidth - margin, 40);

      // 2. Preparação dos Dados da Tabela
      let totalQtdNota = 0;
      let totalQtdLida = 0;
      let totalDivergencias = 0;

      const tableRows = batch.products.map(p => {
        const diff = p.quantityChecked - p.quantityExpected;
        const status = diff === 0 ? 'CONFORME' : diff > 0 ? 'SOBRA' : 'FALTA';

        totalQtdNota += p.quantityExpected;
        totalQtdLida += p.quantityChecked;
        if (diff !== 0) totalDivergencias++;

        return [
          batch.notes[0]?.number || '-',
          p.code,
          p.ean,
          p.description.toUpperCase(),
          formatNumber(p.quantityExpected),
          formatNumber(p.quantityChecked),
          formatNumber(diff),
          status
        ];
      });

      // 3. Tabela com autoTable
      autoTable(doc, {
        startY: 45,
        head: [['PEDIDO', 'CÓDIGO', 'EAN', 'DESCRIÇÃO DO PRODUTO', 'QTD NOTA', 'QTD LIDA', 'DIFF', 'STATUS']],
        body: tableRows,
        theme: 'grid',
        styles: {
          fontSize: 8,
          cellPadding: 2,
          overflow: 'linebreak',
          valign: 'middle'
        },
        headStyles: {
