      doc.text(`Qtd Total Nota: ${formatNumber(totalQtdNota)}`, margin + 5, finalY + 17);
      doc.text(`Qtd Total Lida: ${formatNumber(totalQtdLida)}`, margin + 5, finalY + 21);

