import React, { useState } from 'react';
import { X, Download, FileText, Package, Loader2, Eye, ShieldCheck, AlertTriangle } from 'lucide-react';
import { ConferenceBatch } from '../types';
import { INITIAL_BRANCHES } from '../constants';
import { jsPDF } from 'jspdf';
import autoTable from 'jspdf-autotable';

interface ReportModalProps {
  batch: ConferenceBatch;
  onClose: () => void;
}

// Logo Normatel em Base64 (Laranja institucional simplificado)
const NORMATEL_LOGO = 'data:image/png;base64,';

const ReportModal: React.FC<ReportModalProps> = ({ batch, onClose }) => {
  const [isExporting, setIsExporting] = useState(false);
  const [isPreviewing, setIsPreviewing] = useState(false);

  const branchName = INITIAL_BRANCHES.find(b => b.cnpj === batch.notes[0]?.vendorCnpj)?.name || 'FILIAL PADRÃO';
  const nfeNumbers = batch.notes.map(n => n.number).join(', ');

  const formatNumber = (num: number) => {
    return num.toLocaleString('pt-BR', { 
      minimumFractionDigits: 0, 
      maximumFractionDigits: 3 
    });
  };

  const generatePDF = async (action: 'preview' | 'download') => {
    if (action === 'preview') setIsPreviewing(true);
    else setIsExporting(true);

    try {
      // 1. Instanciar o Documento PDF (A4 Portrait em mm)
      const doc = new jsPDF({
        orientation: 'portrait',
        unit: 'mm',
        format: 'a4'
      });

      const pageWidth = doc.internal.pageSize.getWidth();
      const pageHeight = doc.internal.pageSize.getHeight();
      const margin = 15;

      // --- CABEÇALHO PROFISSIONAL ---
      // Logo (Superior Esquerda)
      doc.addImage(NORMATEL_LOGO, 'PNG', margin, 10, 20, 20);

      // Nome da Empresa e Título
      doc.setFont('helvetica', 'bold');
      doc.setFontSize(14);
      doc.setTextColor(230, 107, 39); // Laranja Normatel (#E66B27)
      doc.text('NORMATEL HOME CENTER', 40, 18);

      doc.setFontSize(13);
      doc.setTextColor(40, 40, 40);
      doc.text('RELATÓRIO DE CONFERÊNCIA DE MANIFESTO', 40, 24);

      // Detalhes Gerais
      doc.setFontSize(9);
      doc.setFont('helvetica', 'normal');
      doc.setTextColor(80, 80, 80);

      doc.text(`Manifesto ID: #${batch.id.toUpperCase()}`, 40, 30);
      doc.text(`Filial Destino: ${branchName}`, 40, 34);

      doc.text(`Data: ${new Date(batch.endTime || batch.startTime).toLocaleString('pt-BR')}`, pageWidth - margin, 30, { align: 'right' });
      doc.text(`Conferente: ${batch.conferenteName.toUpperCase()}`, pageWidth - margin, 34, { align: 'right' });

      // Linha Separadora de Cabeçalho
      doc.setDrawColor(230, 107, 39);
      doc.setLineWidth(0.5);
      doc.line(margin, 38, pageWidth - margin, 38);

      // --- PREPARAÇÃO DOS DADOS ---
      let totalQtdNota = 0;
      let totalQtdLida = 0;
      let totalDivergencias = 0;

      const tableRows = batch.products.map(p => {
        const diff = p.quantityChecked - p.quantityExpected;
        const status = diff === 0 ? 'CONFORME' : diff > 0 ? 'SOBRA' : 'FALTA';

        totalQtdNota += p.quantityExpected;
        totalQtdLida += p.quantityChecked;
        if (diff !== 0) totalDivergencias++;

        return [
          batch.notes[0]?.number || '-',
          p.code,
          p.ean,
          p.description.toUpperCase(),
          formatNumber(p.quantityExpected),
          formatNumber(p.quantityChecked),
          formatNumber(diff),
          status
        ];
      });

      // --- TABELA ESTRUTURADA (autoTable) ---
      autoTable(doc, {
        startY: 45,
        head: [['PEDIDO', 'CÓDIGO', 'EAN', 'DESCRIÇÃO DO PRODUTO', 'QTD NOTA', 'QTD LIDA', 'DIFF', 'STATUS']],
        body: tableRows,
        theme: 'grid',
        styles: {
          fontSize: 9,
          cellPadding: 3,
          overflow: 'linebreak',
          valign: 'middle',
          font: 'helvetica'
        },
        headStyles: {
          fillColor: [60, 60, 60],
          textColor: [255, 255, 255],
          fontStyle: 'bold',
          halign: 'center'
        },
        columnStyles: {
          0: { cellWidth: 15, halign: 'center' },
          1: { cellWidth: 20, halign: 'left' },
          2: { cellWidth: 28, halign: 'left' },
          3: { cellWidth: 'auto', halign: 'left' }, // Descrição (~40%+)
          4: { cellWidth: 18, halign: 'center' },
          5: { cellWidth: 18, halign: 'center' },
          6: { cellWidth: 15, halign: 'center' },
          7: { cellWidth: 20, halign: 'center' }
        },
        didParseCell: (data) => {
          // Destacar linhas com divergência (Sobra ou Falta)
          if (data.section === 'body') {
            const rowData = data.row.raw as any[];
            const diffStr = rowData[6] as string;
            const diffValue = parseFloat(diffStr.replace('.', '').replace(',', '.'));

            if (diffValue !== 0) {
              data.cell.styles.fillColor = [255, 235, 235]; // Fundo vermelho claro
              data.cell.styles.textColor = [180, 0, 0];    // Texto bordô
              data.cell.styles.fontStyle = 'bold';
            }
          }
        },
        didDrawPage: (data) => {
          // --- RODAPÉ AUTOMÁTICO ---
          const str = `Página ${doc.getNumberOfPages()}`;
          doc.setFontSize(8);
          doc.setTextColor(150);
          doc.setFont('helvetica', 'normal');

          // Nome do Sistema e Paginação
          doc.text('SISTEMA DE CONFERÊNCIA - NORMATEL', margin, pageHeight - 10);
          doc.text(str, pageWidth - margin, pageHeight - 10, { align: 'right' });
        },
        margin: { top: 20, bottom: 40, left: margin, right: margin },
      });

      // --- RESUMO FINAL (Posicionado após a tabela) ---
      const finalY = (doc as any).lastAutoTable.finalY + 10;

      // Box de Resumo Cinza
      doc.setFillColor(248, 248, 248);
      doc.setDrawColor(230, 230, 230);
      doc.roundedRect(margin, finalY, 100, 30, 2, 2, 'FD');

      doc.setFont('helvetica', 'bold');
      doc.setFontSize(10);
      doc.setTextColor(40, 40, 40);
      doc.text('RESUMO DA CONFERÊNCIA', margin + 5, finalY + 7);

      doc.setFontSize(9);
      doc.setFont('helvetica', 'normal');
      doc.text(`• Total SKUs Processados: ${batch.products.length}`, margin + 5, finalY + 14);
      doc.text(`• Qtd. Total no XML: ${formatNumber(totalQtdNota)}`, margin + 5, finalY + 20);
      doc.text(`• Qtd. Total Bipada: ${formatNumber(totalQtdLida)}`, margin + 5, finalY + 26);

      // Alerta de Divergências se houver
      if (totalDivergencias > 0) {
        doc.setFont('helvetica', 'bold');
        doc.setTextColor(200, 0, 0);
        doc.text(`• ITENS COM DIVERGÊNCIA: ${totalDivergencias}`, margin + 55, finalY + 14);
      }

      // --- CAMPO PARA ASSINATURA ---
      const signY = pageHeight - 35;
      doc.setDrawColor(180);
      doc.setLineWidth(0.2);
      doc.line(pageWidth / 2 - 40, signY, pageWidth / 2 + 40, signY);

      doc.setFontSize(9);
      doc.setTextColor(100);
      doc.setFont('helvetica', 'bold');
      doc.text('ASSINATURA DO CONFERENTE', pageWidth / 2, signY + 5, { align: 'center' });
      doc.setFont('helvetica', 'normal');
      doc.text(batch.conferenteName.toUpperCase(), pageWidth / 2, signY + 10, { align: 'center' });

      // --- EXECUÇÃO DA AÇÃO ---
      if (action === 'preview') {
        const blob = doc.output('blob');
        const url = URL.createObjectURL(blob);
        const win = window.open(url, '_blank');
        if (!win) {
          alert('Pop-up bloqueado! Por favor, habilite pop-ups para visualizar o PDF.');
        }
      } else {
        doc.save(`NORMATEL_CONFERENCIA_${batch.id.toUpperCase()}.pdf`);
      }
    } catch (error: any) {
      console.error('Erro ao gerar PDF:', error);
      alert(`Erro técnico ao gerar relatório: ${error.message || 'Erro desconhecido'}`);
    } finally {
      setIsPreviewing(false);
      setIsExporting(false);
    }
  };

  return (
    <div id="print-modal-container" className="fixed inset-0 z-[200] flex items-center justify-center p-0 md:p-6 bg-slate-900/95 backdrop-blur-md no-print">
      <div className="bg-white w-full max-w-4xl h-full md:h-auto md:max-h-[90vh] rounded-none md:rounded-[24px] shadow-2xl flex flex-col overflow-hidden animate-in fade-in zoom-in duration-300 border border-white/10">

        {/* Header UI */}
        <div className="px-8 py-6 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
          <div className="flex items-center gap-4">
            <div className="bg-[#E66B27] p-2.5 rounded-xl text-white shadow-lg shadow-orange-500/20">
              <ShieldCheck size={24} />
            </div>
            <div>
              <h2 className="font-black text-slate-800 text-lg uppercase tracking-tight">Relatório Normatel</h2>
              <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">PDF VETORIAL CORPORATIVO • JS-AUTOTABLE</p>
            </div>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-red-50 hover:text-red-500 rounded-xl transition-all">
            <X size={24} />
          </button>
        </div>

        {/* Content UI Preview */}
        <div className="flex-1 overflow-y-auto p-12 bg-white flex flex-col items-center justify-center">
          <div className="max-w-2xl w-full border border-slate-100 p-12 rounded-[40px] shadow-sm text-center bg-gradient-to-b from-white to-slate-50">
            <div className="w-24 h-24 bg-orange-50 text-[#E66B27] rounded-full flex items-center justify-center mx-auto mb-8 shadow-inner">
              <FileText size={48} />
            </div>
            <h3 className="text-2xl font-black text-slate-800 uppercase tracking-tight mb-4">Documento Pronto para Emissão</h3>
            <p className="text-slate-500 text-base mb-10 leading-relaxed">
              O manifesto <b>#{batch.id.toUpperCase()}</b> foi processado com sucesso. 
              As divergências identificadas estão destacadas em vermelho para facilitar a auditoria logística.
            </p>

            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              <button 
                onClick={() => generatePDF('preview')}
                disabled={isPreviewing || isExporting}
                className="flex items-center justify-center gap-3 bg-white border-2 border-slate-200 hover:border-[#E66B27] hover:text-[#E66B27] text-slate-700 px-8 py-5 rounded-2xl font-black text-xs uppercase tracking-widest transition-all disabled:opacity-50"
              >
                {isPreviewing ? <Loader2 className="animate-spin" size={20} /> : <Eye size={20} />}
                Abrir Visualização
              </button>
              <button 
                onClick={() => generatePDF('download')}
                disabled={isPreviewing || isExporting}
                className="flex items-center justify-center gap-3 bg-[#E66B27] hover:bg-[#d55a1a] text-white px-8 py-5 rounded-2xl font-black text-xs uppercase tracking-widest transition-all shadow-xl shadow-orange-500/20 disabled:opacity-50 transform hover:scale-[1.02] active:scale-95"
              >
                {isExporting ? <Loader2 className="animate-spin" size={20} /> : <Download size={20} />}
                Baixar Manifesto
              </button>
            </div>

            {batch.products.some(p => p.quantityChecked !== p.quantityExpected) && (
              <div className="mt-8 p-4 bg-red-50 border border-red-100 rounded-2xl flex items-center gap-3 text-red-700">
                <AlertTriangle size={20} className="shrink-0" />
                <p className="text-[10px] font-black uppercase tracking-widest text-left">Atenção: Este lote possui divergências aprovadas pela supervisão.</p>
              </div>
            )}
          </div>
        </div>

        {/* Footer UI */}
        <div className="p-6 bg-slate-50 border-t border-slate-100 text-center">
          <p className="text-[9px] font-bold text-slate-400 uppercase tracking-[0.3em]">
            SISTEMA DE CONFERÊNCIA DE MERCADORIAS - NORMATEL v2.9
          </p>
        </div>
      </div>
    </div>
  );
};

